window.__ARXIV_DATA__ = {"papers":[{"id":"2605.27372v1","title":"G3T Up! Gravity Aligned Coordinate Frames Simplify Pointmap Processing","abstract":"Modern feed-forward 3D reconstruction methods like VGGT predict pixel-aligned pointmaps in camera-centric coordinate frames. However, this choice of coordinate frame is not always optimal. We propose instead to predict pointmaps in upright, gravity-aligned frames that exploit strong structural cues present in many real-world scenes. Unlike camera-centric frames, gravity-aligned frames share a common vertical axis across viewpoints, reducing the rotational degrees of freedom needed to relate pointmaps to one another. To this end, we introduce the Gravity Grounded Geometry Transformer (G3T), fine-tuned from existing models on gravity-aligned 3D data. G3T produces highly accurate gravity-aware predictions, including upright pointmaps and camera-to-gravity poses. We further introduce G3T-Long, a submap-based incremental 3D reconstruction pipeline that leverages the reduced rotational degrees of freedom afforded by upright frames to achieve significantly improved reconstruction accuracy.","authors":["Bharath Raj Nagoor Kani","Noah Snavely"],"published":"2026-05-26T17:59:55Z","updated":"2026-05-26T17:59:55Z","abstract_url":"https://arxiv.org/abs/2605.27372v1","html_url":"https://arxiv.org/html/2605.27372v1","pdf_url":"https://arxiv.org/pdf/2605.27372v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":58422,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Modern feed-forward 3D reconstruction methods like VGGT predict pixel-aligned pointmaps in camera-centric coordinate frames. However, this choice of coordinate frame is not always optimal. We propose instead to predict pointmaps in upright, gravity-aligned fr...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:04+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27367v1","title":"SpatialBench: Is Your Spatial Foundation Model an All-Round Player?","abstract":"While spatial foundation models have demonstrated impressive performance on standard datasets, a critical question remains: are they truly all-round players capable of generalizing robustly across diverse downstream tasks, arbitrary viewpoints, shifting scene domains, varying input densities, and specific hardware constraints? Answering this overarching question requires a holistic assessment, yet current models are mainly evaluated on specific domains for which they were specifically designed or trained. Such evaluations are intrinsically limited by narrow paradigm coverage, limited scene domains, and arbitrary frame sampling, making it fundamentally difficult to assess their true generalization capabilities. To address this gap, we present SpatialBench, a cross-paradigm, domain-diverse benchmark for spatial foundation models with deterministic sampling. SpatialBench features unprecedented scale and rigorous deterministic design, comprising 19 datasets and 546 scenes across 5 diverse spatial domains. It comprehensively evaluates 41 models across 6 paradigms on 5 task suites under 4 different input density settings. Our extensive evaluation reveals that current models are not yet all-round players, and uncovers crucial insights for future advancement. Specifically, we demonstrate that full-context attention maximizes accuracy while bounded-memory strategies unlock long-sequence scalability. Moreover, our empirical evaluations in challenging embodied and egocentric tasks demonstrate that strict domain alignment and high data quality are far more critical to performance than simple dataset scaling. Furthermore, to address the largest data gap identified in our analysis, we go beyond evaluation by introducing a large-scale dataset, DA-Next-5M, and a strong baseline model, DA-Next, pushing the boundaries of spatial representation learning.","authors":["Haosong Peng","Hao Li","Jiaqi Chen","Yuhao Pan","Runmao Yao","Yalun Dai","Fushuo Huo","Fangzhou Hong","Zhaoxi Chen","Haozhao Wang","Dingwen Zhang","Ziwei Liu","Wenchao Xu"],"published":"2026-05-26T17:59:20Z","updated":"2026-05-26T17:59:20Z","abstract_url":"https://arxiv.org/abs/2605.27367v1","html_url":"https://arxiv.org/html/2605.27367v1","pdf_url":"https://arxiv.org/pdf/2605.27367v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":277415,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：While spatial foundation models have demonstrated impressive performance on standard datasets, a critical question remains: are they truly all-round players capable of generalizing robustly across diverse downstream tasks, arbitrary viewpoints, shifting scene...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:05+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27351v1","title":"Feedforward 3D Editing Learns from Semantic-Part Transformation","abstract":"3D editing is a fundamental capability for scalable 3D content creation. While image editing has rapidly evolved toward large-scale feedforward generative paradigms, 3D AI generation remains dominated by training-free editing pipelines. A central challenge of feedforward 3D editing lies in the lack of high-quality paired supervision. Editable 3D assets require simultaneous preservation of geometry, multi-view consistency, structural coherence, and localized edit controllability. Existing 3D editing datasets often rely on independently generated assets, image-mediated reconstruction or narrow edit taxonomies, leading to inaccurate localization, weak preservation, blurred edit boundaries, and limited semantic consistency. In this work, we introduce a new perspective: scalable feedforward 3D editing should be learned from semantic-part transformations. Based on this insight, we propose Pxform, a high-quality 3D editing dataset with over 100K consistent before/after editing pairs across seven edit types. Instead of treating objects as unstructured shapes, our pipeline grounds edits directly in semantic 3D parts. Built upon Pxform, we further propose PartFlow, a feedforward 3D editing network that injects source-aware latent control into pretrained 3D generative priors. PartFlow introduces mask-aware velocity preservation and render-space consistency supervision to jointly improve edit fidelity and source preservation, while requiring no 3D edit mask during inference. Extensive experiments demonstrate that high-quality semantic-part supervision substantially improves scalable 3D editing, enabling PartFlow to achieve state-of-the-art performance on both geometric and appearance editing benchmarks.","authors":["Jiawei Weng","Saining Zhang","Zhenxin Diao","Peishuo Li","Henghaofan Zhang","Junhao Chen","Hao Zhao"],"published":"2026-05-26T17:51:59Z","updated":"2026-05-26T17:51:59Z","abstract_url":"https://arxiv.org/abs/2605.27351v1","html_url":"https://arxiv.org/html/2605.27351v1","pdf_url":"https://arxiv.org/pdf/2605.27351v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":67209,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：3D editing is a fundamental capability for scalable 3D content creation. While image editing has rapidly evolved toward large-scale feedforward generative paradigms, 3D AI generation remains dominated by training-free editing pipelines. A central challenge of...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:05+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27348v1","title":"When Eyes Betray AI: Social Gaze Consistency as a Semantic Cue for AI-Generated Image Detection","abstract":"Recent generative models have largely closed the gap on low-level artifacts - pixel fingerprints, frequency anomalies, upsampling traces - particularly in person-centric and partial-edit settings where the manipulated region is small and surrounded by photometrically authentic content. We introduce Social Gaze Consistency, a high-level semantic cue defined as the mutual coherence of gaze direction, head-eye alignment, and pupil placement between interacting individuals, and show that it constitutes a previously underutilized detection axis orthogonal to existing low-level paradigms. We instantiate this insight through three coupled mechanisms: (i) a controlled diagnostic dataset with region-specific perturbations of gaze-consistent imagery, where strict pair-level grouping forecloses generator-fingerprint memorization as an optimization-time shortcut rather than relying on augmentation; (ii) Block-Compositional Caption Supervision, which holds a single 5-block reasoning skeleton invariant across 1,250 macro-combined captions, decoupling reasoning consistency from surface diversity; (iii) Cross-architecture validation showing the same supervision improves a vision-language backbone (FakeVLM) by +3.7 pp on the COCOAI Interaction subset (balanced accuracy 67.8 -> 71.5) and +1.3 pp on the COCOAI Person subset (83.0 -> 84.3), with consistent gains on a vision-only backbone (Effort), evidencing a backbone-agnostic cue. Real- and fake-class recalls rise simultaneously, ruling out a \"predict-all-fake\" artifact. A four-step mechanistic account - paired-edit shortcut blocking, hard-to-easy difficulty transfer, CLIP prior preservation, and diffusion-family shared spectral weakness in periocular structure - explains why training on a single inpainter (FLUX.1-Fill) transfers to multi-generator suites. We will release the code upon acceptance to facilitate reproducibility.","authors":["Kim Jihyeon","Sohee Kim","Soosan Lee","Souhwan Jung","James Matthew Rehg","Hyesong Choi"],"published":"2026-05-26T17:50:17Z","updated":"2026-05-26T17:50:17Z","abstract_url":"https://arxiv.org/abs/2605.27348v1","html_url":"https://arxiv.org/html/2605.27348v1","pdf_url":"https://arxiv.org/pdf/2605.27348v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":91835,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Recent generative models have largely closed the gap on low-level artifacts - pixel fingerprints, frequency anomalies, upsampling traces - particularly in person-centric and partial-edit settings where the manipulated region is small and surrounded by photome...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:05+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27343v1","title":"Towards Controllable Image Generation through Representation-Conditioned Diffusion Models","abstract":"Diffusion models have emerged as powerful tools for high-quality image generation and editing, but guiding these models to produce specific outputs remains a challenge. Conventional approaches rely on conditioning mechanisms, such as text prompts or semantic maps, which require extensively annotated datasets. In this preliminary work, we explore diffusion models conditioned on representations from a pre-trained self-supervised model. The self-conditioning mechanism not only improves the quality of unconditional image generation, but also provides a representation space that can be used to control the generation. We explore this conditioning space by identifying directions of variations, and demonstrate promising properties in terms of smoothness and disentanglement.","authors":["Nithesh Chandher Karthikeyan","Jonas Unger","Gabriel Eilertsen"],"published":"2026-05-26T17:46:25Z","updated":"2026-05-26T17:46:25Z","abstract_url":"https://arxiv.org/abs/2605.27343v1","html_url":"https://arxiv.org/html/2605.27343v1","pdf_url":"https://arxiv.org/pdf/2605.27343v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":17257,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Diffusion models have emerged as powerful tools for high-quality image generation and editing, but guiding these models to produce specific outputs remains a challenge. Conventional approaches rely on conditioning mechanisms, such as text prompts or semantic...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:05+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27336v1","title":"PARE: Pruning and Adaptive Routing for Efficient Video Generation","abstract":"Video Diffusion Transformers (DiTs) generate high-quality videos but demand substantial compute due to wide blocks, deep architectures, and iterative sampling. Recent methods reduce cost by compressing width, depth, or sampling steps, but typically commit to a fixed architecture that cannot adapt to individual inputs or denoising stages. We propose PARE (Pruning and Adaptive Routing for Efficient video generation), which jointly compresses width and depth with structure-aware pruning and input-adaptive routing. For width, we observe that attention heads specialize into spatial and temporal roles, and design importance scoring that accounts for this distinction to prevent motion-critical temporal heads from being pruned prematurely. For depth, we train a lightweight router conditioned on denoising timestep and visual content to dynamically select which blocks to execute at each step, enabling per-input compute adaptation rather than static block removal. A progressive pipeline first recovers width-pruned quality via distillation, then jointly optimizes the student and router to decouple the two learning objectives. Experiments on Wan2.1-14B for both image-to-video and text-to-video generation show that PARE substantially reduces per-step computation while preserving quality across VBench dimensions, and composes with step distillation for further acceleration.","authors":["Yutong Wang","Yunke Wang","Tianfan Xue","Yu Qiao","Yaohui Wang","Xinyuan Chen","Chang Xu"],"published":"2026-05-26T17:43:25Z","updated":"2026-05-26T17:43:25Z","abstract_url":"https://arxiv.org/abs/2605.27336v1","html_url":"https://arxiv.org/html/2605.27336v1","pdf_url":"https://arxiv.org/pdf/2605.27336v1.pdf","matched_keywords":["video","diffusion"],"source_used":"html","source_text_chars":53410,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, diffusion 相关；摘要显示其主要贡献为：Video Diffusion Transformers (DiTs) generate high-quality videos but demand substantial compute due to wide blocks, deep architectures, and iterative sampling. Recent methods reduce cost by compressing width, depth, or sampling steps, but typically commit to...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:05+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27318v1","title":"Q-GeoMem: Question-Guided Geometric Memory for Video Spatial Reasoning","abstract":"Video spatial reasoning requires accumulating viewpoint-dependent evidence over time while retaining information useful to the question being asked. Existing spatial video-language models improve geometric perception and long-range context modeling, but often treat memory as a generic temporal cache, which can introduce redundant or irrelevant geometry and weaken long-horizon reasoning. We propose \\textbf{\\ours}, a question-guided geometric memory framework for video spatial reasoning. \\ours injects camera-conditioned geometry into visual tokens and maintains two complementary memories: a Fine-Grained Context Bank for recent dense features and camera states, and a Semantic-Geometric Evidence Bank for compact long-range evidence. Each candidate frame is scored by the product of Q-Former-based question relevance and novelty with respect to the retained bank; this score is stored and reused during reading, while a capacity-based replacement rule keeps the bank compact. During reasoning, both memories are read before update and adaptively fused with the current frame representation. Experiments on VSI-Bench and VSTI-Bench show that \\ours achieves state-of-the-art performance among evaluated spatial reasoning models, validating the effectiveness of question-guided geometric memory. Ablations further verify the contribution of the proposed evidence scoring mechanism.","authors":["Xianqiang Gao","Qizhi Chen","Delin Qu","Haoming Song","Zhigang Wang","Bin Zhao","Dong Wang","Xuelong Li"],"published":"2026-05-26T17:26:29Z","updated":"2026-05-26T17:26:29Z","abstract_url":"https://arxiv.org/abs/2605.27318v1","html_url":"https://arxiv.org/html/2605.27318v1","pdf_url":"https://arxiv.org/pdf/2605.27318v1.pdf","matched_keywords":["video","representation"],"source_used":"html","source_text_chars":49652,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation 相关；摘要显示其主要贡献为：Video spatial reasoning requires accumulating viewpoint-dependent evidence over time while retaining information useful to the question being asked. Existing spatial video-language models improve geometric perception and long-range context modeling, but often...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27310v1","title":"How and What to Imagine? Visual Thinking in Unified Multimodal Models for Cross-View Spatial Reasoning","abstract":"Cross-view spatial reasoning remains a weak spot for vision-language models (VLMs): they often reason in language and lose the fine-grained geometry needed for the task. Thinking with images aims to address this by generating an intermediate thinking image, but recent work shows that models often ignore the visual evidence in these traces. We therefore ask how to make visual thinking matter, and what kind of visual thinking works best. We study these questions in unified multimodal models (UMMs), which natively support interleaved image-text generation. For the first question, we propose View Dropout (VDrop), a training-time intervention that hides parts of one input view from the answer span while keeping them visible to the thinking-image tokens. This encourages the model to use the thinking image when answering, instead of relying only on the input views. Once the thinking image is used for answer prediction, we study which type of visual thinking is most effective. We frame this as a learnability-informativeness tradeoff and compare three thinking-image variants: top-down, panoramic, and point-matching renderings. Trained on synthetic scenes and evaluated on five real-world out-of-domain benchmarks, panoramic visual thinking with VDrop is the only configuration that is both informative and learnable, and it achieves the best out-of-domain generalization.","authors":["Qian Yang","Ankur Sikarwar","Huy Le","Le Zhang","Zhuan Shi","Perouz Taslakian","Aishwarya Agrawal"],"published":"2026-05-26T17:20:05Z","updated":"2026-05-26T17:20:05Z","abstract_url":"https://arxiv.org/abs/2605.27310v1","html_url":"https://arxiv.org/html/2605.27310v1","pdf_url":"https://arxiv.org/pdf/2605.27310v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":75940,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Cross-view spatial reasoning remains a weak spot for vision-language models (VLMs): they often reason in language and lose the fine-grained geometry needed for the task. Thinking with images aims to address this by generating an intermediate thinking image, b...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27304v1","title":"PlayClass: Automated Play Behaviour Classification in Poultry","abstract":"Automated monitoring of animal welfare has largely targeted negative indicators, leaving positive welfare behaviours such as play underexplored. To address this gap, we present PlayClass, a pipeline for play-behaviour classification in poultry from top-down pen video. The pipeline leverages long-duration tracking with SAM 3 via YOLO-guided chunk boundaries to minimise identity errors in point-based prompting, and frozen embeddings from image and video foundation models for play action classification. Although handcrafted motion features from tracked masks alone achieved competitive accuracy, V-JEPA 2.1 consistently outperformed all other backbones across model scales, reaching 77.0 macro-averaged F$_1$ when combined with handcrafted features. Despite this result, the dataset remains challenging due to play sub-types sharing similar kinematic profiles with non-play and inter-bird occlusion. Overall, our work provides encouraging evidence towards automated frameworks for play behaviour classification in poultry.","authors":["Prince Ravi Leow","Neil Scheidwasser","Rebecca Oscarsson","Per Jensen","Samir Bhatt","David Alejandro Duchêne"],"published":"2026-05-26T17:13:36Z","updated":"2026-05-26T17:13:36Z","abstract_url":"https://arxiv.org/abs/2605.27304v1","html_url":"https://arxiv.org/html/2605.27304v1","pdf_url":"https://arxiv.org/pdf/2605.27304v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":35847,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Automated monitoring of animal welfare has largely targeted negative indicators, leaving positive welfare behaviours such as play underexplored. To address this gap, we present PlayClass, a pipeline for play-behaviour classification in poultry from top-down p...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27295v1","title":"Gemini Embedding 2: A Native Multimodal Embedding Model from Gemini","abstract":"We introduce Gemini Embedding 2, a native multimodal embedding model that allows embedding video, audio, image, and text modalities in a unified representation space. We leverage the multimodal capabilities of Gemini to produce embeddings for arbitrary combinations of interleaved inputs across all these modalities that generalize well across a wide variety of tasks. Applying large-scale contrastive learning in a multi-task multi-stage training setup, we achieve state-of-the-art performance on key embedding benchmarks including unimodal, cross-modal, and multimodal retrieval spanning a diverse set of tasks. We show that our embedding model demonstrates strong performance (with a score of 62.9 R@1 on MSCOCO, 68.8 NDCG@10 on Vatex, 69.9 on MTEB multilingual and 84.0 on MTEB Code) across a variety of tasks surpassing the performance of specialized models. These unified capabilities make Gemini Embedding 2 a promising candidate for downstream use cases such as RAG, recommendation and search. Furthermore, its robust zero-shot performance across distinct fields - from astronomy and bioscience to fine arts and the culinary arts - establishes it as a highly reliable, out-of-the-box representation even for specialized domains.","authors":["Madhuri Shanbhogue","Zhe Li","Shanfeng Zhang","Gustavo Hernández Ábrego","Shih-Cheng Huang","Aashi Jain","Daniel Salz","Sonam Goenka","Chaitra Hegde","Ji Ma","Feiyang Chen","Jiaxing Wu","Tanmaya Dabral","Babak Samari","Kevin Poulet","Daniel Cer","Kaifeng Chen","Paul Suganathan","Hui Hui","Jovan Andonov","Philippe Schlattner","Jay Han","Iftekhar Naim","Wing Lowe","Vladimir Pchelin","Albert Yang","Yi-Ting Chen","Zhongli Ding","Grace Zhang","Georg Heigold","Yichang Chen","Antoine Reveillon","Brendan Mccloskey","Wenlei Zhou","Dahun Kim","Rui Meng","Emma Wang","Jack Zheng","Halley Fede","Zhen Yang","Keegan Mosley","Brian Potetz","Sahil Dua","Henrique Schechter Vera","Shen Gao","Hesen Zhang","Andreas Hess","Hengxuan Ying","Alberto Montes","Karan Gill","Min Choi","Sebastian Russo","Anja Hauth","Jinhyuk Lee","Michael Boratko","Megan Barnes","Vikram Rao","Claudiu Musat","Cyril Allauzen","Ehsan Variani","Shankar Kumar","Tom Bagby","Junyi Jiao","Yang Gu","Tengxin Li","Ayush Agrawal","Roberto Santana","Dev Nath","Stephen Karukas","Shuoxuan Han","Lucia Loher","Alice Twu","Nidhi Vyas","Siddharth Bhai","Frank Palma Gomez","Wangyuan Zhang","Chaoren Liu","Jizheng Yang","Steve Qiu","Shijie Zhang","Sujay Kulkarni","Sascha Rothe","Sean Nakamoto","Raphael Hoffmann","Zach Gleicher","Yunhsuan Sung","Qin Yin","Tom Duerig","Mojtaba Seyedhosseini"],"published":"2026-05-26T17:07:55Z","updated":"2026-05-26T17:07:55Z","abstract_url":"https://arxiv.org/abs/2605.27295v1","html_url":"https://arxiv.org/html/2605.27295v1","pdf_url":"https://arxiv.org/pdf/2605.27295v1.pdf","matched_keywords":["video","retrieval","representation","multimodal"],"source_used":"html","source_text_chars":49633,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, representation, multimodal 相关；摘要显示其主要贡献为：We introduce Gemini Embedding 2, a native multimodal embedding model that allows embedding video, audio, image, and text modalities in a unified representation space. We leverage the multimodal capabilities of Gemini to produce embeddings for arbitrary combin...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27243v1","title":"Can Retrieval Heads See Images? Multimodal Retrieval Heads in Long-Context Vision-Language Models","abstract":"Large vision-language models increasingly rely on long-context modeling to reason over documents, hour-level videos, and long-horizon agent trajectories, requiring them to locate relevant evidence across interleaved text and images. Prior work has studied this behavior using retrieval heads in large language models, but its copy-based criterion does not directly apply when evidence appears in images. We introduce a multimodal retrieval head detection method that scores attention from question tokens to textual or visual evidence. With this method, we show that multimodal retrieval heads are sparse, intrinsic, and causally important: only 4.4-10.2% of attention heads account for 50% of the positive retrieval-score mass, and masking the top-5% selected heads drops MMLongBench-Doc from 48.2% to 5.7% and SlideVQA from 71.2% to 8.9%, while random-head masking is far less damaging. Further analysis shows that these heads are partly shared across modalities yet remain dynamic within each modality, with image retrieval heads changing more than text retrieval heads as context length and haystack modality change. Without further training, we find that these heads can also be used directly to rank visually rich documents: on MMDocIR, Qwen3-VL-8B selected-head scoring improves Recall@1 by 7.7/7.4 macro/micro points for page retrieval and 6.3/6.8 points for layout retrieval over the strongest reported baseline.","authors":["Aaron Branson Cigres Li","Zhaowei Wang","Yu Zhao","Yiming Du","Haobo Li","Xiyu Ren","Ginny Wong","Simon See","Lishu Luo","Haodong Duan","Pasquale Minervini","Yangqiu Song"],"published":"2026-05-26T16:24:29Z","updated":"2026-05-26T16:24:29Z","abstract_url":"https://arxiv.org/abs/2605.27243v1","html_url":"https://arxiv.org/html/2605.27243v1","pdf_url":"https://arxiv.org/pdf/2605.27243v1.pdf","matched_keywords":["video","retrieval","agent","multimodal"],"source_used":"abstract","source_text_chars":1520,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, agent, multimodal 相关；摘要显示其主要贡献为：Large vision-language models increasingly rely on long-context modeling to reason over documents, hour-level videos, and long-horizon agent trajectories, requiring them to locate relevant evidence across interleaved text and images. Prior work has studied thi...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27235v1","title":"MRT: Masked Region Transformer for Layered Image Generation and Editing at Scale","abstract":"Layered image generation and editing is a fundamental capability that enables layer-wise reuse, editing, and composition of generated visual content, analogous to word-level editing in natural language. Despite its importance, this remains an underexplored area at scale. To address this gap, we present MRT, a 20B-parameter masked region diffusion model tailored for multi-layer transparent image generation and editing, trained on over 10M multilingual design samples spanning diverse aspect ratios and textual prompts. To fully leverage this scale, we make two key technical contributions. First, we unify three complementary tasks including text-to-layers, image-to-layers, and layers-to-layers within a shared masked region diffusion framework, where selective token masking enables flexible layer-wise generation and editing. Second, to enable overflow layer generation, we introduce an overflow-aware canvas layer that handles boundary inconsistencies and supports semi-transparent background synthesis, enabling complete editable layers extending beyond visible canvas boundaries. Additionally, we apply diffusion distillation to achieve 8-step, real-time multi-layer generation with minimal quality degradation. Extensive experiments demonstrate that our framework substantially outperforms prior state-of-the-art approaches, including various commercial systems, across all three tasks, establishing a new benchmark for multi-layer transparent image generation. Notably, our model significantly outperforms the concurrent Qwen-Image-Layered model in image-to-layers quality according to user-study results, while achieving 10-100\\times faster inference and reducing activation GPU memory consumption by 50-90\\% during image-to-layer inference.","authors":["Zhicong Tang","Zhao Zhang","Jingye Chen","Mohan Zhou","Yifan Pu","Yuchi Liu","Yalong Bai","Ethan Smith","Yuhui Yuan"],"published":"2026-05-26T16:16:19Z","updated":"2026-05-26T16:16:19Z","abstract_url":"https://arxiv.org/abs/2605.27235v1","html_url":"https://arxiv.org/html/2605.27235v1","pdf_url":"https://arxiv.org/pdf/2605.27235v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":88589,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Layered image generation and editing is a fundamental capability that enables layer-wise reuse, editing, and composition of generated visual content, analogous to word-level editing in natural language. Despite its importance, this remains an underexplored ar...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27203v1","title":"Generative Animations: A Multi-Model Pipeline for Prompt-Driven Motion Synthesis","abstract":"Animation elevates digital documents into immersive experiences, yet creating custom motion paths remains cumbersome, requiring designers to manually select presets, plot Bézier points, and configure timing properties. We introduce Generative Animations, a system that transforms natural language prompts into production-ready animations. By chaining Large Language Models (LLMs) for semantic parsing with the Segment Anything Model (SAM) for visual grounding, our pipeline automatically generates motion paths that respect scene geometry, handle depth-based occlusions, and honor 3D perspective transforms. We demonstrate the system through three use cases: contour-following trajectories, orbital animations with z-order awareness, and perspective-aligned motion on transformed objects.","authors":["Mannat Khurana","Sanyam Jain","Rishav Agarwal"],"published":"2026-05-26T15:58:30Z","updated":"2026-05-26T15:58:30Z","abstract_url":"https://arxiv.org/abs/2605.27203v1","html_url":"https://arxiv.org/html/2605.27203v1","pdf_url":"https://arxiv.org/pdf/2605.27203v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":870,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Animation elevates digital documents into immersive experiences, yet creating custom motion paths remains cumbersome, requiring designers to manually select presets, plot Bézier points, and configure timing properties. We introduce Generative Animations, a sy...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27194v1","title":"Not All Tokens Matter Equally: Dynamic In-context Vector Distillation with Decisive-Token Supervision for Long-form Medical Report Generation","abstract":"Distilling demonstration effects into hidden-space interventions offers a lightweight alternative to full finetuning. However, existing multimodal variants are mostly evaluated on short-form tasks, where outputs end after a few tokens. Extending these methods to long-form generation exposes a fundamental yet underexamined limitation: token-level distillation implicitly treats all output tokens as equally informative, but long-form outputs are dominated by high-frequency template and grammatical tokens, while the tokens that actually determine output quality are sparsely distributed. In medical report generation (MRG), two such decisive tokens stand out: pathology-related tokens that determine diagnostic content, and the end-of-sequence (EOS) event that determines termination. Both receive insufficient supervision under uniform cross-entropy, and autoregressive decoding further compounds the problem by drifting away from teacher-forced trajectories. We propose DIVE, a frozen-backbone distillation framework that addresses long-form report generation through two complementary mechanisms matched to these failures. Decisive-token supervision restores supervision balance by upweighting the cross-entropy contribution of pathology-related tokens and the EOS event, ensuring that content fidelity and termination are learned during training rather than imposed at decoding time. State-conditioned dynamic steering replaces fixed open-loop residuals with hidden-state-dependent adapters, allowing the injected signal to adapt as decoding drifts. Experiments on MIMIC-CXR and CheXpert Plus with two medical VLM backbones show that DIVE consistently ranks among the strongest methods across lexical and clinical-proxy metrics. Our method achieves the best BLEU-4, ROUGE-L, and RadGraph F1 in all dataset--backbone settings, while remaining competitive on coarse label-level CheXbert F1.","authors":["Ning Wu","Rui Liu","Xinkun Lin","Weixing Chen","Jinxi Xiang","Tao Wei","Lina Yao","Mingjie Li"],"published":"2026-05-26T15:46:00Z","updated":"2026-05-26T15:46:00Z","abstract_url":"https://arxiv.org/abs/2605.27194v1","html_url":"https://arxiv.org/html/2605.27194v1","pdf_url":"https://arxiv.org/pdf/2605.27194v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":69340,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Distilling demonstration effects into hidden-space interventions offers a lightweight alternative to full finetuning. However, existing multimodal variants are mostly evaluated on short-form tasks, where outputs end after a few tokens. Extending these methods...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27178v1","title":"FoundObj: Self-supervised Foundation Models as Rewards for Label-free 3D Object Segmentation","abstract":"We address the challenging task of 3D object segmentation in complex scene point clouds without relying on any scene-level human annotations during training. Existing methods are typically constrained to identifying simple objects, primarily due to insufficient object priors in the learning process. In this paper, we present FoundObj, a novel framework featuring a superpoint-based object discovery agent that incrementally merges suitable neighboring superpoints, guided by our innovative semantic and geometric reward modules. These modules synergistically leverage semantic and geometric priors from self-supervised 2D/3D foundation models, providing complementary feedback to the object discovery agent and enabling robust identification of multi-class objects through reinforcement learning. Extensive experiments on diverse benchmarks demonstrate that our approach consistently outperforms existing baselines. Notably, our method exhibits strong generalization in zero-shot and long-tail scenarios, underscoring its potential for scalable, label-free 3D object segmentation.","authors":["Zihui Zhang","Zhixuan Sun","Yafei Yang","Jinxi Li","Jiahao Chen","Bo Yang"],"published":"2026-05-26T15:32:32Z","updated":"2026-05-26T15:32:32Z","abstract_url":"https://arxiv.org/abs/2605.27178v1","html_url":"https://arxiv.org/html/2605.27178v1","pdf_url":"https://arxiv.org/pdf/2605.27178v1.pdf","matched_keywords":["3d","agent"],"source_used":"html","source_text_chars":76841,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent 相关；摘要显示其主要贡献为：We address the challenging task of 3D object segmentation in complex scene point clouds without relying on any scene-level human annotations during training. Existing methods are typically constrained to identifying simple objects, primarily due to insufficie...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27155v1","title":"Semantic Robustness Probing via Inpainting: An Interactive Tool for Safety-Critical Object Detection","abstract":"Testing object detectors in safety-critical domains requires semantically meaningful probes beyond pixel-level corruptions. We present SemProbe, a tool for semantic robustness probing: users upload deployment images, create masks manually or automatically, select operational design domain-derived factors (or custom prompts), and run diffusion-based controlled inpainting. The system supports batch jobs, parallel seed/workflow variations, and configurable generation parameters. After each output, model inference runs automatically and displays annotated before/after comparisons with performance deltas. All probes are logged as structured artifacts, enabling traceable robustness evidence aligned with safety evaluation workflows. We demonstrate \\textsc{SemProbe} on hand detection for dimension saws, targeting factors from insurance-oriented test criteria.","authors":["Nico Steckhan","Krutarth Prajapati","Weija Shao","Silvia Vock"],"published":"2026-05-26T15:15:38Z","updated":"2026-05-26T15:15:38Z","abstract_url":"https://arxiv.org/abs/2605.27155v1","html_url":"https://arxiv.org/html/2605.27155v1","pdf_url":"https://arxiv.org/pdf/2605.27155v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":13468,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Testing object detectors in safety-critical domains requires semantically meaningful probes beyond pixel-level corruptions. We present SemProbe, a tool for semantic robustness probing: users upload deployment images, create masks manually or automatically, se...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27154v1","title":"Touch-R1: Reinforcing Touch Reasoning in MLLMs","abstract":"While rule-based reinforcement learning has recently catalyzed explicit reasoning in multimodal models, tactile reasoning remains largely underexplored. Existing tactile-language models primarily rely on supervised or contrastive objectives, which limits their capacity to ground predictions in physical evidence or rectify misleading visual priors. Tactile reasoning introduces two modality-specific challenges: the ordinal nature of physical attributes (e.g., hardness, roughness) and the cross-sensor distribution shifts inherent in optical tactile hardware. In this work, we introduce TouchReason-1M, a large-scale multimodal dataset comprising over 1M synchronized tactile pairs across four distinct sensors, and TouchReason-Bench, a rigorous framework for evaluating tactile perception and visual-tactile conflict resolution. Building upon these, we propose Touch-R1, a tactile reasoning MLLM based on Qwen2.5-VL-7B. Touch-R1 is trained via a tactile-grounded GRPO objective that combines ordinal-aware accuracy, cross-sensor physical consistency, structured-format control, and an input-side tactile grounding objective. Specifically, the tactile-use reward assigns credit only when authentic tactile inputs yield superior correctness relative to counterfactual controls where the tactile stream is removed, shuffled, or noise-masked. On TouchReason-Bench, Touch-R1-7B outperforms Octopi-13B by 18.4\\% and GPT-4o by 24.7\\% on average. Its structured reasoning traces reveal emergent behaviors of probing, comparison, and revision, demonstrating that R1-style reasoning can be effectively grounded in physical contact.","authors":["Yingxin Lai","Yafei Zhou","Fucai Zhu","Siyu Zhu","Weihao Yuan"],"published":"2026-05-26T15:14:56Z","updated":"2026-05-26T15:14:56Z","abstract_url":"https://arxiv.org/abs/2605.27154v1","html_url":"https://arxiv.org/html/2605.27154v1","pdf_url":"https://arxiv.org/pdf/2605.27154v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":47239,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：While rule-based reinforcement learning has recently catalyzed explicit reasoning in multimodal models, tactile reasoning remains largely underexplored. Existing tactile-language models primarily rely on supervised or contrastive objectives, which limits thei...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27146v1","title":"Chaos-SSL: An Attention-Based Self-Supervised Learning Framework with Chaotic Transformation for Medical Image Classification","abstract":"Self-Supervised Learning (SSL) has emerged as a powerful paradigm to mitigate the reliance on large, annotated datasets, a common bottleneck in medical image analysis. However, standard SSL methods, which rely on simple geometric and color augmentations, may fail to capture the fine-grained, complex textural details necessary for classifying subtle pathologies. This paper introduces Chaos-SSL, a novel two-stage framework for medical image classification. In the first stage, we propose a new self-supervised pre-training strategy that leverages 1D chaotic maps (Logistic, Tent, and Sine) as a complex, non-linear augmentation for contrastive learning. We hypothesize that these chaotic transformations create ``harder'' and more semantically-rich views, forcing a network to learn robust representations of fine-grained medical textures. In the second stage, we introduce an attention-based fusion model that dynamically combines the specialized features from our Chaos-SSL model with the general-purpose features of a larger, ImageNet-pre-trained model. We validate our method on two public datasets: ISIC 2018 (skin lesions) and APTOS 2019 (diabetic retinopathy). Our results demonstrate that the Chaos-SSL model pre-trained with a Tent map for 30 epochs, followed by attention fusion, achieves performance fully competitive with the state-of-the-art, yielding an accuracy of 0.9261 on ISIC 2018 and 0.8726 on APTOS 2019. This significantly outperforms existing SSL methods, including several recent approaches.","authors":["Joao Batista Florindo"],"published":"2026-05-26T15:10:00Z","updated":"2026-05-26T15:10:00Z","abstract_url":"https://arxiv.org/abs/2605.27146v1","html_url":"https://arxiv.org/html/2605.27146v1","pdf_url":"https://arxiv.org/pdf/2605.27146v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":34356,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Self-Supervised Learning (SSL) has emerged as a powerful paradigm to mitigate the reliance on large, annotated datasets, a common bottleneck in medical image analysis. However, standard SSL methods, which rely on simple geometric and color augmentations, may...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27144v1","title":"Is an Image Also Worth 16x16=256 Superpixels? A Framework for Attentional Image Classification","abstract":"Superpixel-based image classification has traditionally leveraged graph neural networks (GNNs) for processing irregular image representations. Recent advances in computer vision, driven by Vision Transformers (ViTs), have introduced new paradigms in self-attentional models, surpassing convolutional neural networks (CNNs) in various tasks. However, a synergistic connection between GNNs, superpixels, and transformers remains unexplored. In this work, we propose Superpixel Transformers (SPT), a novel framework that unifies superpixel-based image classification and ViTs. SPT generalizes the Superpixel Image Classification with Graph Attention Networks (SICGAT) model and ViT to support arbitrary superpixel-based chunking strategies, connectivity graphs, and positional encodings. We introduce refinements including a multidimensional sine-cosine positional encoding and an enriched patch data structure that fully incorporates superpixel shape and color information. By testing SPT across datasets such as CIFAR10, FashionMNIST, and Imagenette, with various superpixel generation and graph connectivity strategies, we demonstrate that SPT achieves superior performance compared to previous superpixel-based GNN methods and remains competitive with ViTs. Notably, our approach addresses the limitations of SICGAT, such as information loss during pixel aggregation, and shows how constrained graph connectivity can enhance ViT performance. SPT bridges the gap between superpixel-based and transformer models, opening avenues for cross-domain generalization and future innovations in hybrid attentional frameworks, and showing that an image can also be worth $16\\times16$ superpixels.","authors":["Pedro Henrique da Costa Avelar","Anderson R. Tavares","Luís C. Lamb"],"published":"2026-05-26T15:09:46Z","updated":"2026-05-26T15:09:46Z","abstract_url":"https://arxiv.org/abs/2605.27144v1","html_url":"https://arxiv.org/html/2605.27144v1","pdf_url":"https://arxiv.org/pdf/2605.27144v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":68023,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Superpixel-based image classification has traditionally leveraged graph neural networks (GNNs) for processing irregular image representations. Recent advances in computer vision, driven by Vision Transformers (ViTs), have introduced new paradigms in self-atte...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:08+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27139v1","title":"Unsupervised Deep Image Prior for Sparse-View and Limited-Angle Electron Tomography","abstract":"Electron tomography (ET) plays an important role in the three-dimensional (3D) characterization of nanomaterials. However, under limited-angle and sparse-view conditions, conventional algorithms produce degraded reconstructions, which compromise the quality and interpretability of resulting 3D data. In this paper, we present deep image prior (DIP), an unsupervised deep learning (DL) approach, for highly degraded tomography acquisitions and demonstrate, using simulated data, that its performance is comparable to that of supervised approaches requiring training datasets, even for tilt ranges as limited as 60° and tilt increments of 10°. We then apply it to experimental data and show that it enables reliable 3D quantification under both sparse-view and limited-angle conditions, highlighting its potential for a wide range of materials and acquisition modalities.","authors":["Serge Brosset","Daniel del Pozo Bueno","Thomas David","Laure Guetaz","Philippe Ciuciu","Zineb Saghi"],"published":"2026-05-26T15:07:01Z","updated":"2026-05-26T15:07:01Z","abstract_url":"https://arxiv.org/abs/2605.27139v1","html_url":"https://arxiv.org/html/2605.27139v1","pdf_url":"https://arxiv.org/pdf/2605.27139v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":955,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Electron tomography (ET) plays an important role in the three-dimensional (3D) characterization of nanomaterials. However, under limited-angle and sparse-view conditions, conventional algorithms produce degraded reconstructions, which compromise the quality a...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-05-27T05:12:08+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27136v1","title":"Leveraging Visual Signals for Robust Token-Level Uncertainty in Vision-Language Generation","abstract":"Uncertainty quantification (UQ) remains a critical challenge in Large Vision Language Models (LVLMs) for reliable predictions and real-world deployment. However, most existing methods are adapted from the LLM literature and primarily focus on the language modality, leaving the contribution of visual information to LVLM uncertainty largely underexplored. In this paper, we investigate how LVLMs process visual information and whether this process can be used to improve uncertainty estimation. By analyzing hidden representations after the integration of visual features during the generation process, we observe that high-confidence predictions rely more heavily on visual content than uncertain ones. Building on this insight, we propose Visual-Grounded Token UQ (VIG-TUQ), a training-free framework that explicitly incorporates visual grounding into uncertainty estimation by weighting token-level language uncertainty with visual grounding scores. We evaluate VIG-TUQ on multiple datasets and across diverse LVLM architectures, including early-fusion, late-fusion, and native-fusion models. Results indicate that our method often improves upon existing token-level uncertainty approaches. Code and data will be made available upon acceptance.","authors":["Joseph Hoche","David Brellmann","Gianni Franchi"],"published":"2026-05-26T15:04:55Z","updated":"2026-05-26T15:04:55Z","abstract_url":"https://arxiv.org/abs/2605.27136v1","html_url":"https://arxiv.org/html/2605.27136v1","pdf_url":"https://arxiv.org/pdf/2605.27136v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27135v1","title":"Do Modern Post-Hoc Watermarking Methods Beat Broken-Arrows?","abstract":"With the rapid proliferation of generative models, such as diffusion models, digital watermarking has emerged as a crucial solution for identifying AI-generated images. Modern post-hoc watermarking schemes use neural networks to achieve an extremely low false-alarm rate while remaining robust to common image transformations. However, there is a lack of comparison between these modern methods and classic ones, particularly in real-world scenarios where robustness and security take precedence over achieving an extremely low false-alarm probability. In this paper, we propose a fair comparison of robustness and security between modern and classic post-hoc watermarking across various types of classic augmentations and recent sophisticated attacks. Our experiments show that, in a realistic scenario, classic watermarking outperforms modern techniques in terms of security while maintaining robustness.","authors":["Enoal Gesny","Eva Giboulot"],"published":"2026-05-26T15:04:46Z","updated":"2026-05-26T15:04:46Z","abstract_url":"https://arxiv.org/abs/2605.27135v1","html_url":"https://arxiv.org/html/2605.27135v1","pdf_url":"https://arxiv.org/pdf/2605.27135v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27129v1","title":"YOLO26-RipeLoc Lite: A lightweight architecture for tomato ripeness detection and picking point localization in greenhouse robotic harvesting","abstract":"In greenhouse tomato production, automated harvesting requires accurate detection of ripe tomatoes, ripeness classification, and precise picking-point localization for robotic end-effectors. This paper proposes YOLO26-RipeLoc Lite, a lightweight deep learning architecture based on YOLO26 for simultaneous detection, ripeness classification, and center-point localization of greenhouse tomatoes. The model introduces three modifications: (1) a Lightweight Feature Pyramid Network (LFPN) with depthwise separable convolutions for efficient multi-scale fusion, (2) a Ripeness-Aware Attention Module (RAAM) with dual pooling and a learnable ripeness bias vector for enhanced color-texture discrimination, and (3) a Compact Detection Head (CDH) with shared convolutions and an integrated center-point regression branch for direct grasp planning. The model is evaluated on a custom dataset of 1,500 images with 6,227 instances (3,566 ripe, 2,661 unripe) from the SILAL greenhouse, Abu Dhabi, UAE. YOLO26-RipeLoc Lite achieves mAP@0.5 of 92.9% (95.2% ripe, 90.6% unripe) with the highest precision (95.2%) among all evaluated architectures using only 2.38M parameters. Post-training BatchNorm pruning at 30% reduces parameters to ~1.8M with negligible accuracy loss. Ablation studies confirm that greenhouse-aware HSV augmentation provides the largest improvement (+2.02 pp mAP@50), backbone freezing achieves peak precision (93.8%), and 3-phase progressive unfreezing yields the best localization quality (mAP@50:95 of 64.6%). Comparisons with YOLOv8n/s, YOLO11n/s, YOLO12n/s, and YOLO26s confirm superior accuracy-efficiency: 2.9 pp higher precision than YOLO12n with 7.0% fewer parameters and integrated center-point localization for robotic end-effector guidance.","authors":["Rajmeet Singh","Manveen Kaur","Shahpour Alirezaee","Irfan Hussain"],"published":"2026-05-26T15:00:24Z","updated":"2026-05-26T15:00:24Z","abstract_url":"https://arxiv.org/abs/2605.27129v1","html_url":"https://arxiv.org/html/2605.27129v1","pdf_url":"https://arxiv.org/pdf/2605.27129v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27116v1","title":"COVD: Continual Open-Vocabulary Object Detection with Novel Concept Injection","abstract":"Open-vocabulary object detection (OVD) has made significant progress, enabling detectors to generalize from seen to unseen categories. However, real-world category spaces continually evolve, and existing OVD models still struggle with newly emerging concepts, while repeated full retraining is prohibitively expensive. To this end, we introduce a new task setting, termed Continual OVD with Novel Concept Injection (COVD), where models sequentially learn incoming novel concept groups while preserving prior concepts and original open-vocabulary knowledge, along with a new benchmark, Novel-114. Our key observation is that pretrained visual encoders often already perceive and represent many novel concepts, and the main bottleneck lies in the lack of stable semantic alignment between visual representations and textual concepts. Based on this, we propose NoIn-Det, an efficient continual injection framework without additional parameters. NoIn-Det freezes the visual encoder, preserves the text representation space using only texts of common concepts and previously injected concepts, and injects novel concepts by updating only a small subset of text-branch parameters beneficial to novel concept learning. Extensive experiments show that NoIn-Det effectively learns novel concepts, preserves old knowledge, and consistently outperforms existing continual learning methods for VLMs without introducing additional parameters.Novel-114 and the code will be released.","authors":["Yupeng Zhang","Ruize Han","Yuzhong Feng","Zixin Ren","Yuntong Tian","Liang Wan"],"published":"2026-05-26T14:53:14Z","updated":"2026-05-26T14:53:14Z","abstract_url":"https://arxiv.org/abs/2605.27116v1","html_url":"https://arxiv.org/html/2605.27116v1","pdf_url":"https://arxiv.org/pdf/2605.27116v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27102v1","title":"JLT: Clean-Latent Prediction in Latent Diffusion Transformers","abstract":"Flow matching with clean-data prediction has shown that regressing the clean point can exploit low-dimensional structure more effectively than predicting an ambient noised quantity. We ask whether this principle remains useful after images are mapped into a learned latent space, where compression has already removed much of the raw pixel variability. We introduce JLT, a 130M latent diffusion Transformer over frozen FLUX.2 VAE codes, and compare clean-latent prediction with a matched velocity-prediction DiT under the same representation, backbone, and training settings. Although the three variables x, epsilon, and v are linearly convertible for a fixed corruption time, a local Gaussian analysis shows that velocity regression inherits an isotropic target-covariance floor and amplifies low-variance latent directions, while clean prediction damps them. On ImageNet 256 x 256, JLT-B/1 obtains FID-50K 2.50 with classifier-free guidance, with a large matched-target gap over velocity prediction. These results suggest that prediction targets in latent diffusion are representation-dependent geometric choices, rather than interchangeable algebraic parameterizations.","authors":["Funing Fu","Tenghui Wang","Junyong Cen","Qichao Zhu","Guanyu Zhou"],"published":"2026-05-26T14:41:58Z","updated":"2026-05-26T14:41:58Z","abstract_url":"https://arxiv.org/abs/2605.27102v1","html_url":"https://arxiv.org/html/2605.27102v1","pdf_url":"https://arxiv.org/pdf/2605.27102v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27101v1","title":"Pop-Up Distractions Reveal Bag-of-Events Behavior in Video Large Language Models","abstract":"A key capability for video understanding is reliably linking subjects to events across time, yet whether Video Large Language Models (VideoLLMs) actually achieve this remains unclear. In this work, we introduce DistractionBench to evaluate whether VideoLLMs can robustly link subjects and events in the presence of unrelated video segments. Through controlled interventions, such as inserting short advertisement clips into longer videos, we show that VideoLLMs frequently hallucinate interactions between entities from different segments, incorrectly attributing actions from injected advertisements to subjects in the main video. We characterize this systematic hallucination as bag-of-events (BoE) behavior, where models process videos as collections of events rather than temporally structured sequences. Evaluating 11 popular VideoLLMs, we find that all models exhibit substantial BoE behavior. Our findings suggest that VideoLLMs lack reliable mechanisms for temporal grounding and motivate the development of models with more robust subject-event association.","authors":["Oscar Chew","Serhii Honcharenko","Qian-Hui Chen","Patricia Lu","Dishant Zaveri","Khoa D. Doan","Kuan-Hao Huang"],"published":"2026-05-26T14:41:05Z","updated":"2026-05-26T14:41:05Z","abstract_url":"https://arxiv.org/abs/2605.27101v1","html_url":"https://arxiv.org/html/2605.27101v1","pdf_url":"https://arxiv.org/pdf/2605.27101v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27080v1","title":"Semi-Supervised Gaze Estimation via Disentangled Subspace Contrastive Learning","abstract":"Appearance-based gaze estimation always suffers from poor generalization due to limited annotated samples and insufficient dataset diversity. Leading approaches adopt weakly supervised learning to generate large-scale pseudo-labeled data from unconstrained real-world scenarios, aiming to mitigate the domain shifts. In this work, we devise a simple yet effective semi-supervised learning architecture that leverages unlabeled data to enhance domain generalization, thereby reducing reliance on labor-intensive manual annotations. Our key insight is to impose Jacobian regularization to disentangle feature representations into discriminative subspaces dedicated to specific gaze components, such as pitch and yaw angles. We further exploit the intrinsic ordinal ranking within each subspace for contrastive learning, enabling the model to learn robust gaze representations from a small set of labeled samples and an abundance of unlabeled ones. This ultimately yields our Disentangled Subspace Contrastive Learning (DSCL) framework. Extensive experiments on multiple benchmarks verify that the proposed DSCL is plug-and-play, achieving competitive performance using only 20\\%, 10\\%, and even 5\\% of the annotated data under both in-domain and cross-domain evaluation settings. The public code is available at \\href{https://github.com/da60266/DSCL}{https://github.com/da60266/DSCL}.","authors":["Qida Tan","Hongyu Yang","Wenchao Du"],"published":"2026-05-26T14:31:10Z","updated":"2026-05-26T14:31:10Z","abstract_url":"https://arxiv.org/abs/2605.27080v1","html_url":"https://arxiv.org/html/2605.27080v1","pdf_url":"https://arxiv.org/pdf/2605.27080v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27075v1","title":"SoftCap: Soft-Budget Control for Diffusion Transformer Acceleration","abstract":"Diffusion Transformers (DiTs) achieve strong visual quality, but their iterative denoising process requires many costly Transformer evaluations. Training-free acceleration methods reduce this cost by caching, forecasting, or verifying intermediate features, yet the runtime decision of when to execute a Full step is often driven by fixed schedules or hand-tuned thresholds. We propose \\textbf{SoftCap}, a training-free control layer for cache-based DiT inference. SoftCap couples a Trajectory Drift Observer, which estimates local cache risk from lightweight hidden-state statistics, with a Soft-Budget PI Controller, which adjusts the Full-triggering threshold from realized compute relative to a fixed reference profile. The budget is a soft ceiling: it shapes the threshold but does not require a run to spend a prescribed number of Full evaluations. On FLUX.1-dev, SoftCap improves over SpeCa at a comparable middle-compute operating point, raising ImageReward from 0.967 to 0.981 and reducing LPIPS-Full from 0.518 to 0.498 at nearly identical FLOPs, while target-sweep diagnostics show the intended soft-ceiling behavior as the budget is relaxed.","authors":["Yuhang Zhang","Junxiang Qiu","Huixia Ben","Zhenhua Tang","Shuo Wang","Yanbin Hao"],"published":"2026-05-26T14:24:48Z","updated":"2026-05-26T14:24:48Z","abstract_url":"https://arxiv.org/abs/2605.27075v1","html_url":"https://arxiv.org/html/2605.27075v1","pdf_url":"https://arxiv.org/pdf/2605.27075v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27074v1","title":"IPIBench: Evaluating Interactive Proactive Intelligence of MLLMs under Continuous Streams","abstract":"Recent multimodal large language models (MLLMs) achieve strong performance on reactive question answering, but real-world streaming assistants require proactive reasoning over continuous visual inputs. Existing benchmarks mainly study reactive or proactive interactions in isolated single-turn settings, overlooking dynamic multi-turn scenarios where users may add, modify, or cancel proactive requests alongside interleaved reactive queries. To address this gap, we introduce IPIBench, the first benchmark for evaluating Interactive Proactive Intelligence of MLLMs under streaming video settings. IPIBench covers proactive monitoring, proactive task management, and interleaved reactive-proactive requests. Evaluations on representative MLLMs reveal two major limitations: unstable proactive triggering and weak coordination between reactive and proactive behaviors. We further propose IPI-Agent, a training-free agentic framework with an interaction-control policy and a temporal-gating mechanism for stabilizing proactive triggering and coordinating multi-turn interactions. Experiments show that IPI-Agent consistently improves existing MLLMs across all benchmark settings.","authors":["Jinzhao Li","Yinuo Chen","Wenxuan Song","Yijia Lei","Yichi Zhang","Honglei Yan","Panwang Pan","Miao Liu"],"published":"2026-05-26T14:23:25Z","updated":"2026-05-26T14:23:25Z","abstract_url":"https://arxiv.org/abs/2605.27074v1","html_url":"https://arxiv.org/html/2605.27074v1","pdf_url":"https://arxiv.org/pdf/2605.27074v1.pdf","matched_keywords":["video","agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27067v1","title":"BEAT: Rhythm-Elastic Alignment for Agentic Music-guided Movie Trailer Generation","abstract":"Automatic movie trailer generation must select shots from a full-length film and synchronize them with background music. Existing methods either relegate music alignment to post-processing or enforce rigid one-to-one shot-music mappings, overlooking that professional editing rhythm is elastic: rapid cuts accompany high-energy passages while sustained shots span quieter bars. We introduce BEAT, a framework that addresses this gap with two core components: MuVA, a compact music-visual alignment encoder trained with Sinkhorn-regularized two-stage learning, and Bar-DP, an energy-adaptive dynamic programming algorithm that produces elastic many-to-one alignments following musical dynamics. These components are integrated into a five-phase agentic pipeline that grounds the core alignment in learned cross-modal features while coordinating higher-level creative decisions through structured text signals. To support comprehensive evaluation, we also introduce TrailerArena, a benchmark with 20+ metrics across four complementary dimensions. On TrailerArena, BEAT achieves state-of-the-art performance across shot selection, ordering, and perceptual quality, while producing fully composed trailers end-to-end.","authors":["Yutong Wang","Yunke Wang","Xinyuan Chen","Chang Xu"],"published":"2026-05-26T14:18:13Z","updated":"2026-05-26T14:18:13Z","abstract_url":"https://arxiv.org/abs/2605.27067v1","html_url":"https://arxiv.org/html/2605.27067v1","pdf_url":"https://arxiv.org/pdf/2605.27067v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27032v1","title":"SCKAN: Structural Consensus-based KAN Prototype Learning for Semi-Supervised Pancreas Segmentation","abstract":"Accurate pancreas segmentation is critical for early cancer diagnosis, where annotation scarcity necessitates Semi-Supervised Learning (SSL). However, due to significant inter-sample morphological variability, existing SSL methods face severe generalizability limitations under sparse supervision, leading to the Supervision Bias problem. To address this, we propose Structural Consensus-based KAN Prototype Learning (SCKAN), which constructs the first cross-sample structural consensus learning with Kolmogorov-Arnold Networks (KANs), to achieve more generalizable and accurate segmentation. Specifically, SCKAN contains two key designs: Structure-constrained Prototype Consistency Learning (SPCL), which prompts unbiased structural representation by enforcing cross-sample consistency via prototype-level contrastive optimization, and Consensus-based Kolmogorov-Arnold Fusion (CKaF), which reduces morphology-specific bias by aggregating stable consensus and filtering sample-wise noise via KAN's adaptive B-spline nonlinearity. Extensive experiments on two public pancreas datasets demonstrate the effectiveness of SCKAN. Code is at https://github.com/rhodaliu17/SCKAN.","authors":["Yuqi Liu","Yufei Chen","Wei Fu","Xiaodong Yue","Shuo Li"],"published":"2026-05-26T13:53:45Z","updated":"2026-05-26T13:53:45Z","abstract_url":"https://arxiv.org/abs/2605.27032v1","html_url":"https://arxiv.org/html/2605.27032v1","pdf_url":"https://arxiv.org/pdf/2605.27032v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27024v1","title":"NeR-SC: Adapting Neural Video Representation to Screen Content","abstract":"Implicit neural representations have emerged as a promising paradigm for video compression, with recent methods achieving competitive performance on natural video. However, screen content video -- common in remote desktop, online education, and cloud gaming -- exhibits distinct statistics: sharp edges, limited color palettes, and strong temporal redundancy. Existing neural representation methods, designed for natural scenes, lack mechanisms to exploit these properties, leaving substantial room for improvement. In this paper, we propose NeR-SC, a neural representation framework tailored for screen content video. Building on the SNeRV backbone, NeR-SC introduces three screen-content-specific modules: (i) a learnable color palette that models the discrete color structure of screen content by restricting the low-frequency sub-band to a learned color set; (ii) a multi-gate dense fusion module that replaces sequential feature fusion with dense, attention-gated cross-stage interaction; and (iii) an embedding-level frame skip strategy that bypasses redundant decoder invocations for static frames, with zero training overhead. Experiments on DSCVC and VCD show that NeR-SC achieves 40.32~dB and 41.73~dB average PSNR, outperforming representative neural video representation methods and, at low bitrates, surpassing H.264 and H.265. The skip strategy enables real-time decoding with no loss in quality.","authors":["Ruohan Shi","Jiaoyan Zhao","Haogang Feng"],"published":"2026-05-26T13:43:50Z","updated":"2026-05-26T13:43:50Z","abstract_url":"https://arxiv.org/abs/2605.27024v1","html_url":"https://arxiv.org/html/2605.27024v1","pdf_url":"https://arxiv.org/pdf/2605.27024v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27020v1","title":"Black-box Membership Inference Attacks on the Pre-training Data of Image-generation Models","abstract":"The rapid advancement of diffusion-based image generation models has raised serious concerns regarding potential copyright and privacy infringements involving human-created data. Membership inference attacks (MIAs) have emerged as a promising tool for identifying unauthorized data usage during model training. Existing methods typically assess the ability of model to denoise perturbed suspect images as an indicator of membership status. However, the discriminative power of such features is highly dependent on the degree of model memorization and deteriorates significantly when applied to less exposed data (e.g., pre-training data). Although several methods attempt to enhance detection by leveraging internal model features, these features are generally inaccessible in mainstream closed-source image generation platforms, limiting their practicality. In this paper, we demonstrate that analyzing how a black-box diffusion model denoises a target image and corresponding perturbed textual instructions can reveal more distinctive membership cues. Based on this insight, we propose a black-box membership inference attack framework (named SD-MIA) that leverages a cross-modal data perturbation mechanism to detect pre-training data in diffusion models. We conduct extensive experiments on both a public benchmark dataset and a newly constructed dataset, each comprising pre-training membership and non-membership samples with identical distributions. Experimental results demonstrate that SD-MIA achieves superior performance compared to existing baselines, including those with the unfair advantage of accessing internal model features.","authors":["Tao Qi","Huili Wang","Yuanhong Huang","Wendan Wang","Lianchao Zhao","Jinrui Wang","Zichen Qin","Shangguang Wang","Yongfeng Huang"],"published":"2026-05-26T13:38:25Z","updated":"2026-05-26T13:38:25Z","abstract_url":"https://arxiv.org/abs/2605.27020v1","html_url":"https://arxiv.org/html/2605.27020v1","pdf_url":"https://arxiv.org/pdf/2605.27020v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27003v1","title":"Timestep-Aware SVDQuant-GPTQ for W4A4 Quantization of Wan2.2-I2V","abstract":"W4A4 quantization of large video diffusion Transformers offers substantial memory savings but is hindered by two main challenges: sparse large-magnitude activation outliers, and strongly timestep-dependent activation distributions across the multi-step denoising trajectory. These difficulties are compounded by Wan2.2-I2V's two-expert Mixture-of-Experts DiT design, whose high-noise and low-noise experts exhibit distinct quantization sensitivities that a single global calibration policy cannot capture. We propose a post-training quantization framework combining SVDQuant-based low-rank outlier compensation, GPTQ-based reconstruction-aware residual weight quantization, and timestep-bin-wise per-layer activation clipping-ratio search conducted independently for each expert. On the OpenS2V-Eval benchmark, our method reduces peak GPU memory by 59.3\\% relative to the BF16 baseline while incurring only a 0.9\\% drop in VBench average score and a 2.3\\% drop in Imaging Quality, demonstrating that expert- and timestep-aware calibration is essential for high-fidelity W4A4 inference on MoE video DiTs.","authors":["Junhao Wu","Dezhong Yao","Hai Jin"],"published":"2026-05-26T13:24:01Z","updated":"2026-05-26T13:24:01Z","abstract_url":"https://arxiv.org/abs/2605.27003v1","html_url":"https://arxiv.org/html/2605.27003v1","pdf_url":"https://arxiv.org/pdf/2605.27003v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26994v1","title":"ChartAct: A Benchmark for Dynamic Chart Understanding","abstract":"Charts are widely used to present complex data for analysis and decision making. Existing chart understanding benchmarks mainly focus on static charts, but real-world charts are often dynamic and interactive. Key information may only appear after actions such as hovering, clicking, zooming, or dragging. Dynamic chart understanding therefore requires models to identify visible content, choose proper interactions, and reason over changing chart states. To evaluate this ability, we propose ChartAct, an interactive benchmark for dynamic chart understanding. ChartAct collects and filters 673 dynamic charts from 8 real chart websites, covers 7 common chart types, and constructs 1,440 high-quality question-answer samples. Each sample is instantiated in two environments, Dynamic Chart and Dashboard Chart, to evaluate dynamic chart understanding under different contexts. Based on ChartAct, we systematically evaluate 11 advanced multimodal models and GUI agents. Experimental results show that existing models still have clear limitations in dynamic chart understanding. The strongest model, Claude-Opus-4.7, achieves an average success rate of 84.5\\%, while most models remain below 60\\%. We also conduct detailed failure attribution and case analysis. ChartAct provides a new benchmark for studying chart understanding in real interactive environments. Codes at https://github.com/wulin-wulin/OSWorld_Chart","authors":["Muye Huang","Wu Lin","Lingling Zhang","Hang Yan","Zhiyuan Wang","Yumeng Fu","Zesheng Yang","Jun Liu"],"published":"2026-05-26T13:15:21Z","updated":"2026-05-26T13:15:21Z","abstract_url":"https://arxiv.org/abs/2605.26994v1","html_url":"https://arxiv.org/html/2605.26994v1","pdf_url":"https://arxiv.org/pdf/2605.26994v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26992v1","title":"On the Robustness of Machine Unlearning for Vision-Language Models","abstract":"Vision-language models (VLMs) may memorize undesirable information from training data, motivating growing interest in machine unlearning. In this work, we present the first systematic survey and robustness analysis of VLM unlearning. We provide a comprehensive taxonomy and review of existing VLM unlearning methods, together with unified evaluations under multiple prompt settings. We then propose three attack paradigms to examine whether forgotten multimodal knowledge can be reactivated through contextual prompting or downstream retraining. Extensive experiments show that many existing methods remain vulnerable under these attacks, indicating that current approaches often hide rather than fully remove target knowledge. Our study provides new insights into the robustness and limitations of current VLM unlearning methods and highlights the need for more reliable multimodal unlearning strategies. Code is available at https://github.com/XMUDeepLIT/VLM-UnL-Attack.","authors":["Yujie Lin","Kaidi Jia","Jiayao Ma","Chengyi Yang","Jinsong Su"],"published":"2026-05-26T13:14:12Z","updated":"2026-05-26T13:14:12Z","abstract_url":"https://arxiv.org/abs/2605.26992v1","html_url":"https://arxiv.org/html/2605.26992v1","pdf_url":"https://arxiv.org/pdf/2605.26992v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26967v1","title":"CodecCap: High-Fidelity Codec-Inspired Residual Modeling for Dense Video Captioning","abstract":"Existing video captioning methods struggle to balance visual fidelity and redundancy: holistic captions are compact but lose fine-grained evidence, whereas segment-wise captions improve coverage but introduce heavy redundancy. We propose CodecCap, a codec-inspired framework for high-fidelity dense video captioning. Analogous to video codecs, CodecCap represents videos using keyframe and residual captions. Keyframe captions exhaustively encode stable visual context, while residual captions capture temporally only localized actions, motions and changes. This effectively preserves fine-grained visual evidence while reducing redundant descriptions. To quantify the fidelity of captions, we introduce VidCapQA, a caption-then-QA benchmark with 1,000 questions across 14 capability dimensions. Results on VidCapQA show that captions directly generated by strong VLMs still miss many visual details, highlighting caption representation as a critical bottleneck. Experiments show that CodecCap significantly surpasses direct captioning with the same underlying VLMs, suggesting keyframe-residual captioning a way for high-fidelity video-language supervision. We further use CodecCap to construct CodecVDC-100K, a large-scale dense captioning dataset with anchor, residual, scene-level, and video-level supervision.","authors":["Zihan Lin","Songhe Deng","Shuwei He","Danxiang Zhu","Dan Zhang","Yishu Lei","Xianlong Luo","Shikun Feng","Rui Liu"],"published":"2026-05-26T12:53:55Z","updated":"2026-05-26T12:53:55Z","abstract_url":"https://arxiv.org/abs/2605.26967v1","html_url":"https://arxiv.org/html/2605.26967v1","pdf_url":"https://arxiv.org/pdf/2605.26967v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26949v1","title":"DinoComplete: 3D Shape Completion with Distilled Semantic Priors and State Space Models","abstract":"3D shape completion from partial scans remains challenging for unseen categories and noisy real-world observations, where geometry alone is often insufficient for inferring missing structure. We present DinoComplete, a deterministic and efficient shape completion framework that augments geometric reconstruction with voxel-aligned semantic priors distilled from DINO features. First, we construct multi-view DINO feature volumes aligned with ShapeNet data and train a student network to predict dense semantic features directly from incomplete shapes. These predicted features capture global structure and part-aware semantic context while remaining aligned with the underlying geometry. We then integrate these distilled features into a completion network, where geometric and semantic voxel representations are fused through voxel state-space modeling. To enable efficient long-range reasoning without sacrificing resolution, we introduce a multi-scale voxel Mamba module that refines the fused features by combining full-grid and chunk-wise sequence modeling. Experiments on unseen ShapeNet categories and ScanNet objects show that DinoComplete achieves stronger completion quality than prior deterministic and generative based completion methods while using fewer parameters, requiring lower memory, and achieving faster inference. Our results demonstrate that distilling semantic priors from visual foundation models improves generalization and robustness in 3D shape completion.","authors":["Furkan Mert Algan","Eckehard Steinbach"],"published":"2026-05-26T12:40:52Z","updated":"2026-05-26T12:40:52Z","abstract_url":"https://arxiv.org/abs/2605.26949v1","html_url":"https://arxiv.org/html/2605.26949v1","pdf_url":"https://arxiv.org/pdf/2605.26949v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26944v1","title":"Object Pose and Shape Estimation for Grasping: Does it Work?","abstract":"The problem of object pose and shape estimation has seen key advancements lately. Encoder-decoder (e.g., SAM3D, LRM, CRISP) and diffusion-based models (e.g., InstantMesh, Zero123, SceneComplete) have shown category-agnostic shape encoding capacity and open-set generalizability. In this work, we ask the question: Are the object pose and shape estimation methods mature enough, such that when used with antipodal grasp sampling, can outperform the end-to-end grasp synthesis methods? We explore this question in detail by scoping our study to parallel jaw grippers, 7-DoF grasps, and single-view RGB(-D) image as input. We implement and compare a state-of-the-art, end-to-end grasp synthesis method and three modular methods, which first estimate the object pose and shape for all objects in the scene, and generate grasps using antipodal sampling. We observe that the modular methods outperform the end-to-end method in all our experiments. The modular methods are able to synthesize plenty of grasps, even for small objects, where the end-to-end methods fail. The effectiveness of the modular methods is contingent on the accuracy of the pose and shape estimation, and suffers partial degradation in cluttered scenes - a limitation of the existing pose and shape estimation methods. We also analyze the failure modes and run-times for the three modular methods, which use two different ways of object pose and shape estimation: one based on an encoder-decoder model, while another a diffusion model. Finally, we demonstrate that the single-view object pose and shape estimation methods can be augmented with vision-language models to yield language-conditioned grasps from just single-view RGB-D image as input. We notice comparable performance to the state-of-the-art LERF-TOGO baseline.","authors":["Pavan Karke","Kushal Shah","Gaurav Singh","Md Faizal Karim","K Madhava Krishna","Rajat Talak"],"published":"2026-05-26T12:32:50Z","updated":"2026-05-26T12:32:50Z","abstract_url":"https://arxiv.org/abs/2605.26944v1","html_url":"https://arxiv.org/html/2605.26944v1","pdf_url":"https://arxiv.org/pdf/2605.26944v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26933v1","title":"Leveraging Text-to-Image Diffusion Models for Unsupervised Visual Object Tracking","abstract":"Unsupervised visual object tracking is a challenging task that requires following arbitrary targets in videos without training on ground-truth annotations. Despite considerable progress, existing state-of-the-art unsupervised trackers often struggle in scenarios that demand fine-grained understanding of semantic and visual structural information within video frames. Text-to-image diffusion models are well known for their ability to generate images that accurately reflect the semantics and structures described in the input prompt, demonstrating a strong grasp of visual semantics and structures. Building on this capability, we approach the unsupervised tracking from a new perspective by exploiting the rich semantic knowledge encoded in pretrained text-to-image diffusion models. To adapt the diffusion models, which are originally developed for image generation, to the tracking task, we reinterpret the models as a bridge between text and image modalities. This connection is realized through the cross-attention mechanism: when both text and an image are input into the models, they highlight the regions of the image that are semantically aligned with the text in the cross-attention maps. We therefore learn a prompt that represents the tracking target and activates its corresponding region in the cross-attention map for each frame, which enables object tracking with the diffusion model. Specifically, our method Diff-Tracking is composed of two main components: an initial prompt learner and an online prompt updater. The initial prompt learner generates a prompt that captures the target object in the first frame, allowing the diffusion model to identify the target. The online prompt updater refines the prompt based on motion information, enabling consistent tracking across video frames. We evaluate our approach on six challenging tracking datasets demonstrate the effectiveness of our approach.","authors":["Zhengbo Zhang","Zhigang Tu","Junsong Yuan","De Wen Soh","Bo Du"],"published":"2026-05-26T12:26:56Z","updated":"2026-05-26T12:26:56Z","abstract_url":"https://arxiv.org/abs/2605.26933v1","html_url":"https://arxiv.org/html/2605.26933v1","pdf_url":"https://arxiv.org/pdf/2605.26933v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26921v1","title":"Revealing the core dimensions underlying representations in brains, behavior and AI","abstract":"The study of representations is widespread across fields, including neuroscience, psychology, and artificial intelligence. While representations are often studied and compared through similarities between stimuli, current methods provide only limited access to the dimensions that shape these representations and are often limited in interpretability. To overcome these challenges, here we introduce Similarity-Based Representation Factorization (SRF), a general computational method for recovering low-dimensional, non-negative, interpretable embeddings from similarity matrices derived from measured data. Across simulations and many neural, behavioral, and computational datasets, SRF recovers interpretable dimensions from diverse forms of representational data, even for very sparsely sampled, incomplete data. The dimensions derived from these datasets match those obtained by task-specific models, predict independent behavioral properties, improve exploratory analysis, and offer higher power for confirmatory hypothesis testing than comparing similarity matrices. Together, these results establish SRF as a general-purpose method with broad applications for uncovering, understanding, and leveraging the dimensions underlying representations.","authors":["Florian P. Mahner","Ka Chun Lam","Francisco Pereira","Martin N. Hebart"],"published":"2026-05-26T12:19:17Z","updated":"2026-05-26T12:19:17Z","abstract_url":"https://arxiv.org/abs/2605.26921v1","html_url":"https://arxiv.org/html/2605.26921v1","pdf_url":"https://arxiv.org/pdf/2605.26921v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26914v1","title":"I2PRef: Image-Driven Point Completion with Iterative Refinement","abstract":"We present an image-conditioned point cloud completion approach that treats images as the primary geometric source rather than a secondary guide. To this end, we introduce an Image-to-Point (I2P) module that can reconstruct complete point clouds directly from a single RGB image, with no need for 3D inputs. Additionally, we introduce a transformer-based Point-to-Point (P2P) refinement module that uses self- and cross-attention between point tokens and image features to iteratively refine the coarse I2P output. The I2P module enables the image encoder to learn rich geometric representations, while the P2P module progressively recovers fine-grained details. Unlike existing multimodal methods that rely on auxiliary losses or fusion modules, our explicit I2P task provides a strong, geometry-aware prior based on images alone. Extensive experiments on ShapeNet-ViPC demonstrate state-of-the-art completion performance with a 12.3% relative Chamfer Distance improvement over prior methods. Code is available at: https://github.com/AzharSindhi/I2PRef.git","authors":["Azhar Hussian","Marina Ritthaler","André Kaup","Vasileios Belagiannis"],"published":"2026-05-26T12:12:20Z","updated":"2026-05-26T12:12:20Z","abstract_url":"https://arxiv.org/abs/2605.26914v1","html_url":"https://arxiv.org/html/2605.26914v1","pdf_url":"https://arxiv.org/pdf/2605.26914v1.pdf","matched_keywords":["3d","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26884v1","title":"Small Object Detection in Industrial Recycling: A New Dataset and YOLO Performance Evaluation","abstract":"In this paper, we address the problem of detecting small, dense, and overlapping objects, a major challenge in computer vision. Our focus is on reviewing proposed methods based on deep learning supervised approaches. We provide a detailed comparison of these systems on a new dataset of more than 10k images and 120k instances, highlighting their performance, accuracy, and computational efficiency in the industrial recycling process use case. Through this comparative analysis, we identify the most reliable systems currently available and the specific challenges they are designed to tackle. Furthermore, we explore the benefits of data augmentation and synthetic images. Based on our analysis, we also propose potential future directions and innovative solutions that could enhance the effectiveness of small, dense and overlapped object detection systems. The scope of our investigations encompasses object detection, length measurement, and anomaly detection within the context of the recycling process. The anomaly detection strategy is robust against variations in image resolution and zoom levels, ensuring reliable performance in industrial applications. The repository of the proposed dataset, methods and evaluation codes can be found at: https://github.com/o-messai/SDOOD","authors":["Oussama Messai","Abbass Zein-Eddine","Abdelouahid Bentamou","Mickael Picq","Nicolas Duquesne","Stéphane Puydarrieux","Yann Gavet"],"published":"2026-05-26T11:47:31Z","updated":"2026-05-26T11:47:31Z","abstract_url":"https://arxiv.org/abs/2605.26884v1","html_url":"https://arxiv.org/html/2605.26884v1","pdf_url":"https://arxiv.org/pdf/2605.26884v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26879v1","title":"Natural Human Motion Recovery by Aligning High-Order Temporal Dynamics from Monocular Videos","abstract":"Human motion recovered from monocular videos often appears overly smooth or dynamically inconsistent, even when joint positions are numerically accurate. We observe that this limitation stems from the absence of reliable high-order temporal cues -- velocity and acceleration -- which are essential for reconstructing motion that exhibits realistic momentum, timing, and high-frequency detail. We introduce HTD-Refine, a post-processing framework that augments existing Human Motion Recovery (HMR) pipelines using explicitly estimated high-order temporal dynamics. At the core of our system is PVA-Net, a temporal transformer that infers per-joint 2D positions, 3D velocities, and 3D accelerations directly from a monocular video. These predicted dynamics serve as soft yet informative constraints in a global optimization procedure that refines world-space trajectories, significantly reducing jitter, suppressing over-smoothing, and restoring physically plausible motion. Extensive experiments on challenging in-the-wild benchmarks show that HTD-Refine consistently improves state-of-the-art HMR methods, yielding more accurate global trajectories and substantially more natural motion dynamics. Our results highlight the critical role of high-order temporal modeling in advancing monocular human motion recovery.","authors":["Dingkun Wei","Zehong Shen","Yan Xia","Georgios Pavlakos","Yujun Shen","Xiaowei Zhou"],"published":"2026-05-26T11:38:36Z","updated":"2026-05-26T11:38:36Z","abstract_url":"https://arxiv.org/abs/2605.26879v1","html_url":"https://arxiv.org/html/2605.26879v1","pdf_url":"https://arxiv.org/pdf/2605.26879v1.pdf","matched_keywords":["video","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26861v1","title":"REVERSE: Reinforcing Evidence Verification and Search for Agentic Image geo-localization","abstract":"Image geo-localization aims to determine where a photograph was taken, a task that often requires more than recognizing visible landmarks. Human experts typically solve it through an iterative workflow: they inspect informative regions, form location hypotheses, seek external evidence, and revise their judgments as new clues appear. Existing methods only partially capture this process: direct prediction methods bypass evidence acquisition altogether, while retrieval-augmented methods introduce external evidence but usually provide limited supervision on the intermediate decisions of where to search, how to query, and how to filter noisy results. We present REVERSE, a framework that reinforces the interplay between evidence search and verification to enable multi-turn agentic reasoning. REVERSE teaches three intermediate decisions: where to look, what to query, and what evidence to trust. To support this, we construct tool-grounded trajectories with annotated region selections, search observations, and geo-informative evidence labels, and introduce process rewards for visual grounding, query utility, and evidence discrimination. An offline search cache makes retrieval observations stable and reusable during reinforcement learning, enabling dense supervision over noisy search results. With a 4B model, REVERSE outperforms strong retrieval-augmented baselines and rivals substantially larger models on Im2GPS3k and YFCC4k. Code is available at https://github.com/yonglleee/REVERSE.","authors":["Yong Li","Furong Jia","Dacheng Yin","Kang Rong","Fengyun Rao","Jing Lyu","Fan Zhang"],"published":"2026-05-26T11:20:09Z","updated":"2026-05-26T11:20:09Z","abstract_url":"https://arxiv.org/abs/2605.26861v1","html_url":"https://arxiv.org/html/2605.26861v1","pdf_url":"https://arxiv.org/pdf/2605.26861v1.pdf","matched_keywords":["retrieval","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26831v1","title":"OSMa-Bench++: Toward Open-Ended Benchmarking of Semantic Mapping for Manipulation with Prompt-Generated Synthetic Scenes","abstract":"Semantic mapping methods are increasingly used as intermediate scene representations for downstream robotic reasoning and manipulation, yet their evaluation is still largely tied to fixed benchmark datasets with limited coverage of manipulation-relevant corner cases. In this work, we extend OSMa-Bench toward controllable benchmarking with prompt-generated synthetic indoor scenes. Our pipeline automatically generates scene descriptions, synthesizes corresponding environments with SceneSmith, and adapts the resulting assets into an OSMa-Bench-compatible simulation format. This adaptation requires a nontrivial intermediate layer, including semantic normalization, material and texture repair, shader fallback policies, floor handling, navigation setup, and controlled lighting configuration. A key advantage of the proposed setup is that the original scene-generation prompt is known in advance and can therefore serve as an auxiliary semantic specification of the intended scene. We use this property to extend the VQA component of OSMa-Bench with a prompt-grounded question category. The resulting framework supports targeted stress-testing of semantic scene representations under conditions such as clutter, small objects, partial occlusions, and lighting variation, and makes benchmarking more extensible and better aligned with downstream manipulation requirements. Our code is available at https://github.com/be2rlab/OSMa-Bench-v2.","authors":["Regina Kurkova","Maxim Popov","Sergey Kolyubin"],"published":"2026-05-26T10:51:36Z","updated":"2026-05-26T10:51:36Z","abstract_url":"https://arxiv.org/abs/2605.26831v1","html_url":"https://arxiv.org/html/2605.26831v1","pdf_url":"https://arxiv.org/pdf/2605.26831v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26774v1","title":"Cesarean Scar Defect Segmentation in Transvaginal Ultrasound Images: a Dataset and Benchmark","abstract":"Cesarean Scar Defect (CSD) is one of the most prevalent complications following cesarean delivery. Transvaginal ultrasonography is widely used for primary CSD screening. Accurate determination of CSD outline and dimensions is crucial for treatment. However, CSDs are frequently overlooked by sonographers due to small size and irregular morphology, suboptimal image quality, and limited clinical awareness in resource-constrained settings. Despite artificial intelligence advances in medical imaging, no public dataset exists for transvaginal ultrasound CSD segmentation. To address this gap, we present a comprehensive CSD dataset comprising 1,111 images and 16 videos, yielding 501 positive samples with confirmed CSD and precise pixel-level manual annotations. Annotations are performed following standardized clinical guidelines through collaboration between experienced sonographers and trained PhD students. This work provides high-quality benchmark resources for advancing medical image segmentation algorithms and promoting clinical innovation. Ultimately, improved CSD diagnosis and subsequent treatment strategies can enhance the quality of life in women of reproductive age, representing significant value for both medical research and clinical practice.","authors":["Yuan Tian","Yue Li","Wei Xia","Tianyu Xu","Jian Zhang","Liye Shi","Jing Liu","Yang Wang","Ming Liu","Qing Xu","Yixuan Zhang","Maggie M. He","Xiangjian He"],"published":"2026-05-26T09:45:19Z","updated":"2026-05-26T09:45:19Z","abstract_url":"https://arxiv.org/abs/2605.26774v1","html_url":"https://arxiv.org/html/2605.26774v1","pdf_url":"https://arxiv.org/pdf/2605.26774v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26761v1","title":"Once-For-All: A Train-Once and Select-Anytime Framework for Multimodal Instruction Tuning","abstract":"Multimodal instruction tuning is the de facto recipe for adapting vision language models (VLMs), yet instruction data are highly redundant, making data selection critical for training efficiency. Existing methods derive selection signals from a specific model or dataset, so whenever the target model or candidate pool changes, the criteria must be recomputed from scratch at substantial cost. To address this, we propose OFA, a data selection framework that trains a reusable selector once and applies it to any dataset or model without recomputation. OFA clusters multimodal instructions in a frozen CLIP space, derives pseudo labels from the cluster structure, and trains a lightweight selector for only a few epochs; samples on which this selector is least confident are selected as the most informative. Once trained, the frozen selector transfers directly across datasets and model scales. The selector is trained once on LLaVA-665K and applied both to LLaVA-665K itself and, without any retraining, to the unseen Vision-Flan-186K. Selecting only 15% of the data, OFA achieves 98.3% of full data performance across 10 downstream benchmarks; on the smaller Vision-Flan-186K, the transferred selector surpasses full data training by 10.6%, confirming that the learned signal generalizes to datasets never seen during selector training. The same selected subsets benefit VLMs at both Qwen2.5-VL-3B and LLaVA-v1.5-7B without per model recomputation, decoupling selection from the target model. These results demonstrate that a single, transferable selector provides an effective and reusable solution for efficient multimodal instruction tuning.","authors":["Mingkang Dong","Hongyi Cai","Xiwen Lei","Jie Li","Tao Zhang","Muxin Pu"],"published":"2026-05-26T09:31:20Z","updated":"2026-05-26T09:31:20Z","abstract_url":"https://arxiv.org/abs/2605.26761v1","html_url":"https://arxiv.org/html/2605.26761v1","pdf_url":"https://arxiv.org/pdf/2605.26761v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26744v1","title":"Self-Intersection-Aware 3D Human Motion Generation Using an Efficient Human Sphere Proxy","abstract":"Human motion generation has made tremendous progress in recent years, with state-of-the-art approaches surpassing ground truth data in leading evaluation benchmarks. However, visual inspection of the generated motions paints a different picture. Even state-of-the-art approaches generate motions frequently containing self-intersections, i.e., body parts interpenetrating, which are strong artifacts, severely limiting the perceived motion quality. We introduce a novel loss, which explicitly penalizes self-intersections, to the training of human motion generation methods. We base our loss on a sphere proxy of human geometry, which allows us to calculate a self-intersection loss 98% faster and uses 83% less memory than comparable methods based on triangular meshes. The loss is agnostic to the specific approach, and we add it to the training of the recent human motion generation methods human motion diffusion model (MDM) and MoMask. Our extensive experiments show a reduction of self-intersections in generated motions of up to 49% while improving other evaluation metrics. The code is available at https://github.com/boschresearch/humansphereproxy .","authors":["Pascal Herrmann","Maarten Bieshaar","Dennis Mack","Robert Herzog","Juergen Gall"],"published":"2026-05-26T09:17:46Z","updated":"2026-05-26T09:17:46Z","abstract_url":"https://arxiv.org/abs/2605.26744v1","html_url":"https://arxiv.org/html/2605.26744v1","pdf_url":"https://arxiv.org/pdf/2605.26744v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26734v1","title":"CIRCLED: A Multi-turn CIR Dataset with Consistent Dialogues across Domains","abstract":"Existing Multi-Turn Composed Image Retrieval (MTCIR) datasets lack dialogue-history consistency and are restricted to the fashion domain. To address these limitations, we construct CIRCLED by extending FashionIQ, CIRR, and CIRCO. In CIRCLED, the query at each turn progressively approaches the target image. Data are generated via a CIReVL-based retrieval pipeline and curated with multiple filters on retrieval success, turn length, consistency, and information redundancy to ensure quality. In total, we collect 22,608 multi-turn sessions across nine subsets, substantially exceeding Multi-turn FashionIQ (11,505 sessions) in both scale and generality. We further apply multiple baseline methods and quantitatively assess retrieval accuracy on CIRCLED. Our work provides a practical, high-quality benchmark to facilitate future research on multi-turn CIR. The dataset and code are publicly available at https://huggingface.co/datasets/tk1441/CIRCLED and https://github.com/mti-lab/circled.","authors":["Tomohisa Takeda","Yu-Chieh Lin","Yuji Nozawa","Youyang Ng","Osamu Torii","Yusuke Matsui"],"published":"2026-05-26T09:11:15Z","updated":"2026-05-26T09:11:15Z","abstract_url":"https://arxiv.org/abs/2605.26734v1","html_url":"https://arxiv.org/html/2605.26734v1","pdf_url":"https://arxiv.org/pdf/2605.26734v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26725v1","title":"Joint 2D-3D Segmentation and Association in Street-level Imaging","abstract":"Accurate interpretation of street-level imagery is essential for large-scale urban mapping and the creation of Spatial Digital Twin (SDT) environments. This work presents a unified framework for joint 2D-3D segmentation and association that integrates visual semantics with multi-view geometric reasoning. Unlike conventional approaches that rely heavily on sequential frames for temporal tracking, our method leverages zero-shot detection and segmentation together with structure-from-motion reconstruction to establish stable cross-view correspondences. A 3D-driven association mechanism replaces traditional 2D multi-object tracking, using geometric consistency to guide identity preservation across wide-baseline viewpoints and varying imaging conditions. By combining 2D texture cues with global 3D context, the proposed pipeline is well-suited for scalable street-level processing and can be used for a variety of object types. Experiments demonstrate substantially improved coverage of ground-truth sequences and more robust identity retention compared to state-of-the-art 2D-only tracking methods, achieving a 22% performance gain in challenging urban scenarios.","authors":["Amir Melnikov","Masayuki Tanaka","Yusuke Monno","Masatoshi Okutomi"],"published":"2026-05-26T09:04:51Z","updated":"2026-05-26T09:04:51Z","abstract_url":"https://arxiv.org/abs/2605.26725v1","html_url":"https://arxiv.org/html/2605.26725v1","pdf_url":"https://arxiv.org/pdf/2605.26725v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26702v1","title":"Rotation-Invariant Spherical Watermarking via Third-Order SO(3) Representation Coupling","abstract":"Reliable watermarking of panoramic imagery is fundamentally challenged by arbitrary 3D rotations. As panoramas are defined on the sphere, they naturally transform under the action of $SO(3)$, rendering conventional planar representations and augmentation-based robustness strategies inadequate and devoid of theoretical guarantees. To address this, we formulate panoramas as spherical signals and leverage $SO(3)$ representation theory to derive provably rotation-invariant descriptors. While spherical harmonic coefficients transform equivariantly under rotations, the natural invariant constructions are typically limited to zeroth-order statistics which eliminate directional information and severely constrain embedding capacity. In this work, we introduce a principled third-order invariant construction by coupling higher-order $SO(3)$ irreducible representations via tensor products and projecting onto the trivial representation. This yields a spherical invariant bispectrum that preserves phase information while remaining strictly rotation-invariant. Leveraging this property, we embed watermarks into higher-order spherical harmonic coefficients and recover them from invariant bispectral scalars, enabling reliable extraction under arbitrary 3D rotations. We provide a theoretical proof of $SO(3)$ invariance for it and demonstrate experimentally its near-perfect robustness to continuous rotations while maintaining high visual fidelity.","authors":["Pengzhen Chen","Yanwei Liu","Xiaoyan Gu","Antonios Argyriou","Wu Liu","Weiping Wang"],"published":"2026-05-26T08:43:40Z","updated":"2026-05-26T08:43:40Z","abstract_url":"https://arxiv.org/abs/2605.26702v1","html_url":"https://arxiv.org/html/2605.26702v1","pdf_url":"https://arxiv.org/pdf/2605.26702v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26689v1","title":"PinPoint: Prompting with Informative Interior Points","abstract":"Modern referring image segmentation pipelines couple a vision-language model (VLM) for grounding with a promptable segmenter such as the Segment Anything Model (SAM) for mask generation. Prior training-free instances of this recipe consistently trail fine-tuned and reinforcement-learning (RL)-tuned specialists, and it has been unclear whether the gap comes from the VLM's grounding, SAM's capacity, or the prompt. We show that the gap is dominated by prompt ambiguity: a VLM-proposed bounding box (bbox) leaves SAM to guess which pixels inside the bbox belong to the object the expression denotes. Interior points are the natural disambiguator, but where they fall matters; prior work relies on naively sampled points that land on boundaries, distractors, and background clutter, and can even hurt performance compared to the bbox alone. Supervised and RL-tuned methods close this gap by training a VLM to predict better points; we show that this training is unnecessary. At a matched budget of five interior points, replacing naive sampling with stable, informative point selection improves cumulative Intersection-over-Union (cIoU) by 12-18 points across RefCOCO/+/g, with every model fixed. We turn this observation into PinPoint, a deterministic, training-free point selector that fuses four visual cues into a consensus map, selects compact, spatially diverse points away from boundaries, and uses the frozen VLM to label each point. Without any task-specific training, PinPoint matches supervised and RL-tuned specialists on the same stack while issuing only two VLM calls per query.","authors":["Pouya Sadeghi","Shawn He","Pedro Pablo Guerrero Vela","C. Thomas","Alex Wong","Sirisha Rambhatla"],"published":"2026-05-26T08:28:54Z","updated":"2026-05-26T08:28:54Z","abstract_url":"https://arxiv.org/abs/2605.26689v1","html_url":"https://arxiv.org/html/2605.26689v1","pdf_url":"https://arxiv.org/pdf/2605.26689v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26682v1","title":"SteelDS: A High-Resolution Video Dataset of E40 Steel Scrap for Object Detection and Instance Segmentation","abstract":"This dataset provides high-resolution, annotated video sequences of shredded E40-grade steel and copper scrap on a conveyor belt. Captured in a controlled laboratory environment, the data reflects the industrial post-magnetic sorting stage, where manual intervention is typically required to remove copper contaminants. The dataset comprises 24,297 labeled frames across five subsets, featuring 396 steel and 101 copper objects categorized by size. It supports the development of machine learning models for material classification, object detection, and instance segmentation. Variations in object spacing and density are included to simulate realistic industrial sorting conditions. Ground truth annotations include pixel-wise segmentation masks and material classes. This dataset serves as a benchmark for evaluating automated sorting algorithms aiming to identify copper impurities within complex, heterogeneous steel scrap streams.","authors":["Melanie Neubauer","Christian Rauch","Gerald Koinig","Alexia Tischberger-Aldrian","Roland Pomberger","Elmar Rueckert"],"published":"2026-05-26T08:20:12Z","updated":"2026-05-26T08:20:12Z","abstract_url":"https://arxiv.org/abs/2605.26682v1","html_url":"https://arxiv.org/html/2605.26682v1","pdf_url":"https://arxiv.org/pdf/2605.26682v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26680v1","title":"DynFrame: Adaptive Reasoning-Driven Multimodal Framework with Dynamic Frame Augmentation for Complex Video Understanding","abstract":"Recent video multimodal large language models (MLLMs) increasingly couple step-by-step reasoning with on-demand visual evidence retrieval, allowing models to revisit relevant video segments during inference. However, two structural gaps remain in existing thinking-with-video systems. (i) Sampling density is not a learnable decision: existing methods may let the model decide where to look, but the per-window frame rate is largely fixed. As a result, fine-grained evidence is often recovered through repeated retrieval calls, which increases inference context length and training difficulty. (ii) Retrieval and answer generation are usually optimized with a single trajectory-level advantage, so the \"where to look\" tokens and the \"how to answer\" tokens receive the same credit even when one is correct and the other is not. To address these gaps, we present DynFrame, a framework that emits the temporal window and the sampling density as native tokens within a single autoregressive pass. This learnable span-density retrieval enables acquiring multi-granularity evidence with a single retrieval step. Based on the above tokenized retrieval interface, we further introduce Segment-Decoupled GRPO (SD-GRPO), which splits each rollout at the retrieval boundary and assigns role-specific token-level advantages, separately crediting the sampling decision and the answer. Trained on the curated DM-CoT-74k and DM-RL-45k, DynFrame-4B is competitive with strong 7B-8B baselines across six benchmarks (NExT-GQA, Charades-STA, ActivityNet-MR, Video-MME, MLVU, LVBench), and DynFrame-8B sets new state-of-the-art on most metrics. Code is available at https://github.com/zhangguanghao523/DynFrame.","authors":["Peng Zhang","Guanghao Zhang","Wanggui He","Longxiang Zhang","Mushui Liu","Yan Xia","Zhenhao Peng","Weilong Dai","Jinlong Liu","Haobing Tang","Le Zhang","Hao Jiang","Pipei Huang"],"published":"2026-05-26T08:16:16Z","updated":"2026-05-26T08:16:16Z","abstract_url":"https://arxiv.org/abs/2605.26680v1","html_url":"https://arxiv.org/html/2605.26680v1","pdf_url":"https://arxiv.org/pdf/2605.26680v1.pdf","matched_keywords":["video","retrieval","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26656v1","title":"DV-SFT: Direct Vision Supervision for Fine-Grained Visual Understanding","abstract":"Multimodal large language models are typically trained end-to-end to predict ground-truth answers, yet supervision signals are applied exclusively to text tokens. Visual tokens, the core carriers of visual information, are optimized only implicitly as part of the context, leading to coarse-grained visual understanding. Prior works attempt to supervise visual inputs but inevitably rely on auxiliary components such as additional decoders or forward passes, because visual tokens lack readily interpretable labels. This limits their practical applicability. In this work, we propose \\textbf{D}irect \\textbf{V}ision \\textbf{S}upervised \\textbf{F}ine-\\textbf{T}uning (DV-SFT), which constructs explicit, token-level supervision for visual tokens and trains them through the same next-token prediction objective used for text. Specifically, we exploit the direct vision--text correspondence in OCR-related scenarios and automatically label each visual token with the word in its corresponding image patch. DV-SFT treats the MLLM as a black box, requiring no architectural modifications or additional forward passes. Extensive experiments demonstrate the superiority of direct vision supervision. DV-SFT consistently outperforms standard SFT across three in-domain and four out-of-domain benchmarks. Further analyses show that vision supervision effectively enhances fine-grained visual understanding and achieves higher multimodal alignment efficiency.","authors":["Jianfei Zhao","Feng Zhang","Xin Sun","Chong Feng","Bing Wang","Zhixing Tan"],"published":"2026-05-26T07:41:48Z","updated":"2026-05-26T07:41:48Z","abstract_url":"https://arxiv.org/abs/2605.26656v1","html_url":"https://arxiv.org/html/2605.26656v1","pdf_url":"https://arxiv.org/pdf/2605.26656v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26642v1","title":"Adaptation-Free Heterogeneous Collaborative Perception with Unseen Agent Configurations","abstract":"Collaborative perception improves 3D object detection by enabling agents to share complementary observations, but most existing methods assume fixed or known collaborator encoder configurations, limiting deployment in practice. In this work, we consider an open-world setting in which auxiliary agents with unseen configurations may appear after deployment, such as different LiDAR beam counts or encoder architectures. To address this challenge, we propose ALF, a collaborative perception framework that enables zero-adaptation collaboration with unseen agent configurations by lifting lightweight box-level messages into ego-compatible auxiliary features. ALF converts auxiliary box-level messages into pseudo-BEV maps and synthesizes ego-compatible latent features by combining object-centric cues with scene context from the ego feature. On V2X-Real, under a zero-shot evaluation across 64 case studies, ALF outperforms the strongest prior baseline by 35.91% in relative mAP@0.7 while requiring only 120 bytes per agent per frame (approximately 9.6 Kbps bandwidth at 10 Hz).","authors":["Hyunchul Bae","Heejin Ahn"],"published":"2026-05-26T07:26:34Z","updated":"2026-05-26T07:26:34Z","abstract_url":"https://arxiv.org/abs/2605.26642v1","html_url":"https://arxiv.org/html/2605.26642v1","pdf_url":"https://arxiv.org/pdf/2605.26642v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26641v1","title":"OmniRetriever: Any-to-Any Audio-Video-Text Retrieval via Fusion-as-Teacher Distillation","abstract":"Unified multimodal embedding spaces have become the standard interface for cross-modal retrieval and multimodal RAG, and recent audio-video-text (AVT) encoders extend this setting to three modalities. Such encoders can produce a joint (T,V,A) embedding whenever all three modalities are available, but standard pairwise InfoNCE objectives leave this signal unused during training. We close this gap with fusion-as-teacher distillation, which treats a stop-gradient copy of the fused embedding as a teacher signal for the single-modal embeddings, paired with a Tuple-InfoNCE term that supervises the fused embedding directly. We instantiate this objective as OmniRetriever-7B. Across six zero-shot retrieval benchmarks, OmniRetriever-7B surpasses the closed-source Gemini Embedding 2 by 13.3-18.0 R@1 on Clotho and SoundDescs, and reaches the contemporary zero-shot specialist band of open video-text encoders on MSR-VTT and MSVD. To stress-test joint representations, we further release OmniRetriever-Bench, a 12-direction AVT retrieval benchmark totaling 3782 triples; on it OmniRetriever-7B attains AVG-all 34.84, improving over Gemini Embedding 2 by 1.72 and over the best prior open-source AVT method by 8.03.","authors":["Yunze Liu","Chi-Hao Wu","Enmin Zhou","Junxiao Shen"],"published":"2026-05-26T07:26:23Z","updated":"2026-05-26T07:26:23Z","abstract_url":"https://arxiv.org/abs/2605.26641v1","html_url":"https://arxiv.org/html/2605.26641v1","pdf_url":"https://arxiv.org/pdf/2605.26641v1.pdf","matched_keywords":["video","retrieval","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26630v1","title":"Attenuation-Resilient Alternating Optimization for Laparoscopic Liver Landmark Detection","abstract":"Liver surface landmark detection is a fundamental prerequisite for anatomical guidance in laparoscopic liver surgery. However, it remains unreliable in practice due to two pervasive challenges: illumination attenuation in underexposed regions and the structural mismatch between pixel-wise localization and continuous curvilinear geometry. To address these limitations, we propose A2ONet, an attenuation-resilient alternating optimization network for robust liver landmark detection. To mitigate illumination attenuation, A2ONet embraces an illumination field compensation (IFC) block that adaptively enhances dark regions while preserving structural consistency. Meanwhile, we introduce a lightweight frequency-orientation selective filter (FOSF) to suppress repetitive texture interference and preserve salient curvilinear cues. Building upon these resilient representations, we design an alternating seg-curve optimization (ASCO) decoder that iteratively couples dense segmentation with explicit curve modeling, enabling mutual guidance to optimize both structural continuity and endpoint localization. Extensive evaluations on L3D-2K, L3D, and P2ILF demonstrate consistent improvements over competitive methods, establishing a more reliable foundation for intraoperative anatomy guidance. Our code will be available at https://github.com/hyperiondk115/A2ONet.","authors":["Lanqing Liu","Ruize Cui","Jialun Pei","Diandian Guo","Tiffany Y. So","Pheng-Ann Heng","Jing Qin"],"published":"2026-05-26T07:06:10Z","updated":"2026-05-26T07:06:10Z","abstract_url":"https://arxiv.org/abs/2605.26630v1","html_url":"https://arxiv.org/html/2605.26630v1","pdf_url":"https://arxiv.org/pdf/2605.26630v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26629v1","title":"DelowlightSplat: Feed-Forward Gaussian Splatting for Lowlight 3D Scene Reconstruction","abstract":"Novel-view synthesis and 3D reconstruction from sparse posed images are central to robotics and AR/VR. Yet, feed-forward 3D Gaussian reconstruction fails under lowlight due to noise, color shifts, and unreliable correspondence. We propose DelowlightSplat, a lowlight-aware feed-forward Gaussian splatting framework for clean novel-view rendering. We build a controllable multi-view lowlight benchmark by degrading only context views while keeping target views clean. We introduce a lightweight Lowlight Adapter for residual enhancement to improve matchability, and couple it with cost-volume-based multi-view inference to directly predict clean 3D Gaussians. Experiments show that DelowlightSplat significantly outperforms previous feed-forward method and two-stage pipeline under lowlight conditions.","authors":["Fuzhen Jiang","Zengtian Xie","Zhuoran Li"],"published":"2026-05-26T07:05:10Z","updated":"2026-05-26T07:05:10Z","abstract_url":"https://arxiv.org/abs/2605.26629v1","html_url":"https://arxiv.org/html/2605.26629v1","pdf_url":"https://arxiv.org/pdf/2605.26629v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26624v1","title":"MSCGC-KAN: Multi-scale Causal Graph Convolution and Kolmogorov-Arnold Feature Mapping for EEG Emotion Recognition","abstract":"Electroencephalogram (EEG)-based emotion recognition is an important affective computing task, and recent EEG foundation models provide useful generic representations for downstream adaptation. However, under the fine-tuning setting, three limitations remain prominent: insufficient modeling of multi-scale emotional dynamics, inadequate exploitation of inter-channel functional connectivity, and the limited expressive power of simple linear classification heads. To address these issues, this paper proposes a new EEG emotion recognition method, termed MSCGC-KAN, which introduces a structured task head composed of multi-scale causal graph convolution and Kolmogorov--Arnold feature mapping. Built on a pre-trained CBraMod backbone, MSCGC-KAN enhances downstream adaptation by jointly strengthening multi-scale temporal modeling, learnable inter-channel connectivity modeling, and nonlinear discriminative mapping within a compact task-specific head. This design preserves the representation advantage of the foundation model while making the classifier more sensitive to emotion-related spatiotemporal patterns. Extensive experiments are conducted on the public FACED and SEED-VII datasets. The proposed method achieves a balanced accuracy of 60.66\\%, a Cohen's Kappa of 0.5525, and a weighted F1-score of 60.40\\% on FACED, and obtains 33.27\\%, 0.2223, and 33.64\\%, respectively, on SEED-VII. Compared with the CBraMod+Linear baseline, the balanced accuracy is improved by 5.91 and 2.03 percentage points on the two datasets, respectively. These results indicate that structured task-head design is an effective way to improve EEG emotion recognition when fine-tuning pre-trained EEG models.","authors":["Haoliang Gong","Qingshan She","Jiale Xua","Yunyan Gao","Xugang Xi"],"published":"2026-05-26T07:02:13Z","updated":"2026-05-26T07:02:13Z","abstract_url":"https://arxiv.org/abs/2605.26624v1","html_url":"https://arxiv.org/html/2605.26624v1","pdf_url":"https://arxiv.org/pdf/2605.26624v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26621v1","title":"MedVol-R1: Reward-Driven Evidence Grounding for Volumetric Reasoning Segmentation","abstract":"Volumetric Reasoning Segmentation (VRS) aims to segment a target region in a 3D medical scan from a free-form clinical query, where the referent is often implicit and requires both medical knowledge and volume-grounded reasoning. Existing methods typically rely on specialized segmentation tokens to connect language with mask decoding, but this coupling collapses the decision process into opaque latent representations, limiting interpretability and generalization to diverse narrative expressions. In this paper, we present MedVol-R1, a reinforcement learning-based framework for VRS that explicitly decouples evidence grounding from volumetric delineation: the LVLM grounds clinical reasoning to a verifiable 2D evidence anchor (key axial slice and 2D bounding boxes), which is then propagated into a coherent 3D mask by a frozen MedSAM2 module. We train MedVol-R1 with cold-start supervised fine-tuning followed by GRPO, guided by a multi-component reward that encourages informative evidence selection, accurate 2D spatial grounding, and cross-slice volumetric coherence, without requiring costly chain-of-thought annotations. Experiments on CT-ORG, AbdomenCT-1K, and KiTS23 from the M3D-Seg benchmark demonstrate that MedVol-R1 consistently outperforms strong baselines and achieves state-of-the-art performance, with reinforcement learning providing clear gains over pure supervised fine-tuning.","authors":["Zichun Wang","Hairong Shi","Bingzheng Wei","Yan Xu","Zihua Wang"],"published":"2026-05-26T06:59:19Z","updated":"2026-05-26T06:59:19Z","abstract_url":"https://arxiv.org/abs/2605.26621v1","html_url":"https://arxiv.org/html/2605.26621v1","pdf_url":"https://arxiv.org/pdf/2605.26621v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26616v1","title":"Gaussian-Voxel Duet: A Dual-Scaffolding Hybrid Representation for Fast and Accurate Monocular Surface Reconstruction","abstract":"While 3D Gaussian Splatting has achieved remarkable success in photorealistic novel view synthesis, its pursuit of fast and high-fidelity 3D reconstruction has long been constrained by a trade-off between geometric accuracy and optimization efficiency. Methods specialized in image rendering converge quickly at the cost of imperfect geometry caused by superfluous primitives overfitting training views, while methods integrating neural signed-distance field (SDF) for better geometry incur prohibitive training costs. In this paper, we attempt to strike a better trade-off by tethering scaffold-anchored Gaussians to a jointly optimized sparse voxel scaffold. This hybrid Gaussian-Voxel representation explicitly confines anchored Gaussians to a narrow band around surfaces defined by voxelized SDFs, which effectively improves representation efficiency and condenses floating Gaussians without sacrificing geometry quality. An implicit surface tethering loss further pulls individual Gaussian primitives closer to SDF-induced surfaces in a mutually regularized manner for improved reconstruction accuracy. Extensive experiments on diverse real-world indoor scenes from ScanNet++, ScanNetv2, and DeepBlending datasets demonstrate that our method achieves state-of-the-art surface reconstruction quality as well as superior novel view synthesis against leading baselines, while maintaining fast training convergence and real-time rendering. Code will be available at https://github.com/duzh11/VoxelGS.","authors":["Zhenhua Du","Zhen Tan","Haoyu Zhang","Dewen Hu","Shuaifeng Zhi","Peidong Liu"],"published":"2026-05-26T06:53:47Z","updated":"2026-05-26T06:53:47Z","abstract_url":"https://arxiv.org/abs/2605.26616v1","html_url":"https://arxiv.org/html/2605.26616v1","pdf_url":"https://arxiv.org/pdf/2605.26616v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26601v1","title":"FTibSuite: A Comprehensive Resource Suite for Tibetan Vision-Language Modeling","abstract":"Vision-language models have progressed rapidly, but Tibetan remains a severely underserved low-resource language due to the lack of reproducible training and evaluation infrastructure. To fill this gap, we introduce FTibSuite, a comprehensive resource suite for Tibetan vision-language research, consisting of FTibData (human-verified multimodal training corpora spanning continual pretraining, image-text alignment, and instruction tuning data), FTibBench (Tibetan adaptations of five mainstream multimodal benchmarks with a hierarchical quality-control workflow to reduce translation noise), and FTibVLM, a reproducible baseline built on Qwen3-VL-8B-Instruct via a three-stage adaptation pipeline. Experiments on FTibBench show FTibVLM delivers consistent performance gains across all tasks, such as improving MMBench accuracy from 42.97 to 67.78 and POPE-random accuracy from 47.53 to 80.56, while retaining the backbone's original Chinese capabilities with minimal degradation, providing the first standardized foundation for Tibetan multimodal research.","authors":["Guixian Xu","Yide Liang","Zeli Su","Xuexian Song","Ziyin Zhang","Yushuang Dong","Ting Zhang","Xu Han"],"published":"2026-05-26T06:36:27Z","updated":"2026-05-26T06:36:27Z","abstract_url":"https://arxiv.org/abs/2605.26601v1","html_url":"https://arxiv.org/html/2605.26601v1","pdf_url":"https://arxiv.org/pdf/2605.26601v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26584v1","title":"O-MARC: Omni Memory-Augmented Compression Distillation for Efficient Video Understanding","abstract":"Omnimodal large language models enable unified audio video understanding, but long joint token sequences make inference costly, and existing benchmarks do not fully isolate audio visual association in noisy user generated videos. We introduce UGC-AVQA, a public UGC benchmark with 1,000 videos and 4,816 QA pairs, where an audio removal test ensures that benchmark questions require both acoustic and visual evidence. To reduce inference cost, we propose OMAC, a training free plug in compression method that preserves salient visual memory and temporally grounded audio anchors. To further make compact models robust to compressed inputs, we introduce O-MARC, a compression distillation framework for learning with memory compressed multimodal contexts. On Qwen2.5-Omni-3B, O-MARC improves the average score across four benchmarks to 45.8, outperforming full token inference at 44.1 and OmniZip at 41.0. OMAC also keeps inference efficient, reducing latency by 34.6\\% (1.53$\\times$ speedup) and memory by 34.7\\% compared with full token inference.","authors":["Peiran Wu","Yunze Liu","Chi-Hao Wu","Chen Chen","Junxiao Shen"],"published":"2026-05-26T06:07:11Z","updated":"2026-05-26T06:07:11Z","abstract_url":"https://arxiv.org/abs/2605.26584v1","html_url":"https://arxiv.org/html/2605.26584v1","pdf_url":"https://arxiv.org/pdf/2605.26584v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26576v1","title":"TrackRef3D: Multi-View Consistent Track-then-Label for Open-World Referring Segmentation in 3D Gaussian Splatting","abstract":"Referring 3D Gaussian Splatting (R3DGS), which utilizes natural language for 3D object segmentation, has emerged as a crucial capability for embodied AI. However, existing methods typically rely on expensive per-scene manual annotation and per-view pseudo mask generation, which suffer from multi-view inconsistency and poor generalization to varying query specificities. To address this, we present TrackRef3D, a fully automatic pipeline that achieves open-world referring segmentation in 3D Gaussian Splatting (3DGS) without manual annotation by introducing a multi-view consistent track-then-label paradigm that fundamentally decouples object discovery from semantic grounding. Specifically, we propose a Trajectory-Aware Semantic Consensus Module (TSCM) which aggregates cross-view predictions via synonymous clustering and trajectory-aware voting to establish a canonical semantic identity, thereby ensuring multi-view consistency. Furthermore, we employ a visibility-aware description generation strategy to mitigate ambiguity and propose a Hybrid Training Strategy (HTS) that jointly optimizes coarse category semantics and fine-grained referential cues to ensure robustness under varying query specificities using a multi-positive contrastive objective. Extensive experiments on benchmarks demonstrate that TrackRef3D achieves state-of-the-art performance.","authors":["Yuyang Tan","Renhe Zhang","Hang Zhang","Ao Li","Xin Tan"],"published":"2026-05-26T05:49:12Z","updated":"2026-05-26T05:49:12Z","abstract_url":"https://arxiv.org/abs/2605.26576v1","html_url":"https://arxiv.org/html/2605.26576v1","pdf_url":"https://arxiv.org/pdf/2605.26576v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26538v1","title":"Scheduled Style Injection: Expanding the Style-Content Pareto Frontier in Training-Free Diffusion-based Style Transfer","abstract":"Style transfer with pre-trained diffusion models has advanced rapidly, but a core question remains underexplored: where in the model should style injection be strongest? StyleID, the leading training-free method, uses a single global parameter (gamma) uniformly across all layers and timesteps, which forces a fixed tradeoff between style quality and content preservation. We show this tradeoff is unnecessarily rigid. We systematically explore four dimensions of control: varying style injection strength across decoder layers, across denoising timesteps, and scheduling ControlNet geometric conditioning along both axes. The pattern is consistent everywhere: decreasing schedules, with stronger structural signal injection in shallower layers and earlier timesteps, reliably outperform the reverse. Beyond direction, schedule shape matters: cosine and square-root timestep schedules outperform linear. Most importantly, we find that gamma scheduling and ControlNet conditioning are nearly independent. The resulting combined configurations expand the Pareto frontier, offering superior tradeoffs between style fidelity and content preservation compared to any single baseline setting. Our best balanced configuration achieves ArtFID of 27.036 versus StyleID's 28.801 - a 6.1% relative improvement, with consistent gains across the full style-content tradeoff frontier. Results are validated across 35 configurations totaling over 28,000 stylized images using four complementary metrics. These findings generalize across SD backbones with identical rank ordering. All modifications are training-free, parameter-free, and require only a few lines of scheduling code; code is available at https://github.com/ameyskulkarni/scheduled_style_injection.","authors":["Amey Sunil Kulkarni"],"published":"2026-05-26T04:39:40Z","updated":"2026-05-26T04:39:40Z","abstract_url":"https://arxiv.org/abs/2605.26538v1","html_url":"https://arxiv.org/html/2605.26538v1","pdf_url":"https://arxiv.org/pdf/2605.26538v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26535v1","title":"Recursive Flow Matching","abstract":"Generative models have emerged as a powerful paradigm for solving physics systems and modeling complex spatiotemporal dynamics. However, achieving high physical accuracy without incurring high computational cost remains a fundamental challenge, as existing approaches face a critical speed-fidelity trade-off. In this work, we introduce Recursive Flow Matching (RecFM), a generative framework for forecasting complex spatiotemporal dynamics. RecFM enforces self-consistency to align trajectories across discretization scales, reducing discretization errors and improving performance across metrics for physics-based tasks. To our knowledge, this is the first method to achieve high-fidelity one- and few-step (2-4 step) dynamic generation for scientific systems with performance comparable to state-of-the-art multi-step solvers. Across challenging scientific benchmarks, RecFM achieves up to a 20$\\times$ speedup over leading diffusion-based emulators while improving predictive accuracy. Furthermore, RecFM reduces mean squared error by over 15% compared to vanilla flow matching, offering a scalable and efficient solution for real-time scientific emulation.","authors":["Jiahe Huang","Sihan Xu","Sharvaree Vadgama","Rose Yu"],"published":"2026-05-26T04:32:01Z","updated":"2026-05-26T04:32:01Z","abstract_url":"https://arxiv.org/abs/2605.26535v1","html_url":"https://arxiv.org/html/2605.26535v1","pdf_url":"https://arxiv.org/pdf/2605.26535v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26533v1","title":"A Hybrid Vision-Language Architecture for Automated Defect Reasoning and Report Generation in Industrial Inspection","abstract":"Automated industrial inspection requires both precise defect localization and structured maintenance report generation; in current practice these tasks are handled separately, with linguistic interpretation left to human experts. This paper describes a decoupled, edge-deployable pipeline for wind turbine blade inspection built from three components that each handle a distinct sub-task. The Eyes a YOLO26-x-obb oriented bounding-box detector localizes defects at dataset-native resolution. The Bridge a deterministic, parameter-free encoding module maps each detected bounding box to grid-referenced spatial tokens embedded in a structured prompt. The Brain a 4-bit quantized Qwen-2.5-1.5B model adapted with Quantized Low-Rank Adaptation (QLoRA) on 947 synthetically generated maintenance reports generates a structured JSON report from that prompt. Retrieval-Augmented Fine-Tuning (RAFT) further grounds each recommendation in indexed maintenance procedures. Five ablation experiments, scored by BLEU-4, ROUGE-L, Hallucination Rate (HR), and an LLM-as-a-Judge rubric, compare the pipeline against a monolithic vision-language model (VLM) baseline and against partial configurations in which one component is removed. The complete system achieves BLEU-4 0.41, HR=4%, and Expert Score = 8.6/10 compared with 0.07, 65%, and 3.3/10 for the zero-shot VLM baseline. The QLoRA-adapted 1.5B model generates higher-quality reports than a 671B-parameter generalist API model given identical detection evidence, at 47 tokens per second on a single T4-class GPU. The results show that purpose-built decoupled architecture with a small domain-specific training corpus outperforms a generalist end-to-end model on this structured generation task.","authors":["Malikussaid","Imad Gohar"],"published":"2026-05-26T04:27:38Z","updated":"2026-05-26T04:27:38Z","abstract_url":"https://arxiv.org/abs/2605.26533v1","html_url":"https://arxiv.org/html/2605.26533v1","pdf_url":"https://arxiv.org/pdf/2605.26533v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26525v1","title":"ReCA: Multi-Shot Long Video Extrapolation via Recursive Context Allocation","abstract":"Minute-scale cinematic video generation is a central challenge for generative video models. Existing paradigms address only fragments of this challenge: single-shot extrapolation preserves an anchor but lacks cinematic structure, while multi-shot storytelling imposes structure yet remains free to invent its visual states rather than continue an observed one. We define Multi-Shot Video Extrapolation (MSVE), a task that extends an observed frame or clip into a sequence of cinematically structured shots while preserving anchor state and advancing narrative intent. This setting operates under the finite per-call generation budget of short-video models. We identify three coupled bottlenecks: (1) global planners over-specify unsupported details from full screenplays; (2) shot-level prompts dilute task-relevant state when carrying the complete story; and (3) temporal chaining turns generated frames into a lossy memory in which identity, scene, object, and action state decay. MSVE reveals that long-video failure is not merely a limitation of context length, but a failure of context allocation. We propose Recursive Context Allocation (ReCA), an inference-time framework that allocates context hierarchically across planning and generation. ReCA recursively decomposes MSVE into context-bounded subproblems, invokes frozen generators at leaf nodes, and propagates structured state updates across time. To evaluate this setting, we further propose MSVE-Bench and NB-Q, a source-grounded protocol with prompts purpose-built for 3 to 5 minute long-video generation, a regime not addressed by existing short-clip benchmarks. Compared to previous methods, ReCA improves average normalized score by 8 to 16 percent over the strongest competing controller and improves multi-shot consistency metrics by 28 to 43 percent. View the project page at https://reca.vmv.re.","authors":["Akide Liu","Jinbo Xing","Chaojie Mao","Ye Li","Zeyu Zhang","Yefei He","Weijie Wang","Zihan Wang","Yu Liu","Gholamreza Haffari","Bohan Zhuang"],"published":"2026-05-26T04:16:56Z","updated":"2026-05-26T04:16:56Z","abstract_url":"https://arxiv.org/abs/2605.26525v1","html_url":"https://arxiv.org/html/2605.26525v1","pdf_url":"https://arxiv.org/pdf/2605.26525v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26524v1","title":"CmIVTP: Cross-modal Interaction-based Vessel Trajectory Prediction for Maritime Intelligence","abstract":"Maritime intelligent transportation systems (MITS) are essential for ensuring navigation safety and efficiency in busy waterways. However, accurate vessel trajectory prediction remains challenging due to the limitations of single-source data. Automatic identification system (AIS) data is often sparse or unavailable for small vessels, while closed-circuit television (CCTV) data alone cannot fully capture dynamic vessel behavior. To mitigate these challenges, we propose a cross-modal interaction-based vessel trajectory prediction (named CmIVTP) framework to model the intricate interactions between vessel dynamics and environmental constraints. Specifically, we introduce a target-aware scene encoder to extract scene semantic features, effectively capturing vessel-environment interactions and enhancing trajectory prediction accuracy. In addition, we propose a cross-modal interaction transformer, which integrates AIS-derived motion features, CCTV-based environmental features, and scene representations. It leverages cross-modal attention mechanisms to simultaneously capture intra-modal semantics and inter-modal interactions, ensuring dynamically consistent and environmentally feasible predictions. Furthermore, we construct a vessel group trajectory bank by clustering historical AIS trajectories into representative motion patterns, providing an efficient and scalable approach for candidate trajectory generation. Additionally, we introduce the maritime multimodal dataset plus (named Maritime-MmD$^+$), a large-scale dataset that synchronizes AIS data and CCTV video data, providing robust support for multimodal trajectory prediction research. Extensive experiments demonstrate that CmIVTP achieves better performance on multimodal-driven vessel trajectory prediction benchmarks. The code resources for this work can be available at https://github.com/LouisYxLu/CmIVTP.","authors":["Yuxu Lu","Dong Yang","Xiaoyu Li","Mengwei Bao","Congcong Zhao"],"published":"2026-05-26T04:14:35Z","updated":"2026-05-26T04:14:35Z","abstract_url":"https://arxiv.org/abs/2605.26524v1","html_url":"https://arxiv.org/html/2605.26524v1","pdf_url":"https://arxiv.org/pdf/2605.26524v1.pdf","matched_keywords":["video","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26519v1","title":"$R^3$: 3D Reconstruction via Relative Regression","abstract":"Recent feed-forward geometry foundation models have demonstrated impressive generalization by recovering depth and poses in a single forward pass. However, these models are typically constrained by a global coordinate frame assumption. This dependency becomes a significant bottleneck for long-context and streaming reconstruction, as it forces the network to maintain an arbitrary temporal origin and handle translation magnitudes that grow unbounded over time. Our solution, which we call $R^3$, employs relative regression. We employ a lightweight MLP to predict confidence-weighted relative constraints. These confidences serve as a unified anchor: weighting losses during training and guiding pose aggregation during inference. $R^3$ supports both full-context offline reconstruction and causal, bounded-memory streaming. Our evaluation in both offline and streaming settings validates the effectiveness of our relative mechanism. Project page: https://kevinxu02.github.io/r3-site","authors":["Congrong Xu","Huachen Gao","Xingyu Chen","Yuliang Xiu","Jun Gao","Anpei Chen"],"published":"2026-05-26T04:03:38Z","updated":"2026-05-26T04:03:38Z","abstract_url":"https://arxiv.org/abs/2605.26519v1","html_url":"https://arxiv.org/html/2605.26519v1","pdf_url":"https://arxiv.org/pdf/2605.26519v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26514v1","title":"CSV-ViT: A Vision Transformer with the Variable-sized Cortical Supervertices for Detection of Alzheimer's Disease Pathologies","abstract":"Confirming Alzheimer's disease (AD) typically relies on positron emission tomography (PET), which remains costly and invasive, motivating the use of structural MRI-based prescreening. Deep learning on non-Euclidean manifolds, particularly brain cortical surfaces, faces significant challenges due to the data's spherical topology. Recent surface models have enabled learning from cortical surface data; however, imposing face-based uniform patches often causes duplicate vertices at patch boundaries. In general, many surface-based models are limited in their awareness of the region of interest (ROI), which can result in non-cortical regions, such as the medial wall, being included. We propose a cortical surface tokenization that performs ROI-preserving, vertex-based, variable-sized patch partitioning. We refer to these cortical surface patches as cortical supervertices (CSVs). Building on this representation, we design the CSV Vision Transformer (CSV-ViT), a variable-size patch-tolerant Vision Transformer that uses padding and a mask-aware patch embedding. We used T1-weighted MRI and evaluated our framework by classifying AD-related status into three categories: AD diagnosis, amyloid positivity, and tau positivity. Across the experiments, CSV-ViT achieved higher classification performance than recent surface-based models. The results suggest that the proposed CSV-ViT may support MRI-based prediction of AD-related status prior to PET or CSF confirmation.","authors":["Geonwoo Baek","Ikbeom Jang"],"published":"2026-05-26T03:57:33Z","updated":"2026-05-26T03:57:33Z","abstract_url":"https://arxiv.org/abs/2605.26514v1","html_url":"https://arxiv.org/html/2605.26514v1","pdf_url":"https://arxiv.org/pdf/2605.26514v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26513v1","title":"Re-M3Dr: Rebalanced MultiModal Mean Deviation Regression","abstract":"Mean Deviation (MD) is a critical metric for assessing visual field loss in ophthalmology. While previous work has focused solely on predicting MD from Optical Coherence Tomography (OCT), it is intuitive to assume that combining OCT with another imaging of fundus photography (FP) could improve performance, as two ophthalmic medical imaging provide complementary information. This is particularly expected when sophisticated multi-objective optimization is applied, as documented in common multimodal classification. Surprisingly, our investigations reveal that multimodal fusion in this medical imaging scenario performs worse than unimodal model. Through detailed analysis, we identify the root cause as a coupled imbalance between data distribution and modality learning conflict. This imbalance distorts the optimization landscape, leading to unstable training. To address this challenge, we propose the method of Rebalanced MultiModal Mean Deviation Regression (Re-M3Dr), a novel multimodal regression framework. We enhance unimodal representation through adaptive margin based supervised contrastive learning. Then, our framework stabilizes the joint optimization with the sharpness-aware gradient modulation. Experimental results on both public and private clinical datasets show average 29\\% reduction in MSE compared to SOTA multimodal learning methods, demonstrating the superiority of Re-M3Dr. The code is available in the supplementary materials.","authors":["Haojie Yin","Chengcheng Feng","Tianyi Liu","Tianqi Zhang","Kaizhu Huang"],"published":"2026-05-26T03:57:28Z","updated":"2026-05-26T03:57:28Z","abstract_url":"https://arxiv.org/abs/2605.26513v1","html_url":"https://arxiv.org/html/2605.26513v1","pdf_url":"https://arxiv.org/pdf/2605.26513v1.pdf","matched_keywords":["3d","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26503v1","title":"Uncertainty-Aware Gaussian Map for Vision-Language Navigation","abstract":"Vision-Language Navigation (VLN) requires an agent to navigate 3D environments following natural language instructions. During navigation, existing agents commonly encounter perceptual uncertainty, such as insufficient evidence for reliable grounding or ambiguity in interpreting spatial cues, yet they typically ignore such information when predicting actions. In this work, we explicitly model three forms of perceptual uncertainty (i.e., geometric, semantic, and appearance uncertainty) and integrate them into the agent's observation space to enable informed decision-making. Concretely, our agent first constructs a Semantic Gaussian Map (SGM), composed of differentiable 3D Gaussian primitives initialized from panoramic observations, that encodes both the geometric structure and semantic content of the environment. On top of SGM, geometric uncertainty is estimated through variational perturbations of Gaussian position and scale to assess structural reliability; semantic uncertainty is captured by perturbing Gaussian semantic attributes to reveal ambiguous interpretations; and appearance uncertainty is characterized by Fisher Information, which measures the sensitivity of rendered observations to Gaussian-level variations. These uncertainties are incorporated into SGM, extending it into a unified 3D Value Map, which grounds them as affordances and constraints that support reliable navigation. Comprehensive evaluations across multiple VLN benchmarks show the effectiveness of our agent.","authors":["Jianzhe Gao","Rui Liu","Yuxuan Xu","Tongtong Cao","Yingxue Zhang","Zhanguang Zhang","Sida Peng","Yi Yang","Wenguan Wang"],"published":"2026-05-26T03:33:47Z","updated":"2026-05-26T03:33:47Z","abstract_url":"https://arxiv.org/abs/2605.26503v1","html_url":"https://arxiv.org/html/2605.26503v1","pdf_url":"https://arxiv.org/pdf/2605.26503v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26500v1","title":"3D Gaussian Map with Open-Set Semantic Grouping for Vision-Language Navigation","abstract":"Vision-language navigation (VLN) requires an agent to traverse complex 3D environments based on natural language instructions, necessitating a thorough scene understanding. While existing works equip agents with various scene representations to enhance spatial awareness, they often neglect the complex 3D geometry and rich semantics in VLN scenarios, limiting the ability to generalize across diverse and unseen environments. To address these challenges, this work proposes a 3D Gaussian Map that represents the environment as a set of differentiable 3D Gaussians and accordingly develops a navigation strategy for VLN. Specifically, Egocentric Scene Map is constructed online by initializing 3D Gaussians from sparse pseudo-lidar point clouds, providing informative geometric priors for scene understanding. Each Gaussian primitive is further enriched through Open-Set Semantic Grouping operation, which groups 3D Gaussians based on their membership in object instances or stuff categories within the open world, resulting in a unified 3D Gaussian Map. Building on this map, Multi-Level Action Prediction strategy, which combines spatial-semantic cues at multiple granularities, is designed to assist agents in decision-making. Extensive experiments conducted on three public benchmarks (i.e., R2R, R4R, and REVERIE) validate the effectiveness of our method.","authors":["Jianzhe Gao","Rui Liu","Wenguan Wang"],"published":"2026-05-26T03:25:49Z","updated":"2026-05-26T03:25:49Z","abstract_url":"https://arxiv.org/abs/2605.26500v1","html_url":"https://arxiv.org/html/2605.26500v1","pdf_url":"https://arxiv.org/pdf/2605.26500v1.pdf","matched_keywords":["3d","agent","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26491v1","title":"Beyond Pairwise Preferences: Listwise Reward-Aware Alignment for Diffusion Models","abstract":"Preference optimization has emerged as an efficient alternative to online reinforcement learning from human feedback (RLHF) for aligning text-to-image diffusion models. However, existing methods largely reduce supervision to binary pairwise comparisons. This pairwise reduction is limiting when training data naturally contains multiple candidate images for the same prompt, and when continuous reward scores can provide richer information than a single winner-loser label. To address these limitations, we propose Diffusion LAIR, a reward-aware listwise preference optimization method for diffusion models. For each prompt, LAIR converts reward scores across a group of candidate images into centered advantage weights, then optimizes an advantage-weighted regression objective on the implicit reward, defined as the denoising-loss improvement of the current model over a fixed reference model, with a quadratic penalty that regularizes the magnitude of the implicit reward. The resulting objective uses all candidates simultaneously rather than selecting pairs, and remains conservative by explicitly controlling the magnitude of the implicit reward. The LAIR objective admits a bounded closed-form optimum in implicit-reward space, clarifying how the regularization strength controls the magnitude of the preference update. Experiments show that Diffusion LAIR outperforms strong preference optimization baselines on SD1.5 and SDXL across text-to-image generation, compositional generation, and image editing benchmarks.","authors":["Austin Wang","Jiaqi Han","Stefano Ermon","Yisong Yue"],"published":"2026-05-26T03:09:24Z","updated":"2026-05-26T03:09:24Z","abstract_url":"https://arxiv.org/abs/2605.26491v1","html_url":"https://arxiv.org/html/2605.26491v1","pdf_url":"https://arxiv.org/pdf/2605.26491v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26486v1","title":"LongCat-Video-Avatar 1.5 Technical Report","abstract":"Despite advances in audio-driven video generation, achieving commercial-grade stability remains challenging. We present LongCat-Video-Avatar 1.5, an upgraded open-source framework prioritizing systematic engineering and production-readiness over architectural novelty. By upgrading the audio encoder to Whisper Large and meticulously scaling our training recipes, v1.5 achieves accurate lip-synchronization, full-body temporal stability, and robust long-video generation with strict identity consistency. Through rigorous data curation and RLHF Training, the model readily generalizes to stylized domains such as anime and animals, and natively handles complex real-world conditions, such as multi-person interactions and object handling. Furthermore, addressing the practical demands of industrial deployment, we employ advanced step distillation to accelerate inference to an optimal 8 NFE, achieving a favorable trade-off between serving efficiency and visual fidelity. The superiority of our approach is validated through extensive quantitative metrics and a rigorous human evaluation conducted on a comprehensive benchmark of over 500 diverse test cases. Results show that v1.5 achieves competitive or superior performance compared to leading closed-source systems (e.g., HeyGen, OmniHuman 1.5, Kling Avatar 2.0) across human-likeness ratings and expert-level quality assessments on our benchmark. With its open-source release, LongCat-Video-Avatar 1.5 narrows the gap between academic research prototypes and commercial-grade deployment.","authors":["Meituan LongCat Team","Xunliang Cai","Meng Cheng","Feng Gao","Zhe Kong","Jiamu Li","Le Li","Weiheng Li","Hongyu Liu","Shuai Tan","Xiaoming Wei","Tianyu Yang","Yong Zhang"],"published":"2026-05-26T02:54:12Z","updated":"2026-05-26T02:54:12Z","abstract_url":"https://arxiv.org/abs/2605.26486v1","html_url":"https://arxiv.org/html/2605.26486v1","pdf_url":"https://arxiv.org/pdf/2605.26486v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26485v1","title":"OmniInteract: Benchmarking Real-World Streaming Interaction for Real-Time Omnimodal Assistants","abstract":"We introduce OmniInteract, a streaming benchmark for real-time omnimodal large language models evaluated through native online inference over audio-visual streams. Unlike offline video understanding or text-prompted streaming QA, OmniInteract preserves the original audio-visual stream and requires models to process it online, without access to future content. User queries and ambient sounds are embedded in the audio track, requiring models to detect multimodal triggers, decide when to respond, and answer while the stream unfolds. OmniInteract contains 250 videos with 1,430 temporally grounded response slots: 1,062 1Q1A slots across real-time, proactive, and nested scenarios, and 368 1QnA slots for continuous task monitoring and step guidance. Each slot includes a trigger, response window, and target answer. We evaluate response correctness, timing, invalid outputs, interruption handling, and context continuity using Interaction-Aware Quality-Timeliness F1, Interruption Diagnostic Suite, and Nested Chain Completion Score. Experiments show that current models remain weak in streaming interaction, with the best overall IA-QTF1 reaching only 0.368 and the best 1QnA IA-QTF1 only 0.052. Further study on mathematical reasoning in full-duplex settings shows that offline capability does not necessarily transfer to online interaction. Code and datasets will be made publicly accessible at https://github.com/Lucky-Lance/OmniInteract.","authors":["Xudong Lu","Xueying Li","Annan Wang","Yang Bo","Jinpeng Chen","Zengliang Li","Nianzu Yang","Rui Liu","Xue Yang","Jingwen Hou","Hongsheng Li"],"published":"2026-05-26T02:49:47Z","updated":"2026-05-26T02:49:47Z","abstract_url":"https://arxiv.org/abs/2605.26485v1","html_url":"https://arxiv.org/html/2605.26485v1","pdf_url":"https://arxiv.org/pdf/2605.26485v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26483v1","title":"Clinically-Grounded Counterfactual Reasoning for Medical Video Diagnosis","abstract":"Medical video diagnosis involves inferring clinical decisions from dynamic tissue responses throughout examination processes. Existing methods rely on an end-to-end learning paradigm that i) focuses on appearance rather than pathology, ii) lacks clinical priors, and iii) reasons solely from observations without counterfactual comparison. This work introduces MedVCR, a counterfactual reasoning framework that mimics clinical diagnostic thinking. MedVCR comprises three components: a Counterfactual Generator that synthesizes tissue evolution under specified pathological states via a diffusion-based manner; a Counterfactual Representation Learning module that encodes diagnostic knowledge through clinical rules (i.e., temporal consistency, pathological separability, and counterfactual alignment); and a Dual Diagnostic Prediction strategy that integrates video-level assessment with frame-level counterfactual analysis. MedVCR is evaluated under both fully supervised (e.g., colposcopy) and weakly supervised (e.g., colonoscopy) video diagnosis settings, yielding 2.6%-10.2% performance gains compared with leading baselines. Comprehensive ablation studies further validate the effectiveness of each component. The code will be released.","authors":["Jianzhe Gao","Churan Wang","Weiyi Zhang","Jianghua Li","Li-An Li","Wenguan Wang","Yixin Zhu","Yizhou Wang"],"published":"2026-05-26T02:46:15Z","updated":"2026-05-26T02:46:15Z","abstract_url":"https://arxiv.org/abs/2605.26483v1","html_url":"https://arxiv.org/html/2605.26483v1","pdf_url":"https://arxiv.org/pdf/2605.26483v1.pdf","matched_keywords":["video","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"}],"favorites":[],"latest":{"generated_at_utc":"2026-05-27T05:12:04+00:00","category":"cs.CV","keywords":["video","retrieval","3d","agent","representation","instance","multimodal","diffusion"],"fetch_window_hours":72,"daily_window_hours":30,"match_count":80,"new_or_recent_papers":[{"id":"2605.27372v1","title":"G3T Up! Gravity Aligned Coordinate Frames Simplify Pointmap Processing","abstract":"Modern feed-forward 3D reconstruction methods like VGGT predict pixel-aligned pointmaps in camera-centric coordinate frames. However, this choice of coordinate frame is not always optimal. We propose instead to predict pointmaps in upright, gravity-aligned frames that exploit strong structural cues present in many real-world scenes. Unlike camera-centric frames, gravity-aligned frames share a common vertical axis across viewpoints, reducing the rotational degrees of freedom needed to relate pointmaps to one another. To this end, we introduce the Gravity Grounded Geometry Transformer (G3T), fine-tuned from existing models on gravity-aligned 3D data. G3T produces highly accurate gravity-aware predictions, including upright pointmaps and camera-to-gravity poses. We further introduce G3T-Long, a submap-based incremental 3D reconstruction pipeline that leverages the reduced rotational degrees of freedom afforded by upright frames to achieve significantly improved reconstruction accuracy.","authors":["Bharath Raj Nagoor Kani","Noah Snavely"],"published":"2026-05-26T17:59:55Z","updated":"2026-05-26T17:59:55Z","abstract_url":"https://arxiv.org/abs/2605.27372v1","html_url":"https://arxiv.org/html/2605.27372v1","pdf_url":"https://arxiv.org/pdf/2605.27372v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":58422,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Modern feed-forward 3D reconstruction methods like VGGT predict pixel-aligned pointmaps in camera-centric coordinate frames. However, this choice of coordinate frame is not always optimal. We propose instead to predict pointmaps in upright, gravity-aligned fr...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:04+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27367v1","title":"SpatialBench: Is Your Spatial Foundation Model an All-Round Player?","abstract":"While spatial foundation models have demonstrated impressive performance on standard datasets, a critical question remains: are they truly all-round players capable of generalizing robustly across diverse downstream tasks, arbitrary viewpoints, shifting scene domains, varying input densities, and specific hardware constraints? Answering this overarching question requires a holistic assessment, yet current models are mainly evaluated on specific domains for which they were specifically designed or trained. Such evaluations are intrinsically limited by narrow paradigm coverage, limited scene domains, and arbitrary frame sampling, making it fundamentally difficult to assess their true generalization capabilities. To address this gap, we present SpatialBench, a cross-paradigm, domain-diverse benchmark for spatial foundation models with deterministic sampling. SpatialBench features unprecedented scale and rigorous deterministic design, comprising 19 datasets and 546 scenes across 5 diverse spatial domains. It comprehensively evaluates 41 models across 6 paradigms on 5 task suites under 4 different input density settings. Our extensive evaluation reveals that current models are not yet all-round players, and uncovers crucial insights for future advancement. Specifically, we demonstrate that full-context attention maximizes accuracy while bounded-memory strategies unlock long-sequence scalability. Moreover, our empirical evaluations in challenging embodied and egocentric tasks demonstrate that strict domain alignment and high data quality are far more critical to performance than simple dataset scaling. Furthermore, to address the largest data gap identified in our analysis, we go beyond evaluation by introducing a large-scale dataset, DA-Next-5M, and a strong baseline model, DA-Next, pushing the boundaries of spatial representation learning.","authors":["Haosong Peng","Hao Li","Jiaqi Chen","Yuhao Pan","Runmao Yao","Yalun Dai","Fushuo Huo","Fangzhou Hong","Zhaoxi Chen","Haozhao Wang","Dingwen Zhang","Ziwei Liu","Wenchao Xu"],"published":"2026-05-26T17:59:20Z","updated":"2026-05-26T17:59:20Z","abstract_url":"https://arxiv.org/abs/2605.27367v1","html_url":"https://arxiv.org/html/2605.27367v1","pdf_url":"https://arxiv.org/pdf/2605.27367v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":277415,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：While spatial foundation models have demonstrated impressive performance on standard datasets, a critical question remains: are they truly all-round players capable of generalizing robustly across diverse downstream tasks, arbitrary viewpoints, shifting scene...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:05+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27351v1","title":"Feedforward 3D Editing Learns from Semantic-Part Transformation","abstract":"3D editing is a fundamental capability for scalable 3D content creation. While image editing has rapidly evolved toward large-scale feedforward generative paradigms, 3D AI generation remains dominated by training-free editing pipelines. A central challenge of feedforward 3D editing lies in the lack of high-quality paired supervision. Editable 3D assets require simultaneous preservation of geometry, multi-view consistency, structural coherence, and localized edit controllability. Existing 3D editing datasets often rely on independently generated assets, image-mediated reconstruction or narrow edit taxonomies, leading to inaccurate localization, weak preservation, blurred edit boundaries, and limited semantic consistency. In this work, we introduce a new perspective: scalable feedforward 3D editing should be learned from semantic-part transformations. Based on this insight, we propose Pxform, a high-quality 3D editing dataset with over 100K consistent before/after editing pairs across seven edit types. Instead of treating objects as unstructured shapes, our pipeline grounds edits directly in semantic 3D parts. Built upon Pxform, we further propose PartFlow, a feedforward 3D editing network that injects source-aware latent control into pretrained 3D generative priors. PartFlow introduces mask-aware velocity preservation and render-space consistency supervision to jointly improve edit fidelity and source preservation, while requiring no 3D edit mask during inference. Extensive experiments demonstrate that high-quality semantic-part supervision substantially improves scalable 3D editing, enabling PartFlow to achieve state-of-the-art performance on both geometric and appearance editing benchmarks.","authors":["Jiawei Weng","Saining Zhang","Zhenxin Diao","Peishuo Li","Henghaofan Zhang","Junhao Chen","Hao Zhao"],"published":"2026-05-26T17:51:59Z","updated":"2026-05-26T17:51:59Z","abstract_url":"https://arxiv.org/abs/2605.27351v1","html_url":"https://arxiv.org/html/2605.27351v1","pdf_url":"https://arxiv.org/pdf/2605.27351v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":67209,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：3D editing is a fundamental capability for scalable 3D content creation. While image editing has rapidly evolved toward large-scale feedforward generative paradigms, 3D AI generation remains dominated by training-free editing pipelines. A central challenge of...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:05+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27348v1","title":"When Eyes Betray AI: Social Gaze Consistency as a Semantic Cue for AI-Generated Image Detection","abstract":"Recent generative models have largely closed the gap on low-level artifacts - pixel fingerprints, frequency anomalies, upsampling traces - particularly in person-centric and partial-edit settings where the manipulated region is small and surrounded by photometrically authentic content. We introduce Social Gaze Consistency, a high-level semantic cue defined as the mutual coherence of gaze direction, head-eye alignment, and pupil placement between interacting individuals, and show that it constitutes a previously underutilized detection axis orthogonal to existing low-level paradigms. We instantiate this insight through three coupled mechanisms: (i) a controlled diagnostic dataset with region-specific perturbations of gaze-consistent imagery, where strict pair-level grouping forecloses generator-fingerprint memorization as an optimization-time shortcut rather than relying on augmentation; (ii) Block-Compositional Caption Supervision, which holds a single 5-block reasoning skeleton invariant across 1,250 macro-combined captions, decoupling reasoning consistency from surface diversity; (iii) Cross-architecture validation showing the same supervision improves a vision-language backbone (FakeVLM) by +3.7 pp on the COCOAI Interaction subset (balanced accuracy 67.8 -> 71.5) and +1.3 pp on the COCOAI Person subset (83.0 -> 84.3), with consistent gains on a vision-only backbone (Effort), evidencing a backbone-agnostic cue. Real- and fake-class recalls rise simultaneously, ruling out a \"predict-all-fake\" artifact. A four-step mechanistic account - paired-edit shortcut blocking, hard-to-easy difficulty transfer, CLIP prior preservation, and diffusion-family shared spectral weakness in periocular structure - explains why training on a single inpainter (FLUX.1-Fill) transfers to multi-generator suites. We will release the code upon acceptance to facilitate reproducibility.","authors":["Kim Jihyeon","Sohee Kim","Soosan Lee","Souhwan Jung","James Matthew Rehg","Hyesong Choi"],"published":"2026-05-26T17:50:17Z","updated":"2026-05-26T17:50:17Z","abstract_url":"https://arxiv.org/abs/2605.27348v1","html_url":"https://arxiv.org/html/2605.27348v1","pdf_url":"https://arxiv.org/pdf/2605.27348v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":91835,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Recent generative models have largely closed the gap on low-level artifacts - pixel fingerprints, frequency anomalies, upsampling traces - particularly in person-centric and partial-edit settings where the manipulated region is small and surrounded by photome...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:05+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27343v1","title":"Towards Controllable Image Generation through Representation-Conditioned Diffusion Models","abstract":"Diffusion models have emerged as powerful tools for high-quality image generation and editing, but guiding these models to produce specific outputs remains a challenge. Conventional approaches rely on conditioning mechanisms, such as text prompts or semantic maps, which require extensively annotated datasets. In this preliminary work, we explore diffusion models conditioned on representations from a pre-trained self-supervised model. The self-conditioning mechanism not only improves the quality of unconditional image generation, but also provides a representation space that can be used to control the generation. We explore this conditioning space by identifying directions of variations, and demonstrate promising properties in terms of smoothness and disentanglement.","authors":["Nithesh Chandher Karthikeyan","Jonas Unger","Gabriel Eilertsen"],"published":"2026-05-26T17:46:25Z","updated":"2026-05-26T17:46:25Z","abstract_url":"https://arxiv.org/abs/2605.27343v1","html_url":"https://arxiv.org/html/2605.27343v1","pdf_url":"https://arxiv.org/pdf/2605.27343v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":17257,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Diffusion models have emerged as powerful tools for high-quality image generation and editing, but guiding these models to produce specific outputs remains a challenge. Conventional approaches rely on conditioning mechanisms, such as text prompts or semantic...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:05+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27336v1","title":"PARE: Pruning and Adaptive Routing for Efficient Video Generation","abstract":"Video Diffusion Transformers (DiTs) generate high-quality videos but demand substantial compute due to wide blocks, deep architectures, and iterative sampling. Recent methods reduce cost by compressing width, depth, or sampling steps, but typically commit to a fixed architecture that cannot adapt to individual inputs or denoising stages. We propose PARE (Pruning and Adaptive Routing for Efficient video generation), which jointly compresses width and depth with structure-aware pruning and input-adaptive routing. For width, we observe that attention heads specialize into spatial and temporal roles, and design importance scoring that accounts for this distinction to prevent motion-critical temporal heads from being pruned prematurely. For depth, we train a lightweight router conditioned on denoising timestep and visual content to dynamically select which blocks to execute at each step, enabling per-input compute adaptation rather than static block removal. A progressive pipeline first recovers width-pruned quality via distillation, then jointly optimizes the student and router to decouple the two learning objectives. Experiments on Wan2.1-14B for both image-to-video and text-to-video generation show that PARE substantially reduces per-step computation while preserving quality across VBench dimensions, and composes with step distillation for further acceleration.","authors":["Yutong Wang","Yunke Wang","Tianfan Xue","Yu Qiao","Yaohui Wang","Xinyuan Chen","Chang Xu"],"published":"2026-05-26T17:43:25Z","updated":"2026-05-26T17:43:25Z","abstract_url":"https://arxiv.org/abs/2605.27336v1","html_url":"https://arxiv.org/html/2605.27336v1","pdf_url":"https://arxiv.org/pdf/2605.27336v1.pdf","matched_keywords":["video","diffusion"],"source_used":"html","source_text_chars":53410,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, diffusion 相关；摘要显示其主要贡献为：Video Diffusion Transformers (DiTs) generate high-quality videos but demand substantial compute due to wide blocks, deep architectures, and iterative sampling. Recent methods reduce cost by compressing width, depth, or sampling steps, but typically commit to...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:05+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27318v1","title":"Q-GeoMem: Question-Guided Geometric Memory for Video Spatial Reasoning","abstract":"Video spatial reasoning requires accumulating viewpoint-dependent evidence over time while retaining information useful to the question being asked. Existing spatial video-language models improve geometric perception and long-range context modeling, but often treat memory as a generic temporal cache, which can introduce redundant or irrelevant geometry and weaken long-horizon reasoning. We propose \\textbf{\\ours}, a question-guided geometric memory framework for video spatial reasoning. \\ours injects camera-conditioned geometry into visual tokens and maintains two complementary memories: a Fine-Grained Context Bank for recent dense features and camera states, and a Semantic-Geometric Evidence Bank for compact long-range evidence. Each candidate frame is scored by the product of Q-Former-based question relevance and novelty with respect to the retained bank; this score is stored and reused during reading, while a capacity-based replacement rule keeps the bank compact. During reasoning, both memories are read before update and adaptively fused with the current frame representation. Experiments on VSI-Bench and VSTI-Bench show that \\ours achieves state-of-the-art performance among evaluated spatial reasoning models, validating the effectiveness of question-guided geometric memory. Ablations further verify the contribution of the proposed evidence scoring mechanism.","authors":["Xianqiang Gao","Qizhi Chen","Delin Qu","Haoming Song","Zhigang Wang","Bin Zhao","Dong Wang","Xuelong Li"],"published":"2026-05-26T17:26:29Z","updated":"2026-05-26T17:26:29Z","abstract_url":"https://arxiv.org/abs/2605.27318v1","html_url":"https://arxiv.org/html/2605.27318v1","pdf_url":"https://arxiv.org/pdf/2605.27318v1.pdf","matched_keywords":["video","representation"],"source_used":"html","source_text_chars":49652,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation 相关；摘要显示其主要贡献为：Video spatial reasoning requires accumulating viewpoint-dependent evidence over time while retaining information useful to the question being asked. Existing spatial video-language models improve geometric perception and long-range context modeling, but often...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27310v1","title":"How and What to Imagine? Visual Thinking in Unified Multimodal Models for Cross-View Spatial Reasoning","abstract":"Cross-view spatial reasoning remains a weak spot for vision-language models (VLMs): they often reason in language and lose the fine-grained geometry needed for the task. Thinking with images aims to address this by generating an intermediate thinking image, but recent work shows that models often ignore the visual evidence in these traces. We therefore ask how to make visual thinking matter, and what kind of visual thinking works best. We study these questions in unified multimodal models (UMMs), which natively support interleaved image-text generation. For the first question, we propose View Dropout (VDrop), a training-time intervention that hides parts of one input view from the answer span while keeping them visible to the thinking-image tokens. This encourages the model to use the thinking image when answering, instead of relying only on the input views. Once the thinking image is used for answer prediction, we study which type of visual thinking is most effective. We frame this as a learnability-informativeness tradeoff and compare three thinking-image variants: top-down, panoramic, and point-matching renderings. Trained on synthetic scenes and evaluated on five real-world out-of-domain benchmarks, panoramic visual thinking with VDrop is the only configuration that is both informative and learnable, and it achieves the best out-of-domain generalization.","authors":["Qian Yang","Ankur Sikarwar","Huy Le","Le Zhang","Zhuan Shi","Perouz Taslakian","Aishwarya Agrawal"],"published":"2026-05-26T17:20:05Z","updated":"2026-05-26T17:20:05Z","abstract_url":"https://arxiv.org/abs/2605.27310v1","html_url":"https://arxiv.org/html/2605.27310v1","pdf_url":"https://arxiv.org/pdf/2605.27310v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":75940,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Cross-view spatial reasoning remains a weak spot for vision-language models (VLMs): they often reason in language and lose the fine-grained geometry needed for the task. Thinking with images aims to address this by generating an intermediate thinking image, b...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27304v1","title":"PlayClass: Automated Play Behaviour Classification in Poultry","abstract":"Automated monitoring of animal welfare has largely targeted negative indicators, leaving positive welfare behaviours such as play underexplored. To address this gap, we present PlayClass, a pipeline for play-behaviour classification in poultry from top-down pen video. The pipeline leverages long-duration tracking with SAM 3 via YOLO-guided chunk boundaries to minimise identity errors in point-based prompting, and frozen embeddings from image and video foundation models for play action classification. Although handcrafted motion features from tracked masks alone achieved competitive accuracy, V-JEPA 2.1 consistently outperformed all other backbones across model scales, reaching 77.0 macro-averaged F$_1$ when combined with handcrafted features. Despite this result, the dataset remains challenging due to play sub-types sharing similar kinematic profiles with non-play and inter-bird occlusion. Overall, our work provides encouraging evidence towards automated frameworks for play behaviour classification in poultry.","authors":["Prince Ravi Leow","Neil Scheidwasser","Rebecca Oscarsson","Per Jensen","Samir Bhatt","David Alejandro Duchêne"],"published":"2026-05-26T17:13:36Z","updated":"2026-05-26T17:13:36Z","abstract_url":"https://arxiv.org/abs/2605.27304v1","html_url":"https://arxiv.org/html/2605.27304v1","pdf_url":"https://arxiv.org/pdf/2605.27304v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":35847,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Automated monitoring of animal welfare has largely targeted negative indicators, leaving positive welfare behaviours such as play underexplored. To address this gap, we present PlayClass, a pipeline for play-behaviour classification in poultry from top-down p...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27295v1","title":"Gemini Embedding 2: A Native Multimodal Embedding Model from Gemini","abstract":"We introduce Gemini Embedding 2, a native multimodal embedding model that allows embedding video, audio, image, and text modalities in a unified representation space. We leverage the multimodal capabilities of Gemini to produce embeddings for arbitrary combinations of interleaved inputs across all these modalities that generalize well across a wide variety of tasks. Applying large-scale contrastive learning in a multi-task multi-stage training setup, we achieve state-of-the-art performance on key embedding benchmarks including unimodal, cross-modal, and multimodal retrieval spanning a diverse set of tasks. We show that our embedding model demonstrates strong performance (with a score of 62.9 R@1 on MSCOCO, 68.8 NDCG@10 on Vatex, 69.9 on MTEB multilingual and 84.0 on MTEB Code) across a variety of tasks surpassing the performance of specialized models. These unified capabilities make Gemini Embedding 2 a promising candidate for downstream use cases such as RAG, recommendation and search. Furthermore, its robust zero-shot performance across distinct fields - from astronomy and bioscience to fine arts and the culinary arts - establishes it as a highly reliable, out-of-the-box representation even for specialized domains.","authors":["Madhuri Shanbhogue","Zhe Li","Shanfeng Zhang","Gustavo Hernández Ábrego","Shih-Cheng Huang","Aashi Jain","Daniel Salz","Sonam Goenka","Chaitra Hegde","Ji Ma","Feiyang Chen","Jiaxing Wu","Tanmaya Dabral","Babak Samari","Kevin Poulet","Daniel Cer","Kaifeng Chen","Paul Suganathan","Hui Hui","Jovan Andonov","Philippe Schlattner","Jay Han","Iftekhar Naim","Wing Lowe","Vladimir Pchelin","Albert Yang","Yi-Ting Chen","Zhongli Ding","Grace Zhang","Georg Heigold","Yichang Chen","Antoine Reveillon","Brendan Mccloskey","Wenlei Zhou","Dahun Kim","Rui Meng","Emma Wang","Jack Zheng","Halley Fede","Zhen Yang","Keegan Mosley","Brian Potetz","Sahil Dua","Henrique Schechter Vera","Shen Gao","Hesen Zhang","Andreas Hess","Hengxuan Ying","Alberto Montes","Karan Gill","Min Choi","Sebastian Russo","Anja Hauth","Jinhyuk Lee","Michael Boratko","Megan Barnes","Vikram Rao","Claudiu Musat","Cyril Allauzen","Ehsan Variani","Shankar Kumar","Tom Bagby","Junyi Jiao","Yang Gu","Tengxin Li","Ayush Agrawal","Roberto Santana","Dev Nath","Stephen Karukas","Shuoxuan Han","Lucia Loher","Alice Twu","Nidhi Vyas","Siddharth Bhai","Frank Palma Gomez","Wangyuan Zhang","Chaoren Liu","Jizheng Yang","Steve Qiu","Shijie Zhang","Sujay Kulkarni","Sascha Rothe","Sean Nakamoto","Raphael Hoffmann","Zach Gleicher","Yunhsuan Sung","Qin Yin","Tom Duerig","Mojtaba Seyedhosseini"],"published":"2026-05-26T17:07:55Z","updated":"2026-05-26T17:07:55Z","abstract_url":"https://arxiv.org/abs/2605.27295v1","html_url":"https://arxiv.org/html/2605.27295v1","pdf_url":"https://arxiv.org/pdf/2605.27295v1.pdf","matched_keywords":["video","retrieval","representation","multimodal"],"source_used":"html","source_text_chars":49633,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, representation, multimodal 相关；摘要显示其主要贡献为：We introduce Gemini Embedding 2, a native multimodal embedding model that allows embedding video, audio, image, and text modalities in a unified representation space. We leverage the multimodal capabilities of Gemini to produce embeddings for arbitrary combin...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27243v1","title":"Can Retrieval Heads See Images? Multimodal Retrieval Heads in Long-Context Vision-Language Models","abstract":"Large vision-language models increasingly rely on long-context modeling to reason over documents, hour-level videos, and long-horizon agent trajectories, requiring them to locate relevant evidence across interleaved text and images. Prior work has studied this behavior using retrieval heads in large language models, but its copy-based criterion does not directly apply when evidence appears in images. We introduce a multimodal retrieval head detection method that scores attention from question tokens to textual or visual evidence. With this method, we show that multimodal retrieval heads are sparse, intrinsic, and causally important: only 4.4-10.2% of attention heads account for 50% of the positive retrieval-score mass, and masking the top-5% selected heads drops MMLongBench-Doc from 48.2% to 5.7% and SlideVQA from 71.2% to 8.9%, while random-head masking is far less damaging. Further analysis shows that these heads are partly shared across modalities yet remain dynamic within each modality, with image retrieval heads changing more than text retrieval heads as context length and haystack modality change. Without further training, we find that these heads can also be used directly to rank visually rich documents: on MMDocIR, Qwen3-VL-8B selected-head scoring improves Recall@1 by 7.7/7.4 macro/micro points for page retrieval and 6.3/6.8 points for layout retrieval over the strongest reported baseline.","authors":["Aaron Branson Cigres Li","Zhaowei Wang","Yu Zhao","Yiming Du","Haobo Li","Xiyu Ren","Ginny Wong","Simon See","Lishu Luo","Haodong Duan","Pasquale Minervini","Yangqiu Song"],"published":"2026-05-26T16:24:29Z","updated":"2026-05-26T16:24:29Z","abstract_url":"https://arxiv.org/abs/2605.27243v1","html_url":"https://arxiv.org/html/2605.27243v1","pdf_url":"https://arxiv.org/pdf/2605.27243v1.pdf","matched_keywords":["video","retrieval","agent","multimodal"],"source_used":"abstract","source_text_chars":1520,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, retrieval, agent, multimodal 相关；摘要显示其主要贡献为：Large vision-language models increasingly rely on long-context modeling to reason over documents, hour-level videos, and long-horizon agent trajectories, requiring them to locate relevant evidence across interleaved text and images. Prior work has studied thi...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27235v1","title":"MRT: Masked Region Transformer for Layered Image Generation and Editing at Scale","abstract":"Layered image generation and editing is a fundamental capability that enables layer-wise reuse, editing, and composition of generated visual content, analogous to word-level editing in natural language. Despite its importance, this remains an underexplored area at scale. To address this gap, we present MRT, a 20B-parameter masked region diffusion model tailored for multi-layer transparent image generation and editing, trained on over 10M multilingual design samples spanning diverse aspect ratios and textual prompts. To fully leverage this scale, we make two key technical contributions. First, we unify three complementary tasks including text-to-layers, image-to-layers, and layers-to-layers within a shared masked region diffusion framework, where selective token masking enables flexible layer-wise generation and editing. Second, to enable overflow layer generation, we introduce an overflow-aware canvas layer that handles boundary inconsistencies and supports semi-transparent background synthesis, enabling complete editable layers extending beyond visible canvas boundaries. Additionally, we apply diffusion distillation to achieve 8-step, real-time multi-layer generation with minimal quality degradation. Extensive experiments demonstrate that our framework substantially outperforms prior state-of-the-art approaches, including various commercial systems, across all three tasks, establishing a new benchmark for multi-layer transparent image generation. Notably, our model significantly outperforms the concurrent Qwen-Image-Layered model in image-to-layers quality according to user-study results, while achieving 10-100\\times faster inference and reducing activation GPU memory consumption by 50-90\\% during image-to-layer inference.","authors":["Zhicong Tang","Zhao Zhang","Jingye Chen","Mohan Zhou","Yifan Pu","Yuchi Liu","Yalong Bai","Ethan Smith","Yuhui Yuan"],"published":"2026-05-26T16:16:19Z","updated":"2026-05-26T16:16:19Z","abstract_url":"https://arxiv.org/abs/2605.27235v1","html_url":"https://arxiv.org/html/2605.27235v1","pdf_url":"https://arxiv.org/pdf/2605.27235v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":88589,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Layered image generation and editing is a fundamental capability that enables layer-wise reuse, editing, and composition of generated visual content, analogous to word-level editing in natural language. Despite its importance, this remains an underexplored ar...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:06+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27203v1","title":"Generative Animations: A Multi-Model Pipeline for Prompt-Driven Motion Synthesis","abstract":"Animation elevates digital documents into immersive experiences, yet creating custom motion paths remains cumbersome, requiring designers to manually select presets, plot Bézier points, and configure timing properties. We introduce Generative Animations, a system that transforms natural language prompts into production-ready animations. By chaining Large Language Models (LLMs) for semantic parsing with the Segment Anything Model (SAM) for visual grounding, our pipeline automatically generates motion paths that respect scene geometry, handle depth-based occlusions, and honor 3D perspective transforms. We demonstrate the system through three use cases: contour-following trajectories, orbital animations with z-order awareness, and perspective-aligned motion on transformed objects.","authors":["Mannat Khurana","Sanyam Jain","Rishav Agarwal"],"published":"2026-05-26T15:58:30Z","updated":"2026-05-26T15:58:30Z","abstract_url":"https://arxiv.org/abs/2605.27203v1","html_url":"https://arxiv.org/html/2605.27203v1","pdf_url":"https://arxiv.org/pdf/2605.27203v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":870,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Animation elevates digital documents into immersive experiences, yet creating custom motion paths remains cumbersome, requiring designers to manually select presets, plot Bézier points, and configure timing properties. We introduce Generative Animations, a sy...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27194v1","title":"Not All Tokens Matter Equally: Dynamic In-context Vector Distillation with Decisive-Token Supervision for Long-form Medical Report Generation","abstract":"Distilling demonstration effects into hidden-space interventions offers a lightweight alternative to full finetuning. However, existing multimodal variants are mostly evaluated on short-form tasks, where outputs end after a few tokens. Extending these methods to long-form generation exposes a fundamental yet underexamined limitation: token-level distillation implicitly treats all output tokens as equally informative, but long-form outputs are dominated by high-frequency template and grammatical tokens, while the tokens that actually determine output quality are sparsely distributed. In medical report generation (MRG), two such decisive tokens stand out: pathology-related tokens that determine diagnostic content, and the end-of-sequence (EOS) event that determines termination. Both receive insufficient supervision under uniform cross-entropy, and autoregressive decoding further compounds the problem by drifting away from teacher-forced trajectories. We propose DIVE, a frozen-backbone distillation framework that addresses long-form report generation through two complementary mechanisms matched to these failures. Decisive-token supervision restores supervision balance by upweighting the cross-entropy contribution of pathology-related tokens and the EOS event, ensuring that content fidelity and termination are learned during training rather than imposed at decoding time. State-conditioned dynamic steering replaces fixed open-loop residuals with hidden-state-dependent adapters, allowing the injected signal to adapt as decoding drifts. Experiments on MIMIC-CXR and CheXpert Plus with two medical VLM backbones show that DIVE consistently ranks among the strongest methods across lexical and clinical-proxy metrics. Our method achieves the best BLEU-4, ROUGE-L, and RadGraph F1 in all dataset--backbone settings, while remaining competitive on coarse label-level CheXbert F1.","authors":["Ning Wu","Rui Liu","Xinkun Lin","Weixing Chen","Jinxi Xiang","Tao Wei","Lina Yao","Mingjie Li"],"published":"2026-05-26T15:46:00Z","updated":"2026-05-26T15:46:00Z","abstract_url":"https://arxiv.org/abs/2605.27194v1","html_url":"https://arxiv.org/html/2605.27194v1","pdf_url":"https://arxiv.org/pdf/2605.27194v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":69340,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Distilling demonstration effects into hidden-space interventions offers a lightweight alternative to full finetuning. However, existing multimodal variants are mostly evaluated on short-form tasks, where outputs end after a few tokens. Extending these methods...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27178v1","title":"FoundObj: Self-supervised Foundation Models as Rewards for Label-free 3D Object Segmentation","abstract":"We address the challenging task of 3D object segmentation in complex scene point clouds without relying on any scene-level human annotations during training. Existing methods are typically constrained to identifying simple objects, primarily due to insufficient object priors in the learning process. In this paper, we present FoundObj, a novel framework featuring a superpoint-based object discovery agent that incrementally merges suitable neighboring superpoints, guided by our innovative semantic and geometric reward modules. These modules synergistically leverage semantic and geometric priors from self-supervised 2D/3D foundation models, providing complementary feedback to the object discovery agent and enabling robust identification of multi-class objects through reinforcement learning. Extensive experiments on diverse benchmarks demonstrate that our approach consistently outperforms existing baselines. Notably, our method exhibits strong generalization in zero-shot and long-tail scenarios, underscoring its potential for scalable, label-free 3D object segmentation.","authors":["Zihui Zhang","Zhixuan Sun","Yafei Yang","Jinxi Li","Jiahao Chen","Bo Yang"],"published":"2026-05-26T15:32:32Z","updated":"2026-05-26T15:32:32Z","abstract_url":"https://arxiv.org/abs/2605.27178v1","html_url":"https://arxiv.org/html/2605.27178v1","pdf_url":"https://arxiv.org/pdf/2605.27178v1.pdf","matched_keywords":["3d","agent"],"source_used":"html","source_text_chars":76841,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent 相关；摘要显示其主要贡献为：We address the challenging task of 3D object segmentation in complex scene point clouds without relying on any scene-level human annotations during training. Existing methods are typically constrained to identifying simple objects, primarily due to insufficie...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27155v1","title":"Semantic Robustness Probing via Inpainting: An Interactive Tool for Safety-Critical Object Detection","abstract":"Testing object detectors in safety-critical domains requires semantically meaningful probes beyond pixel-level corruptions. We present SemProbe, a tool for semantic robustness probing: users upload deployment images, create masks manually or automatically, select operational design domain-derived factors (or custom prompts), and run diffusion-based controlled inpainting. The system supports batch jobs, parallel seed/workflow variations, and configurable generation parameters. After each output, model inference runs automatically and displays annotated before/after comparisons with performance deltas. All probes are logged as structured artifacts, enabling traceable robustness evidence aligned with safety evaluation workflows. We demonstrate \\textsc{SemProbe} on hand detection for dimension saws, targeting factors from insurance-oriented test criteria.","authors":["Nico Steckhan","Krutarth Prajapati","Weija Shao","Silvia Vock"],"published":"2026-05-26T15:15:38Z","updated":"2026-05-26T15:15:38Z","abstract_url":"https://arxiv.org/abs/2605.27155v1","html_url":"https://arxiv.org/html/2605.27155v1","pdf_url":"https://arxiv.org/pdf/2605.27155v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":13468,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Testing object detectors in safety-critical domains requires semantically meaningful probes beyond pixel-level corruptions. We present SemProbe, a tool for semantic robustness probing: users upload deployment images, create masks manually or automatically, se...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27154v1","title":"Touch-R1: Reinforcing Touch Reasoning in MLLMs","abstract":"While rule-based reinforcement learning has recently catalyzed explicit reasoning in multimodal models, tactile reasoning remains largely underexplored. Existing tactile-language models primarily rely on supervised or contrastive objectives, which limits their capacity to ground predictions in physical evidence or rectify misleading visual priors. Tactile reasoning introduces two modality-specific challenges: the ordinal nature of physical attributes (e.g., hardness, roughness) and the cross-sensor distribution shifts inherent in optical tactile hardware. In this work, we introduce TouchReason-1M, a large-scale multimodal dataset comprising over 1M synchronized tactile pairs across four distinct sensors, and TouchReason-Bench, a rigorous framework for evaluating tactile perception and visual-tactile conflict resolution. Building upon these, we propose Touch-R1, a tactile reasoning MLLM based on Qwen2.5-VL-7B. Touch-R1 is trained via a tactile-grounded GRPO objective that combines ordinal-aware accuracy, cross-sensor physical consistency, structured-format control, and an input-side tactile grounding objective. Specifically, the tactile-use reward assigns credit only when authentic tactile inputs yield superior correctness relative to counterfactual controls where the tactile stream is removed, shuffled, or noise-masked. On TouchReason-Bench, Touch-R1-7B outperforms Octopi-13B by 18.4\\% and GPT-4o by 24.7\\% on average. Its structured reasoning traces reveal emergent behaviors of probing, comparison, and revision, demonstrating that R1-style reasoning can be effectively grounded in physical contact.","authors":["Yingxin Lai","Yafei Zhou","Fucai Zhu","Siyu Zhu","Weihao Yuan"],"published":"2026-05-26T15:14:56Z","updated":"2026-05-26T15:14:56Z","abstract_url":"https://arxiv.org/abs/2605.27154v1","html_url":"https://arxiv.org/html/2605.27154v1","pdf_url":"https://arxiv.org/pdf/2605.27154v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":47239,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：While rule-based reinforcement learning has recently catalyzed explicit reasoning in multimodal models, tactile reasoning remains largely underexplored. Existing tactile-language models primarily rely on supervised or contrastive objectives, which limits thei...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27146v1","title":"Chaos-SSL: An Attention-Based Self-Supervised Learning Framework with Chaotic Transformation for Medical Image Classification","abstract":"Self-Supervised Learning (SSL) has emerged as a powerful paradigm to mitigate the reliance on large, annotated datasets, a common bottleneck in medical image analysis. However, standard SSL methods, which rely on simple geometric and color augmentations, may fail to capture the fine-grained, complex textural details necessary for classifying subtle pathologies. This paper introduces Chaos-SSL, a novel two-stage framework for medical image classification. In the first stage, we propose a new self-supervised pre-training strategy that leverages 1D chaotic maps (Logistic, Tent, and Sine) as a complex, non-linear augmentation for contrastive learning. We hypothesize that these chaotic transformations create ``harder'' and more semantically-rich views, forcing a network to learn robust representations of fine-grained medical textures. In the second stage, we introduce an attention-based fusion model that dynamically combines the specialized features from our Chaos-SSL model with the general-purpose features of a larger, ImageNet-pre-trained model. We validate our method on two public datasets: ISIC 2018 (skin lesions) and APTOS 2019 (diabetic retinopathy). Our results demonstrate that the Chaos-SSL model pre-trained with a Tent map for 30 epochs, followed by attention fusion, achieves performance fully competitive with the state-of-the-art, yielding an accuracy of 0.9261 on ISIC 2018 and 0.8726 on APTOS 2019. This significantly outperforms existing SSL methods, including several recent approaches.","authors":["Joao Batista Florindo"],"published":"2026-05-26T15:10:00Z","updated":"2026-05-26T15:10:00Z","abstract_url":"https://arxiv.org/abs/2605.27146v1","html_url":"https://arxiv.org/html/2605.27146v1","pdf_url":"https://arxiv.org/pdf/2605.27146v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":34356,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Self-Supervised Learning (SSL) has emerged as a powerful paradigm to mitigate the reliance on large, annotated datasets, a common bottleneck in medical image analysis. However, standard SSL methods, which rely on simple geometric and color augmentations, may...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:07+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27144v1","title":"Is an Image Also Worth 16x16=256 Superpixels? A Framework for Attentional Image Classification","abstract":"Superpixel-based image classification has traditionally leveraged graph neural networks (GNNs) for processing irregular image representations. Recent advances in computer vision, driven by Vision Transformers (ViTs), have introduced new paradigms in self-attentional models, surpassing convolutional neural networks (CNNs) in various tasks. However, a synergistic connection between GNNs, superpixels, and transformers remains unexplored. In this work, we propose Superpixel Transformers (SPT), a novel framework that unifies superpixel-based image classification and ViTs. SPT generalizes the Superpixel Image Classification with Graph Attention Networks (SICGAT) model and ViT to support arbitrary superpixel-based chunking strategies, connectivity graphs, and positional encodings. We introduce refinements including a multidimensional sine-cosine positional encoding and an enriched patch data structure that fully incorporates superpixel shape and color information. By testing SPT across datasets such as CIFAR10, FashionMNIST, and Imagenette, with various superpixel generation and graph connectivity strategies, we demonstrate that SPT achieves superior performance compared to previous superpixel-based GNN methods and remains competitive with ViTs. Notably, our approach addresses the limitations of SICGAT, such as information loss during pixel aggregation, and shows how constrained graph connectivity can enhance ViT performance. SPT bridges the gap between superpixel-based and transformer models, opening avenues for cross-domain generalization and future innovations in hybrid attentional frameworks, and showing that an image can also be worth $16\\times16$ superpixels.","authors":["Pedro Henrique da Costa Avelar","Anderson R. Tavares","Luís C. Lamb"],"published":"2026-05-26T15:09:46Z","updated":"2026-05-26T15:09:46Z","abstract_url":"https://arxiv.org/abs/2605.27144v1","html_url":"https://arxiv.org/html/2605.27144v1","pdf_url":"https://arxiv.org/pdf/2605.27144v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":68023,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Superpixel-based image classification has traditionally leveraged graph neural networks (GNNs) for processing irregular image representations. Recent advances in computer vision, driven by Vision Transformers (ViTs), have introduced new paradigms in self-atte...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-05-27T05:12:08+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27139v1","title":"Unsupervised Deep Image Prior for Sparse-View and Limited-Angle Electron Tomography","abstract":"Electron tomography (ET) plays an important role in the three-dimensional (3D) characterization of nanomaterials. However, under limited-angle and sparse-view conditions, conventional algorithms produce degraded reconstructions, which compromise the quality and interpretability of resulting 3D data. In this paper, we present deep image prior (DIP), an unsupervised deep learning (DL) approach, for highly degraded tomography acquisitions and demonstrate, using simulated data, that its performance is comparable to that of supervised approaches requiring training datasets, even for tilt ranges as limited as 60° and tilt increments of 10°. We then apply it to experimental data and show that it enables reliable 3D quantification under both sparse-view and limited-angle conditions, highlighting its potential for a wide range of materials and acquisition modalities.","authors":["Serge Brosset","Daniel del Pozo Bueno","Thomas David","Laure Guetaz","Philippe Ciuciu","Zineb Saghi"],"published":"2026-05-26T15:07:01Z","updated":"2026-05-26T15:07:01Z","abstract_url":"https://arxiv.org/abs/2605.27139v1","html_url":"https://arxiv.org/html/2605.27139v1","pdf_url":"https://arxiv.org/pdf/2605.27139v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":955,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Electron tomography (ET) plays an important role in the three-dimensional (3D) characterization of nanomaterials. However, under limited-angle and sparse-view conditions, conventional algorithms produce degraded reconstructions, which compromise the quality a...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-05-27T05:12:08+00:00","status":"fallback"},"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27136v1","title":"Leveraging Visual Signals for Robust Token-Level Uncertainty in Vision-Language Generation","abstract":"Uncertainty quantification (UQ) remains a critical challenge in Large Vision Language Models (LVLMs) for reliable predictions and real-world deployment. However, most existing methods are adapted from the LLM literature and primarily focus on the language modality, leaving the contribution of visual information to LVLM uncertainty largely underexplored. In this paper, we investigate how LVLMs process visual information and whether this process can be used to improve uncertainty estimation. By analyzing hidden representations after the integration of visual features during the generation process, we observe that high-confidence predictions rely more heavily on visual content than uncertain ones. Building on this insight, we propose Visual-Grounded Token UQ (VIG-TUQ), a training-free framework that explicitly incorporates visual grounding into uncertainty estimation by weighting token-level language uncertainty with visual grounding scores. We evaluate VIG-TUQ on multiple datasets and across diverse LVLM architectures, including early-fusion, late-fusion, and native-fusion models. Results indicate that our method often improves upon existing token-level uncertainty approaches. Code and data will be made available upon acceptance.","authors":["Joseph Hoche","David Brellmann","Gianni Franchi"],"published":"2026-05-26T15:04:55Z","updated":"2026-05-26T15:04:55Z","abstract_url":"https://arxiv.org/abs/2605.27136v1","html_url":"https://arxiv.org/html/2605.27136v1","pdf_url":"https://arxiv.org/pdf/2605.27136v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27135v1","title":"Do Modern Post-Hoc Watermarking Methods Beat Broken-Arrows?","abstract":"With the rapid proliferation of generative models, such as diffusion models, digital watermarking has emerged as a crucial solution for identifying AI-generated images. Modern post-hoc watermarking schemes use neural networks to achieve an extremely low false-alarm rate while remaining robust to common image transformations. However, there is a lack of comparison between these modern methods and classic ones, particularly in real-world scenarios where robustness and security take precedence over achieving an extremely low false-alarm probability. In this paper, we propose a fair comparison of robustness and security between modern and classic post-hoc watermarking across various types of classic augmentations and recent sophisticated attacks. Our experiments show that, in a realistic scenario, classic watermarking outperforms modern techniques in terms of security while maintaining robustness.","authors":["Enoal Gesny","Eva Giboulot"],"published":"2026-05-26T15:04:46Z","updated":"2026-05-26T15:04:46Z","abstract_url":"https://arxiv.org/abs/2605.27135v1","html_url":"https://arxiv.org/html/2605.27135v1","pdf_url":"https://arxiv.org/pdf/2605.27135v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27129v1","title":"YOLO26-RipeLoc Lite: A lightweight architecture for tomato ripeness detection and picking point localization in greenhouse robotic harvesting","abstract":"In greenhouse tomato production, automated harvesting requires accurate detection of ripe tomatoes, ripeness classification, and precise picking-point localization for robotic end-effectors. This paper proposes YOLO26-RipeLoc Lite, a lightweight deep learning architecture based on YOLO26 for simultaneous detection, ripeness classification, and center-point localization of greenhouse tomatoes. The model introduces three modifications: (1) a Lightweight Feature Pyramid Network (LFPN) with depthwise separable convolutions for efficient multi-scale fusion, (2) a Ripeness-Aware Attention Module (RAAM) with dual pooling and a learnable ripeness bias vector for enhanced color-texture discrimination, and (3) a Compact Detection Head (CDH) with shared convolutions and an integrated center-point regression branch for direct grasp planning. The model is evaluated on a custom dataset of 1,500 images with 6,227 instances (3,566 ripe, 2,661 unripe) from the SILAL greenhouse, Abu Dhabi, UAE. YOLO26-RipeLoc Lite achieves mAP@0.5 of 92.9% (95.2% ripe, 90.6% unripe) with the highest precision (95.2%) among all evaluated architectures using only 2.38M parameters. Post-training BatchNorm pruning at 30% reduces parameters to ~1.8M with negligible accuracy loss. Ablation studies confirm that greenhouse-aware HSV augmentation provides the largest improvement (+2.02 pp mAP@50), backbone freezing achieves peak precision (93.8%), and 3-phase progressive unfreezing yields the best localization quality (mAP@50:95 of 64.6%). Comparisons with YOLOv8n/s, YOLO11n/s, YOLO12n/s, and YOLO26s confirm superior accuracy-efficiency: 2.9 pp higher precision than YOLO12n with 7.0% fewer parameters and integrated center-point localization for robotic end-effector guidance.","authors":["Rajmeet Singh","Manveen Kaur","Shahpour Alirezaee","Irfan Hussain"],"published":"2026-05-26T15:00:24Z","updated":"2026-05-26T15:00:24Z","abstract_url":"https://arxiv.org/abs/2605.27129v1","html_url":"https://arxiv.org/html/2605.27129v1","pdf_url":"https://arxiv.org/pdf/2605.27129v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27116v1","title":"COVD: Continual Open-Vocabulary Object Detection with Novel Concept Injection","abstract":"Open-vocabulary object detection (OVD) has made significant progress, enabling detectors to generalize from seen to unseen categories. However, real-world category spaces continually evolve, and existing OVD models still struggle with newly emerging concepts, while repeated full retraining is prohibitively expensive. To this end, we introduce a new task setting, termed Continual OVD with Novel Concept Injection (COVD), where models sequentially learn incoming novel concept groups while preserving prior concepts and original open-vocabulary knowledge, along with a new benchmark, Novel-114. Our key observation is that pretrained visual encoders often already perceive and represent many novel concepts, and the main bottleneck lies in the lack of stable semantic alignment between visual representations and textual concepts. Based on this, we propose NoIn-Det, an efficient continual injection framework without additional parameters. NoIn-Det freezes the visual encoder, preserves the text representation space using only texts of common concepts and previously injected concepts, and injects novel concepts by updating only a small subset of text-branch parameters beneficial to novel concept learning. Extensive experiments show that NoIn-Det effectively learns novel concepts, preserves old knowledge, and consistently outperforms existing continual learning methods for VLMs without introducing additional parameters.Novel-114 and the code will be released.","authors":["Yupeng Zhang","Ruize Han","Yuzhong Feng","Zixin Ren","Yuntong Tian","Liang Wan"],"published":"2026-05-26T14:53:14Z","updated":"2026-05-26T14:53:14Z","abstract_url":"https://arxiv.org/abs/2605.27116v1","html_url":"https://arxiv.org/html/2605.27116v1","pdf_url":"https://arxiv.org/pdf/2605.27116v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27102v1","title":"JLT: Clean-Latent Prediction in Latent Diffusion Transformers","abstract":"Flow matching with clean-data prediction has shown that regressing the clean point can exploit low-dimensional structure more effectively than predicting an ambient noised quantity. We ask whether this principle remains useful after images are mapped into a learned latent space, where compression has already removed much of the raw pixel variability. We introduce JLT, a 130M latent diffusion Transformer over frozen FLUX.2 VAE codes, and compare clean-latent prediction with a matched velocity-prediction DiT under the same representation, backbone, and training settings. Although the three variables x, epsilon, and v are linearly convertible for a fixed corruption time, a local Gaussian analysis shows that velocity regression inherits an isotropic target-covariance floor and amplifies low-variance latent directions, while clean prediction damps them. On ImageNet 256 x 256, JLT-B/1 obtains FID-50K 2.50 with classifier-free guidance, with a large matched-target gap over velocity prediction. These results suggest that prediction targets in latent diffusion are representation-dependent geometric choices, rather than interchangeable algebraic parameterizations.","authors":["Funing Fu","Tenghui Wang","Junyong Cen","Qichao Zhu","Guanyu Zhou"],"published":"2026-05-26T14:41:58Z","updated":"2026-05-26T14:41:58Z","abstract_url":"https://arxiv.org/abs/2605.27102v1","html_url":"https://arxiv.org/html/2605.27102v1","pdf_url":"https://arxiv.org/pdf/2605.27102v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27101v1","title":"Pop-Up Distractions Reveal Bag-of-Events Behavior in Video Large Language Models","abstract":"A key capability for video understanding is reliably linking subjects to events across time, yet whether Video Large Language Models (VideoLLMs) actually achieve this remains unclear. In this work, we introduce DistractionBench to evaluate whether VideoLLMs can robustly link subjects and events in the presence of unrelated video segments. Through controlled interventions, such as inserting short advertisement clips into longer videos, we show that VideoLLMs frequently hallucinate interactions between entities from different segments, incorrectly attributing actions from injected advertisements to subjects in the main video. We characterize this systematic hallucination as bag-of-events (BoE) behavior, where models process videos as collections of events rather than temporally structured sequences. Evaluating 11 popular VideoLLMs, we find that all models exhibit substantial BoE behavior. Our findings suggest that VideoLLMs lack reliable mechanisms for temporal grounding and motivate the development of models with more robust subject-event association.","authors":["Oscar Chew","Serhii Honcharenko","Qian-Hui Chen","Patricia Lu","Dishant Zaveri","Khoa D. Doan","Kuan-Hao Huang"],"published":"2026-05-26T14:41:05Z","updated":"2026-05-26T14:41:05Z","abstract_url":"https://arxiv.org/abs/2605.27101v1","html_url":"https://arxiv.org/html/2605.27101v1","pdf_url":"https://arxiv.org/pdf/2605.27101v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27080v1","title":"Semi-Supervised Gaze Estimation via Disentangled Subspace Contrastive Learning","abstract":"Appearance-based gaze estimation always suffers from poor generalization due to limited annotated samples and insufficient dataset diversity. Leading approaches adopt weakly supervised learning to generate large-scale pseudo-labeled data from unconstrained real-world scenarios, aiming to mitigate the domain shifts. In this work, we devise a simple yet effective semi-supervised learning architecture that leverages unlabeled data to enhance domain generalization, thereby reducing reliance on labor-intensive manual annotations. Our key insight is to impose Jacobian regularization to disentangle feature representations into discriminative subspaces dedicated to specific gaze components, such as pitch and yaw angles. We further exploit the intrinsic ordinal ranking within each subspace for contrastive learning, enabling the model to learn robust gaze representations from a small set of labeled samples and an abundance of unlabeled ones. This ultimately yields our Disentangled Subspace Contrastive Learning (DSCL) framework. Extensive experiments on multiple benchmarks verify that the proposed DSCL is plug-and-play, achieving competitive performance using only 20\\%, 10\\%, and even 5\\% of the annotated data under both in-domain and cross-domain evaluation settings. The public code is available at \\href{https://github.com/da60266/DSCL}{https://github.com/da60266/DSCL}.","authors":["Qida Tan","Hongyu Yang","Wenchao Du"],"published":"2026-05-26T14:31:10Z","updated":"2026-05-26T14:31:10Z","abstract_url":"https://arxiv.org/abs/2605.27080v1","html_url":"https://arxiv.org/html/2605.27080v1","pdf_url":"https://arxiv.org/pdf/2605.27080v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27075v1","title":"SoftCap: Soft-Budget Control for Diffusion Transformer Acceleration","abstract":"Diffusion Transformers (DiTs) achieve strong visual quality, but their iterative denoising process requires many costly Transformer evaluations. Training-free acceleration methods reduce this cost by caching, forecasting, or verifying intermediate features, yet the runtime decision of when to execute a Full step is often driven by fixed schedules or hand-tuned thresholds. We propose \\textbf{SoftCap}, a training-free control layer for cache-based DiT inference. SoftCap couples a Trajectory Drift Observer, which estimates local cache risk from lightweight hidden-state statistics, with a Soft-Budget PI Controller, which adjusts the Full-triggering threshold from realized compute relative to a fixed reference profile. The budget is a soft ceiling: it shapes the threshold but does not require a run to spend a prescribed number of Full evaluations. On FLUX.1-dev, SoftCap improves over SpeCa at a comparable middle-compute operating point, raising ImageReward from 0.967 to 0.981 and reducing LPIPS-Full from 0.518 to 0.498 at nearly identical FLOPs, while target-sweep diagnostics show the intended soft-ceiling behavior as the budget is relaxed.","authors":["Yuhang Zhang","Junxiang Qiu","Huixia Ben","Zhenhua Tang","Shuo Wang","Yanbin Hao"],"published":"2026-05-26T14:24:48Z","updated":"2026-05-26T14:24:48Z","abstract_url":"https://arxiv.org/abs/2605.27075v1","html_url":"https://arxiv.org/html/2605.27075v1","pdf_url":"https://arxiv.org/pdf/2605.27075v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27074v1","title":"IPIBench: Evaluating Interactive Proactive Intelligence of MLLMs under Continuous Streams","abstract":"Recent multimodal large language models (MLLMs) achieve strong performance on reactive question answering, but real-world streaming assistants require proactive reasoning over continuous visual inputs. Existing benchmarks mainly study reactive or proactive interactions in isolated single-turn settings, overlooking dynamic multi-turn scenarios where users may add, modify, or cancel proactive requests alongside interleaved reactive queries. To address this gap, we introduce IPIBench, the first benchmark for evaluating Interactive Proactive Intelligence of MLLMs under streaming video settings. IPIBench covers proactive monitoring, proactive task management, and interleaved reactive-proactive requests. Evaluations on representative MLLMs reveal two major limitations: unstable proactive triggering and weak coordination between reactive and proactive behaviors. We further propose IPI-Agent, a training-free agentic framework with an interaction-control policy and a temporal-gating mechanism for stabilizing proactive triggering and coordinating multi-turn interactions. Experiments show that IPI-Agent consistently improves existing MLLMs across all benchmark settings.","authors":["Jinzhao Li","Yinuo Chen","Wenxuan Song","Yijia Lei","Yichi Zhang","Honglei Yan","Panwang Pan","Miao Liu"],"published":"2026-05-26T14:23:25Z","updated":"2026-05-26T14:23:25Z","abstract_url":"https://arxiv.org/abs/2605.27074v1","html_url":"https://arxiv.org/html/2605.27074v1","pdf_url":"https://arxiv.org/pdf/2605.27074v1.pdf","matched_keywords":["video","agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27067v1","title":"BEAT: Rhythm-Elastic Alignment for Agentic Music-guided Movie Trailer Generation","abstract":"Automatic movie trailer generation must select shots from a full-length film and synchronize them with background music. Existing methods either relegate music alignment to post-processing or enforce rigid one-to-one shot-music mappings, overlooking that professional editing rhythm is elastic: rapid cuts accompany high-energy passages while sustained shots span quieter bars. We introduce BEAT, a framework that addresses this gap with two core components: MuVA, a compact music-visual alignment encoder trained with Sinkhorn-regularized two-stage learning, and Bar-DP, an energy-adaptive dynamic programming algorithm that produces elastic many-to-one alignments following musical dynamics. These components are integrated into a five-phase agentic pipeline that grounds the core alignment in learned cross-modal features while coordinating higher-level creative decisions through structured text signals. To support comprehensive evaluation, we also introduce TrailerArena, a benchmark with 20+ metrics across four complementary dimensions. On TrailerArena, BEAT achieves state-of-the-art performance across shot selection, ordering, and perceptual quality, while producing fully composed trailers end-to-end.","authors":["Yutong Wang","Yunke Wang","Xinyuan Chen","Chang Xu"],"published":"2026-05-26T14:18:13Z","updated":"2026-05-26T14:18:13Z","abstract_url":"https://arxiv.org/abs/2605.27067v1","html_url":"https://arxiv.org/html/2605.27067v1","pdf_url":"https://arxiv.org/pdf/2605.27067v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27032v1","title":"SCKAN: Structural Consensus-based KAN Prototype Learning for Semi-Supervised Pancreas Segmentation","abstract":"Accurate pancreas segmentation is critical for early cancer diagnosis, where annotation scarcity necessitates Semi-Supervised Learning (SSL). However, due to significant inter-sample morphological variability, existing SSL methods face severe generalizability limitations under sparse supervision, leading to the Supervision Bias problem. To address this, we propose Structural Consensus-based KAN Prototype Learning (SCKAN), which constructs the first cross-sample structural consensus learning with Kolmogorov-Arnold Networks (KANs), to achieve more generalizable and accurate segmentation. Specifically, SCKAN contains two key designs: Structure-constrained Prototype Consistency Learning (SPCL), which prompts unbiased structural representation by enforcing cross-sample consistency via prototype-level contrastive optimization, and Consensus-based Kolmogorov-Arnold Fusion (CKaF), which reduces morphology-specific bias by aggregating stable consensus and filtering sample-wise noise via KAN's adaptive B-spline nonlinearity. Extensive experiments on two public pancreas datasets demonstrate the effectiveness of SCKAN. Code is at https://github.com/rhodaliu17/SCKAN.","authors":["Yuqi Liu","Yufei Chen","Wei Fu","Xiaodong Yue","Shuo Li"],"published":"2026-05-26T13:53:45Z","updated":"2026-05-26T13:53:45Z","abstract_url":"https://arxiv.org/abs/2605.27032v1","html_url":"https://arxiv.org/html/2605.27032v1","pdf_url":"https://arxiv.org/pdf/2605.27032v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27024v1","title":"NeR-SC: Adapting Neural Video Representation to Screen Content","abstract":"Implicit neural representations have emerged as a promising paradigm for video compression, with recent methods achieving competitive performance on natural video. However, screen content video -- common in remote desktop, online education, and cloud gaming -- exhibits distinct statistics: sharp edges, limited color palettes, and strong temporal redundancy. Existing neural representation methods, designed for natural scenes, lack mechanisms to exploit these properties, leaving substantial room for improvement. In this paper, we propose NeR-SC, a neural representation framework tailored for screen content video. Building on the SNeRV backbone, NeR-SC introduces three screen-content-specific modules: (i) a learnable color palette that models the discrete color structure of screen content by restricting the low-frequency sub-band to a learned color set; (ii) a multi-gate dense fusion module that replaces sequential feature fusion with dense, attention-gated cross-stage interaction; and (iii) an embedding-level frame skip strategy that bypasses redundant decoder invocations for static frames, with zero training overhead. Experiments on DSCVC and VCD show that NeR-SC achieves 40.32~dB and 41.73~dB average PSNR, outperforming representative neural video representation methods and, at low bitrates, surpassing H.264 and H.265. The skip strategy enables real-time decoding with no loss in quality.","authors":["Ruohan Shi","Jiaoyan Zhao","Haogang Feng"],"published":"2026-05-26T13:43:50Z","updated":"2026-05-26T13:43:50Z","abstract_url":"https://arxiv.org/abs/2605.27024v1","html_url":"https://arxiv.org/html/2605.27024v1","pdf_url":"https://arxiv.org/pdf/2605.27024v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27020v1","title":"Black-box Membership Inference Attacks on the Pre-training Data of Image-generation Models","abstract":"The rapid advancement of diffusion-based image generation models has raised serious concerns regarding potential copyright and privacy infringements involving human-created data. Membership inference attacks (MIAs) have emerged as a promising tool for identifying unauthorized data usage during model training. Existing methods typically assess the ability of model to denoise perturbed suspect images as an indicator of membership status. However, the discriminative power of such features is highly dependent on the degree of model memorization and deteriorates significantly when applied to less exposed data (e.g., pre-training data). Although several methods attempt to enhance detection by leveraging internal model features, these features are generally inaccessible in mainstream closed-source image generation platforms, limiting their practicality. In this paper, we demonstrate that analyzing how a black-box diffusion model denoises a target image and corresponding perturbed textual instructions can reveal more distinctive membership cues. Based on this insight, we propose a black-box membership inference attack framework (named SD-MIA) that leverages a cross-modal data perturbation mechanism to detect pre-training data in diffusion models. We conduct extensive experiments on both a public benchmark dataset and a newly constructed dataset, each comprising pre-training membership and non-membership samples with identical distributions. Experimental results demonstrate that SD-MIA achieves superior performance compared to existing baselines, including those with the unfair advantage of accessing internal model features.","authors":["Tao Qi","Huili Wang","Yuanhong Huang","Wendan Wang","Lianchao Zhao","Jinrui Wang","Zichen Qin","Shangguang Wang","Yongfeng Huang"],"published":"2026-05-26T13:38:25Z","updated":"2026-05-26T13:38:25Z","abstract_url":"https://arxiv.org/abs/2605.27020v1","html_url":"https://arxiv.org/html/2605.27020v1","pdf_url":"https://arxiv.org/pdf/2605.27020v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.27003v1","title":"Timestep-Aware SVDQuant-GPTQ for W4A4 Quantization of Wan2.2-I2V","abstract":"W4A4 quantization of large video diffusion Transformers offers substantial memory savings but is hindered by two main challenges: sparse large-magnitude activation outliers, and strongly timestep-dependent activation distributions across the multi-step denoising trajectory. These difficulties are compounded by Wan2.2-I2V's two-expert Mixture-of-Experts DiT design, whose high-noise and low-noise experts exhibit distinct quantization sensitivities that a single global calibration policy cannot capture. We propose a post-training quantization framework combining SVDQuant-based low-rank outlier compensation, GPTQ-based reconstruction-aware residual weight quantization, and timestep-bin-wise per-layer activation clipping-ratio search conducted independently for each expert. On the OpenS2V-Eval benchmark, our method reduces peak GPU memory by 59.3\\% relative to the BF16 baseline while incurring only a 0.9\\% drop in VBench average score and a 2.3\\% drop in Imaging Quality, demonstrating that expert- and timestep-aware calibration is essential for high-fidelity W4A4 inference on MoE video DiTs.","authors":["Junhao Wu","Dezhong Yao","Hai Jin"],"published":"2026-05-26T13:24:01Z","updated":"2026-05-26T13:24:01Z","abstract_url":"https://arxiv.org/abs/2605.27003v1","html_url":"https://arxiv.org/html/2605.27003v1","pdf_url":"https://arxiv.org/pdf/2605.27003v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26994v1","title":"ChartAct: A Benchmark for Dynamic Chart Understanding","abstract":"Charts are widely used to present complex data for analysis and decision making. Existing chart understanding benchmarks mainly focus on static charts, but real-world charts are often dynamic and interactive. Key information may only appear after actions such as hovering, clicking, zooming, or dragging. Dynamic chart understanding therefore requires models to identify visible content, choose proper interactions, and reason over changing chart states. To evaluate this ability, we propose ChartAct, an interactive benchmark for dynamic chart understanding. ChartAct collects and filters 673 dynamic charts from 8 real chart websites, covers 7 common chart types, and constructs 1,440 high-quality question-answer samples. Each sample is instantiated in two environments, Dynamic Chart and Dashboard Chart, to evaluate dynamic chart understanding under different contexts. Based on ChartAct, we systematically evaluate 11 advanced multimodal models and GUI agents. Experimental results show that existing models still have clear limitations in dynamic chart understanding. The strongest model, Claude-Opus-4.7, achieves an average success rate of 84.5\\%, while most models remain below 60\\%. We also conduct detailed failure attribution and case analysis. ChartAct provides a new benchmark for studying chart understanding in real interactive environments. Codes at https://github.com/wulin-wulin/OSWorld_Chart","authors":["Muye Huang","Wu Lin","Lingling Zhang","Hang Yan","Zhiyuan Wang","Yumeng Fu","Zesheng Yang","Jun Liu"],"published":"2026-05-26T13:15:21Z","updated":"2026-05-26T13:15:21Z","abstract_url":"https://arxiv.org/abs/2605.26994v1","html_url":"https://arxiv.org/html/2605.26994v1","pdf_url":"https://arxiv.org/pdf/2605.26994v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26992v1","title":"On the Robustness of Machine Unlearning for Vision-Language Models","abstract":"Vision-language models (VLMs) may memorize undesirable information from training data, motivating growing interest in machine unlearning. In this work, we present the first systematic survey and robustness analysis of VLM unlearning. We provide a comprehensive taxonomy and review of existing VLM unlearning methods, together with unified evaluations under multiple prompt settings. We then propose three attack paradigms to examine whether forgotten multimodal knowledge can be reactivated through contextual prompting or downstream retraining. Extensive experiments show that many existing methods remain vulnerable under these attacks, indicating that current approaches often hide rather than fully remove target knowledge. Our study provides new insights into the robustness and limitations of current VLM unlearning methods and highlights the need for more reliable multimodal unlearning strategies. Code is available at https://github.com/XMUDeepLIT/VLM-UnL-Attack.","authors":["Yujie Lin","Kaidi Jia","Jiayao Ma","Chengyi Yang","Jinsong Su"],"published":"2026-05-26T13:14:12Z","updated":"2026-05-26T13:14:12Z","abstract_url":"https://arxiv.org/abs/2605.26992v1","html_url":"https://arxiv.org/html/2605.26992v1","pdf_url":"https://arxiv.org/pdf/2605.26992v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26967v1","title":"CodecCap: High-Fidelity Codec-Inspired Residual Modeling for Dense Video Captioning","abstract":"Existing video captioning methods struggle to balance visual fidelity and redundancy: holistic captions are compact but lose fine-grained evidence, whereas segment-wise captions improve coverage but introduce heavy redundancy. We propose CodecCap, a codec-inspired framework for high-fidelity dense video captioning. Analogous to video codecs, CodecCap represents videos using keyframe and residual captions. Keyframe captions exhaustively encode stable visual context, while residual captions capture temporally only localized actions, motions and changes. This effectively preserves fine-grained visual evidence while reducing redundant descriptions. To quantify the fidelity of captions, we introduce VidCapQA, a caption-then-QA benchmark with 1,000 questions across 14 capability dimensions. Results on VidCapQA show that captions directly generated by strong VLMs still miss many visual details, highlighting caption representation as a critical bottleneck. Experiments show that CodecCap significantly surpasses direct captioning with the same underlying VLMs, suggesting keyframe-residual captioning a way for high-fidelity video-language supervision. We further use CodecCap to construct CodecVDC-100K, a large-scale dense captioning dataset with anchor, residual, scene-level, and video-level supervision.","authors":["Zihan Lin","Songhe Deng","Shuwei He","Danxiang Zhu","Dan Zhang","Yishu Lei","Xianlong Luo","Shikun Feng","Rui Liu"],"published":"2026-05-26T12:53:55Z","updated":"2026-05-26T12:53:55Z","abstract_url":"https://arxiv.org/abs/2605.26967v1","html_url":"https://arxiv.org/html/2605.26967v1","pdf_url":"https://arxiv.org/pdf/2605.26967v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26949v1","title":"DinoComplete: 3D Shape Completion with Distilled Semantic Priors and State Space Models","abstract":"3D shape completion from partial scans remains challenging for unseen categories and noisy real-world observations, where geometry alone is often insufficient for inferring missing structure. We present DinoComplete, a deterministic and efficient shape completion framework that augments geometric reconstruction with voxel-aligned semantic priors distilled from DINO features. First, we construct multi-view DINO feature volumes aligned with ShapeNet data and train a student network to predict dense semantic features directly from incomplete shapes. These predicted features capture global structure and part-aware semantic context while remaining aligned with the underlying geometry. We then integrate these distilled features into a completion network, where geometric and semantic voxel representations are fused through voxel state-space modeling. To enable efficient long-range reasoning without sacrificing resolution, we introduce a multi-scale voxel Mamba module that refines the fused features by combining full-grid and chunk-wise sequence modeling. Experiments on unseen ShapeNet categories and ScanNet objects show that DinoComplete achieves stronger completion quality than prior deterministic and generative based completion methods while using fewer parameters, requiring lower memory, and achieving faster inference. Our results demonstrate that distilling semantic priors from visual foundation models improves generalization and robustness in 3D shape completion.","authors":["Furkan Mert Algan","Eckehard Steinbach"],"published":"2026-05-26T12:40:52Z","updated":"2026-05-26T12:40:52Z","abstract_url":"https://arxiv.org/abs/2605.26949v1","html_url":"https://arxiv.org/html/2605.26949v1","pdf_url":"https://arxiv.org/pdf/2605.26949v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26944v1","title":"Object Pose and Shape Estimation for Grasping: Does it Work?","abstract":"The problem of object pose and shape estimation has seen key advancements lately. Encoder-decoder (e.g., SAM3D, LRM, CRISP) and diffusion-based models (e.g., InstantMesh, Zero123, SceneComplete) have shown category-agnostic shape encoding capacity and open-set generalizability. In this work, we ask the question: Are the object pose and shape estimation methods mature enough, such that when used with antipodal grasp sampling, can outperform the end-to-end grasp synthesis methods? We explore this question in detail by scoping our study to parallel jaw grippers, 7-DoF grasps, and single-view RGB(-D) image as input. We implement and compare a state-of-the-art, end-to-end grasp synthesis method and three modular methods, which first estimate the object pose and shape for all objects in the scene, and generate grasps using antipodal sampling. We observe that the modular methods outperform the end-to-end method in all our experiments. The modular methods are able to synthesize plenty of grasps, even for small objects, where the end-to-end methods fail. The effectiveness of the modular methods is contingent on the accuracy of the pose and shape estimation, and suffers partial degradation in cluttered scenes - a limitation of the existing pose and shape estimation methods. We also analyze the failure modes and run-times for the three modular methods, which use two different ways of object pose and shape estimation: one based on an encoder-decoder model, while another a diffusion model. Finally, we demonstrate that the single-view object pose and shape estimation methods can be augmented with vision-language models to yield language-conditioned grasps from just single-view RGB-D image as input. We notice comparable performance to the state-of-the-art LERF-TOGO baseline.","authors":["Pavan Karke","Kushal Shah","Gaurav Singh","Md Faizal Karim","K Madhava Krishna","Rajat Talak"],"published":"2026-05-26T12:32:50Z","updated":"2026-05-26T12:32:50Z","abstract_url":"https://arxiv.org/abs/2605.26944v1","html_url":"https://arxiv.org/html/2605.26944v1","pdf_url":"https://arxiv.org/pdf/2605.26944v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26933v1","title":"Leveraging Text-to-Image Diffusion Models for Unsupervised Visual Object Tracking","abstract":"Unsupervised visual object tracking is a challenging task that requires following arbitrary targets in videos without training on ground-truth annotations. Despite considerable progress, existing state-of-the-art unsupervised trackers often struggle in scenarios that demand fine-grained understanding of semantic and visual structural information within video frames. Text-to-image diffusion models are well known for their ability to generate images that accurately reflect the semantics and structures described in the input prompt, demonstrating a strong grasp of visual semantics and structures. Building on this capability, we approach the unsupervised tracking from a new perspective by exploiting the rich semantic knowledge encoded in pretrained text-to-image diffusion models. To adapt the diffusion models, which are originally developed for image generation, to the tracking task, we reinterpret the models as a bridge between text and image modalities. This connection is realized through the cross-attention mechanism: when both text and an image are input into the models, they highlight the regions of the image that are semantically aligned with the text in the cross-attention maps. We therefore learn a prompt that represents the tracking target and activates its corresponding region in the cross-attention map for each frame, which enables object tracking with the diffusion model. Specifically, our method Diff-Tracking is composed of two main components: an initial prompt learner and an online prompt updater. The initial prompt learner generates a prompt that captures the target object in the first frame, allowing the diffusion model to identify the target. The online prompt updater refines the prompt based on motion information, enabling consistent tracking across video frames. We evaluate our approach on six challenging tracking datasets demonstrate the effectiveness of our approach.","authors":["Zhengbo Zhang","Zhigang Tu","Junsong Yuan","De Wen Soh","Bo Du"],"published":"2026-05-26T12:26:56Z","updated":"2026-05-26T12:26:56Z","abstract_url":"https://arxiv.org/abs/2605.26933v1","html_url":"https://arxiv.org/html/2605.26933v1","pdf_url":"https://arxiv.org/pdf/2605.26933v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26921v1","title":"Revealing the core dimensions underlying representations in brains, behavior and AI","abstract":"The study of representations is widespread across fields, including neuroscience, psychology, and artificial intelligence. While representations are often studied and compared through similarities between stimuli, current methods provide only limited access to the dimensions that shape these representations and are often limited in interpretability. To overcome these challenges, here we introduce Similarity-Based Representation Factorization (SRF), a general computational method for recovering low-dimensional, non-negative, interpretable embeddings from similarity matrices derived from measured data. Across simulations and many neural, behavioral, and computational datasets, SRF recovers interpretable dimensions from diverse forms of representational data, even for very sparsely sampled, incomplete data. The dimensions derived from these datasets match those obtained by task-specific models, predict independent behavioral properties, improve exploratory analysis, and offer higher power for confirmatory hypothesis testing than comparing similarity matrices. Together, these results establish SRF as a general-purpose method with broad applications for uncovering, understanding, and leveraging the dimensions underlying representations.","authors":["Florian P. Mahner","Ka Chun Lam","Francisco Pereira","Martin N. Hebart"],"published":"2026-05-26T12:19:17Z","updated":"2026-05-26T12:19:17Z","abstract_url":"https://arxiv.org/abs/2605.26921v1","html_url":"https://arxiv.org/html/2605.26921v1","pdf_url":"https://arxiv.org/pdf/2605.26921v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26914v1","title":"I2PRef: Image-Driven Point Completion with Iterative Refinement","abstract":"We present an image-conditioned point cloud completion approach that treats images as the primary geometric source rather than a secondary guide. To this end, we introduce an Image-to-Point (I2P) module that can reconstruct complete point clouds directly from a single RGB image, with no need for 3D inputs. Additionally, we introduce a transformer-based Point-to-Point (P2P) refinement module that uses self- and cross-attention between point tokens and image features to iteratively refine the coarse I2P output. The I2P module enables the image encoder to learn rich geometric representations, while the P2P module progressively recovers fine-grained details. Unlike existing multimodal methods that rely on auxiliary losses or fusion modules, our explicit I2P task provides a strong, geometry-aware prior based on images alone. Extensive experiments on ShapeNet-ViPC demonstrate state-of-the-art completion performance with a 12.3% relative Chamfer Distance improvement over prior methods. Code is available at: https://github.com/AzharSindhi/I2PRef.git","authors":["Azhar Hussian","Marina Ritthaler","André Kaup","Vasileios Belagiannis"],"published":"2026-05-26T12:12:20Z","updated":"2026-05-26T12:12:20Z","abstract_url":"https://arxiv.org/abs/2605.26914v1","html_url":"https://arxiv.org/html/2605.26914v1","pdf_url":"https://arxiv.org/pdf/2605.26914v1.pdf","matched_keywords":["3d","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26884v1","title":"Small Object Detection in Industrial Recycling: A New Dataset and YOLO Performance Evaluation","abstract":"In this paper, we address the problem of detecting small, dense, and overlapping objects, a major challenge in computer vision. Our focus is on reviewing proposed methods based on deep learning supervised approaches. We provide a detailed comparison of these systems on a new dataset of more than 10k images and 120k instances, highlighting their performance, accuracy, and computational efficiency in the industrial recycling process use case. Through this comparative analysis, we identify the most reliable systems currently available and the specific challenges they are designed to tackle. Furthermore, we explore the benefits of data augmentation and synthetic images. Based on our analysis, we also propose potential future directions and innovative solutions that could enhance the effectiveness of small, dense and overlapped object detection systems. The scope of our investigations encompasses object detection, length measurement, and anomaly detection within the context of the recycling process. The anomaly detection strategy is robust against variations in image resolution and zoom levels, ensuring reliable performance in industrial applications. The repository of the proposed dataset, methods and evaluation codes can be found at: https://github.com/o-messai/SDOOD","authors":["Oussama Messai","Abbass Zein-Eddine","Abdelouahid Bentamou","Mickael Picq","Nicolas Duquesne","Stéphane Puydarrieux","Yann Gavet"],"published":"2026-05-26T11:47:31Z","updated":"2026-05-26T11:47:31Z","abstract_url":"https://arxiv.org/abs/2605.26884v1","html_url":"https://arxiv.org/html/2605.26884v1","pdf_url":"https://arxiv.org/pdf/2605.26884v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26879v1","title":"Natural Human Motion Recovery by Aligning High-Order Temporal Dynamics from Monocular Videos","abstract":"Human motion recovered from monocular videos often appears overly smooth or dynamically inconsistent, even when joint positions are numerically accurate. We observe that this limitation stems from the absence of reliable high-order temporal cues -- velocity and acceleration -- which are essential for reconstructing motion that exhibits realistic momentum, timing, and high-frequency detail. We introduce HTD-Refine, a post-processing framework that augments existing Human Motion Recovery (HMR) pipelines using explicitly estimated high-order temporal dynamics. At the core of our system is PVA-Net, a temporal transformer that infers per-joint 2D positions, 3D velocities, and 3D accelerations directly from a monocular video. These predicted dynamics serve as soft yet informative constraints in a global optimization procedure that refines world-space trajectories, significantly reducing jitter, suppressing over-smoothing, and restoring physically plausible motion. Extensive experiments on challenging in-the-wild benchmarks show that HTD-Refine consistently improves state-of-the-art HMR methods, yielding more accurate global trajectories and substantially more natural motion dynamics. Our results highlight the critical role of high-order temporal modeling in advancing monocular human motion recovery.","authors":["Dingkun Wei","Zehong Shen","Yan Xia","Georgios Pavlakos","Yujun Shen","Xiaowei Zhou"],"published":"2026-05-26T11:38:36Z","updated":"2026-05-26T11:38:36Z","abstract_url":"https://arxiv.org/abs/2605.26879v1","html_url":"https://arxiv.org/html/2605.26879v1","pdf_url":"https://arxiv.org/pdf/2605.26879v1.pdf","matched_keywords":["video","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26861v1","title":"REVERSE: Reinforcing Evidence Verification and Search for Agentic Image geo-localization","abstract":"Image geo-localization aims to determine where a photograph was taken, a task that often requires more than recognizing visible landmarks. Human experts typically solve it through an iterative workflow: they inspect informative regions, form location hypotheses, seek external evidence, and revise their judgments as new clues appear. Existing methods only partially capture this process: direct prediction methods bypass evidence acquisition altogether, while retrieval-augmented methods introduce external evidence but usually provide limited supervision on the intermediate decisions of where to search, how to query, and how to filter noisy results. We present REVERSE, a framework that reinforces the interplay between evidence search and verification to enable multi-turn agentic reasoning. REVERSE teaches three intermediate decisions: where to look, what to query, and what evidence to trust. To support this, we construct tool-grounded trajectories with annotated region selections, search observations, and geo-informative evidence labels, and introduce process rewards for visual grounding, query utility, and evidence discrimination. An offline search cache makes retrieval observations stable and reusable during reinforcement learning, enabling dense supervision over noisy search results. With a 4B model, REVERSE outperforms strong retrieval-augmented baselines and rivals substantially larger models on Im2GPS3k and YFCC4k. Code is available at https://github.com/yonglleee/REVERSE.","authors":["Yong Li","Furong Jia","Dacheng Yin","Kang Rong","Fengyun Rao","Jing Lyu","Fan Zhang"],"published":"2026-05-26T11:20:09Z","updated":"2026-05-26T11:20:09Z","abstract_url":"https://arxiv.org/abs/2605.26861v1","html_url":"https://arxiv.org/html/2605.26861v1","pdf_url":"https://arxiv.org/pdf/2605.26861v1.pdf","matched_keywords":["retrieval","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26831v1","title":"OSMa-Bench++: Toward Open-Ended Benchmarking of Semantic Mapping for Manipulation with Prompt-Generated Synthetic Scenes","abstract":"Semantic mapping methods are increasingly used as intermediate scene representations for downstream robotic reasoning and manipulation, yet their evaluation is still largely tied to fixed benchmark datasets with limited coverage of manipulation-relevant corner cases. In this work, we extend OSMa-Bench toward controllable benchmarking with prompt-generated synthetic indoor scenes. Our pipeline automatically generates scene descriptions, synthesizes corresponding environments with SceneSmith, and adapts the resulting assets into an OSMa-Bench-compatible simulation format. This adaptation requires a nontrivial intermediate layer, including semantic normalization, material and texture repair, shader fallback policies, floor handling, navigation setup, and controlled lighting configuration. A key advantage of the proposed setup is that the original scene-generation prompt is known in advance and can therefore serve as an auxiliary semantic specification of the intended scene. We use this property to extend the VQA component of OSMa-Bench with a prompt-grounded question category. The resulting framework supports targeted stress-testing of semantic scene representations under conditions such as clutter, small objects, partial occlusions, and lighting variation, and makes benchmarking more extensible and better aligned with downstream manipulation requirements. Our code is available at https://github.com/be2rlab/OSMa-Bench-v2.","authors":["Regina Kurkova","Maxim Popov","Sergey Kolyubin"],"published":"2026-05-26T10:51:36Z","updated":"2026-05-26T10:51:36Z","abstract_url":"https://arxiv.org/abs/2605.26831v1","html_url":"https://arxiv.org/html/2605.26831v1","pdf_url":"https://arxiv.org/pdf/2605.26831v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26774v1","title":"Cesarean Scar Defect Segmentation in Transvaginal Ultrasound Images: a Dataset and Benchmark","abstract":"Cesarean Scar Defect (CSD) is one of the most prevalent complications following cesarean delivery. Transvaginal ultrasonography is widely used for primary CSD screening. Accurate determination of CSD outline and dimensions is crucial for treatment. However, CSDs are frequently overlooked by sonographers due to small size and irregular morphology, suboptimal image quality, and limited clinical awareness in resource-constrained settings. Despite artificial intelligence advances in medical imaging, no public dataset exists for transvaginal ultrasound CSD segmentation. To address this gap, we present a comprehensive CSD dataset comprising 1,111 images and 16 videos, yielding 501 positive samples with confirmed CSD and precise pixel-level manual annotations. Annotations are performed following standardized clinical guidelines through collaboration between experienced sonographers and trained PhD students. This work provides high-quality benchmark resources for advancing medical image segmentation algorithms and promoting clinical innovation. Ultimately, improved CSD diagnosis and subsequent treatment strategies can enhance the quality of life in women of reproductive age, representing significant value for both medical research and clinical practice.","authors":["Yuan Tian","Yue Li","Wei Xia","Tianyu Xu","Jian Zhang","Liye Shi","Jing Liu","Yang Wang","Ming Liu","Qing Xu","Yixuan Zhang","Maggie M. He","Xiangjian He"],"published":"2026-05-26T09:45:19Z","updated":"2026-05-26T09:45:19Z","abstract_url":"https://arxiv.org/abs/2605.26774v1","html_url":"https://arxiv.org/html/2605.26774v1","pdf_url":"https://arxiv.org/pdf/2605.26774v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26761v1","title":"Once-For-All: A Train-Once and Select-Anytime Framework for Multimodal Instruction Tuning","abstract":"Multimodal instruction tuning is the de facto recipe for adapting vision language models (VLMs), yet instruction data are highly redundant, making data selection critical for training efficiency. Existing methods derive selection signals from a specific model or dataset, so whenever the target model or candidate pool changes, the criteria must be recomputed from scratch at substantial cost. To address this, we propose OFA, a data selection framework that trains a reusable selector once and applies it to any dataset or model without recomputation. OFA clusters multimodal instructions in a frozen CLIP space, derives pseudo labels from the cluster structure, and trains a lightweight selector for only a few epochs; samples on which this selector is least confident are selected as the most informative. Once trained, the frozen selector transfers directly across datasets and model scales. The selector is trained once on LLaVA-665K and applied both to LLaVA-665K itself and, without any retraining, to the unseen Vision-Flan-186K. Selecting only 15% of the data, OFA achieves 98.3% of full data performance across 10 downstream benchmarks; on the smaller Vision-Flan-186K, the transferred selector surpasses full data training by 10.6%, confirming that the learned signal generalizes to datasets never seen during selector training. The same selected subsets benefit VLMs at both Qwen2.5-VL-3B and LLaVA-v1.5-7B without per model recomputation, decoupling selection from the target model. These results demonstrate that a single, transferable selector provides an effective and reusable solution for efficient multimodal instruction tuning.","authors":["Mingkang Dong","Hongyi Cai","Xiwen Lei","Jie Li","Tao Zhang","Muxin Pu"],"published":"2026-05-26T09:31:20Z","updated":"2026-05-26T09:31:20Z","abstract_url":"https://arxiv.org/abs/2605.26761v1","html_url":"https://arxiv.org/html/2605.26761v1","pdf_url":"https://arxiv.org/pdf/2605.26761v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26744v1","title":"Self-Intersection-Aware 3D Human Motion Generation Using an Efficient Human Sphere Proxy","abstract":"Human motion generation has made tremendous progress in recent years, with state-of-the-art approaches surpassing ground truth data in leading evaluation benchmarks. However, visual inspection of the generated motions paints a different picture. Even state-of-the-art approaches generate motions frequently containing self-intersections, i.e., body parts interpenetrating, which are strong artifacts, severely limiting the perceived motion quality. We introduce a novel loss, which explicitly penalizes self-intersections, to the training of human motion generation methods. We base our loss on a sphere proxy of human geometry, which allows us to calculate a self-intersection loss 98% faster and uses 83% less memory than comparable methods based on triangular meshes. The loss is agnostic to the specific approach, and we add it to the training of the recent human motion generation methods human motion diffusion model (MDM) and MoMask. Our extensive experiments show a reduction of self-intersections in generated motions of up to 49% while improving other evaluation metrics. The code is available at https://github.com/boschresearch/humansphereproxy .","authors":["Pascal Herrmann","Maarten Bieshaar","Dennis Mack","Robert Herzog","Juergen Gall"],"published":"2026-05-26T09:17:46Z","updated":"2026-05-26T09:17:46Z","abstract_url":"https://arxiv.org/abs/2605.26744v1","html_url":"https://arxiv.org/html/2605.26744v1","pdf_url":"https://arxiv.org/pdf/2605.26744v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26734v1","title":"CIRCLED: A Multi-turn CIR Dataset with Consistent Dialogues across Domains","abstract":"Existing Multi-Turn Composed Image Retrieval (MTCIR) datasets lack dialogue-history consistency and are restricted to the fashion domain. To address these limitations, we construct CIRCLED by extending FashionIQ, CIRR, and CIRCO. In CIRCLED, the query at each turn progressively approaches the target image. Data are generated via a CIReVL-based retrieval pipeline and curated with multiple filters on retrieval success, turn length, consistency, and information redundancy to ensure quality. In total, we collect 22,608 multi-turn sessions across nine subsets, substantially exceeding Multi-turn FashionIQ (11,505 sessions) in both scale and generality. We further apply multiple baseline methods and quantitatively assess retrieval accuracy on CIRCLED. Our work provides a practical, high-quality benchmark to facilitate future research on multi-turn CIR. The dataset and code are publicly available at https://huggingface.co/datasets/tk1441/CIRCLED and https://github.com/mti-lab/circled.","authors":["Tomohisa Takeda","Yu-Chieh Lin","Yuji Nozawa","Youyang Ng","Osamu Torii","Yusuke Matsui"],"published":"2026-05-26T09:11:15Z","updated":"2026-05-26T09:11:15Z","abstract_url":"https://arxiv.org/abs/2605.26734v1","html_url":"https://arxiv.org/html/2605.26734v1","pdf_url":"https://arxiv.org/pdf/2605.26734v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26725v1","title":"Joint 2D-3D Segmentation and Association in Street-level Imaging","abstract":"Accurate interpretation of street-level imagery is essential for large-scale urban mapping and the creation of Spatial Digital Twin (SDT) environments. This work presents a unified framework for joint 2D-3D segmentation and association that integrates visual semantics with multi-view geometric reasoning. Unlike conventional approaches that rely heavily on sequential frames for temporal tracking, our method leverages zero-shot detection and segmentation together with structure-from-motion reconstruction to establish stable cross-view correspondences. A 3D-driven association mechanism replaces traditional 2D multi-object tracking, using geometric consistency to guide identity preservation across wide-baseline viewpoints and varying imaging conditions. By combining 2D texture cues with global 3D context, the proposed pipeline is well-suited for scalable street-level processing and can be used for a variety of object types. Experiments demonstrate substantially improved coverage of ground-truth sequences and more robust identity retention compared to state-of-the-art 2D-only tracking methods, achieving a 22% performance gain in challenging urban scenarios.","authors":["Amir Melnikov","Masayuki Tanaka","Yusuke Monno","Masatoshi Okutomi"],"published":"2026-05-26T09:04:51Z","updated":"2026-05-26T09:04:51Z","abstract_url":"https://arxiv.org/abs/2605.26725v1","html_url":"https://arxiv.org/html/2605.26725v1","pdf_url":"https://arxiv.org/pdf/2605.26725v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26702v1","title":"Rotation-Invariant Spherical Watermarking via Third-Order SO(3) Representation Coupling","abstract":"Reliable watermarking of panoramic imagery is fundamentally challenged by arbitrary 3D rotations. As panoramas are defined on the sphere, they naturally transform under the action of $SO(3)$, rendering conventional planar representations and augmentation-based robustness strategies inadequate and devoid of theoretical guarantees. To address this, we formulate panoramas as spherical signals and leverage $SO(3)$ representation theory to derive provably rotation-invariant descriptors. While spherical harmonic coefficients transform equivariantly under rotations, the natural invariant constructions are typically limited to zeroth-order statistics which eliminate directional information and severely constrain embedding capacity. In this work, we introduce a principled third-order invariant construction by coupling higher-order $SO(3)$ irreducible representations via tensor products and projecting onto the trivial representation. This yields a spherical invariant bispectrum that preserves phase information while remaining strictly rotation-invariant. Leveraging this property, we embed watermarks into higher-order spherical harmonic coefficients and recover them from invariant bispectral scalars, enabling reliable extraction under arbitrary 3D rotations. We provide a theoretical proof of $SO(3)$ invariance for it and demonstrate experimentally its near-perfect robustness to continuous rotations while maintaining high visual fidelity.","authors":["Pengzhen Chen","Yanwei Liu","Xiaoyan Gu","Antonios Argyriou","Wu Liu","Weiping Wang"],"published":"2026-05-26T08:43:40Z","updated":"2026-05-26T08:43:40Z","abstract_url":"https://arxiv.org/abs/2605.26702v1","html_url":"https://arxiv.org/html/2605.26702v1","pdf_url":"https://arxiv.org/pdf/2605.26702v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26689v1","title":"PinPoint: Prompting with Informative Interior Points","abstract":"Modern referring image segmentation pipelines couple a vision-language model (VLM) for grounding with a promptable segmenter such as the Segment Anything Model (SAM) for mask generation. Prior training-free instances of this recipe consistently trail fine-tuned and reinforcement-learning (RL)-tuned specialists, and it has been unclear whether the gap comes from the VLM's grounding, SAM's capacity, or the prompt. We show that the gap is dominated by prompt ambiguity: a VLM-proposed bounding box (bbox) leaves SAM to guess which pixels inside the bbox belong to the object the expression denotes. Interior points are the natural disambiguator, but where they fall matters; prior work relies on naively sampled points that land on boundaries, distractors, and background clutter, and can even hurt performance compared to the bbox alone. Supervised and RL-tuned methods close this gap by training a VLM to predict better points; we show that this training is unnecessary. At a matched budget of five interior points, replacing naive sampling with stable, informative point selection improves cumulative Intersection-over-Union (cIoU) by 12-18 points across RefCOCO/+/g, with every model fixed. We turn this observation into PinPoint, a deterministic, training-free point selector that fuses four visual cues into a consensus map, selects compact, spatially diverse points away from boundaries, and uses the frozen VLM to label each point. Without any task-specific training, PinPoint matches supervised and RL-tuned specialists on the same stack while issuing only two VLM calls per query.","authors":["Pouya Sadeghi","Shawn He","Pedro Pablo Guerrero Vela","C. Thomas","Alex Wong","Sirisha Rambhatla"],"published":"2026-05-26T08:28:54Z","updated":"2026-05-26T08:28:54Z","abstract_url":"https://arxiv.org/abs/2605.26689v1","html_url":"https://arxiv.org/html/2605.26689v1","pdf_url":"https://arxiv.org/pdf/2605.26689v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26682v1","title":"SteelDS: A High-Resolution Video Dataset of E40 Steel Scrap for Object Detection and Instance Segmentation","abstract":"This dataset provides high-resolution, annotated video sequences of shredded E40-grade steel and copper scrap on a conveyor belt. Captured in a controlled laboratory environment, the data reflects the industrial post-magnetic sorting stage, where manual intervention is typically required to remove copper contaminants. The dataset comprises 24,297 labeled frames across five subsets, featuring 396 steel and 101 copper objects categorized by size. It supports the development of machine learning models for material classification, object detection, and instance segmentation. Variations in object spacing and density are included to simulate realistic industrial sorting conditions. Ground truth annotations include pixel-wise segmentation masks and material classes. This dataset serves as a benchmark for evaluating automated sorting algorithms aiming to identify copper impurities within complex, heterogeneous steel scrap streams.","authors":["Melanie Neubauer","Christian Rauch","Gerald Koinig","Alexia Tischberger-Aldrian","Roland Pomberger","Elmar Rueckert"],"published":"2026-05-26T08:20:12Z","updated":"2026-05-26T08:20:12Z","abstract_url":"https://arxiv.org/abs/2605.26682v1","html_url":"https://arxiv.org/html/2605.26682v1","pdf_url":"https://arxiv.org/pdf/2605.26682v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26680v1","title":"DynFrame: Adaptive Reasoning-Driven Multimodal Framework with Dynamic Frame Augmentation for Complex Video Understanding","abstract":"Recent video multimodal large language models (MLLMs) increasingly couple step-by-step reasoning with on-demand visual evidence retrieval, allowing models to revisit relevant video segments during inference. However, two structural gaps remain in existing thinking-with-video systems. (i) Sampling density is not a learnable decision: existing methods may let the model decide where to look, but the per-window frame rate is largely fixed. As a result, fine-grained evidence is often recovered through repeated retrieval calls, which increases inference context length and training difficulty. (ii) Retrieval and answer generation are usually optimized with a single trajectory-level advantage, so the \"where to look\" tokens and the \"how to answer\" tokens receive the same credit even when one is correct and the other is not. To address these gaps, we present DynFrame, a framework that emits the temporal window and the sampling density as native tokens within a single autoregressive pass. This learnable span-density retrieval enables acquiring multi-granularity evidence with a single retrieval step. Based on the above tokenized retrieval interface, we further introduce Segment-Decoupled GRPO (SD-GRPO), which splits each rollout at the retrieval boundary and assigns role-specific token-level advantages, separately crediting the sampling decision and the answer. Trained on the curated DM-CoT-74k and DM-RL-45k, DynFrame-4B is competitive with strong 7B-8B baselines across six benchmarks (NExT-GQA, Charades-STA, ActivityNet-MR, Video-MME, MLVU, LVBench), and DynFrame-8B sets new state-of-the-art on most metrics. Code is available at https://github.com/zhangguanghao523/DynFrame.","authors":["Peng Zhang","Guanghao Zhang","Wanggui He","Longxiang Zhang","Mushui Liu","Yan Xia","Zhenhao Peng","Weilong Dai","Jinlong Liu","Haobing Tang","Le Zhang","Hao Jiang","Pipei Huang"],"published":"2026-05-26T08:16:16Z","updated":"2026-05-26T08:16:16Z","abstract_url":"https://arxiv.org/abs/2605.26680v1","html_url":"https://arxiv.org/html/2605.26680v1","pdf_url":"https://arxiv.org/pdf/2605.26680v1.pdf","matched_keywords":["video","retrieval","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26656v1","title":"DV-SFT: Direct Vision Supervision for Fine-Grained Visual Understanding","abstract":"Multimodal large language models are typically trained end-to-end to predict ground-truth answers, yet supervision signals are applied exclusively to text tokens. Visual tokens, the core carriers of visual information, are optimized only implicitly as part of the context, leading to coarse-grained visual understanding. Prior works attempt to supervise visual inputs but inevitably rely on auxiliary components such as additional decoders or forward passes, because visual tokens lack readily interpretable labels. This limits their practical applicability. In this work, we propose \\textbf{D}irect \\textbf{V}ision \\textbf{S}upervised \\textbf{F}ine-\\textbf{T}uning (DV-SFT), which constructs explicit, token-level supervision for visual tokens and trains them through the same next-token prediction objective used for text. Specifically, we exploit the direct vision--text correspondence in OCR-related scenarios and automatically label each visual token with the word in its corresponding image patch. DV-SFT treats the MLLM as a black box, requiring no architectural modifications or additional forward passes. Extensive experiments demonstrate the superiority of direct vision supervision. DV-SFT consistently outperforms standard SFT across three in-domain and four out-of-domain benchmarks. Further analyses show that vision supervision effectively enhances fine-grained visual understanding and achieves higher multimodal alignment efficiency.","authors":["Jianfei Zhao","Feng Zhang","Xin Sun","Chong Feng","Bing Wang","Zhixing Tan"],"published":"2026-05-26T07:41:48Z","updated":"2026-05-26T07:41:48Z","abstract_url":"https://arxiv.org/abs/2605.26656v1","html_url":"https://arxiv.org/html/2605.26656v1","pdf_url":"https://arxiv.org/pdf/2605.26656v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26642v1","title":"Adaptation-Free Heterogeneous Collaborative Perception with Unseen Agent Configurations","abstract":"Collaborative perception improves 3D object detection by enabling agents to share complementary observations, but most existing methods assume fixed or known collaborator encoder configurations, limiting deployment in practice. In this work, we consider an open-world setting in which auxiliary agents with unseen configurations may appear after deployment, such as different LiDAR beam counts or encoder architectures. To address this challenge, we propose ALF, a collaborative perception framework that enables zero-adaptation collaboration with unseen agent configurations by lifting lightweight box-level messages into ego-compatible auxiliary features. ALF converts auxiliary box-level messages into pseudo-BEV maps and synthesizes ego-compatible latent features by combining object-centric cues with scene context from the ego feature. On V2X-Real, under a zero-shot evaluation across 64 case studies, ALF outperforms the strongest prior baseline by 35.91% in relative mAP@0.7 while requiring only 120 bytes per agent per frame (approximately 9.6 Kbps bandwidth at 10 Hz).","authors":["Hyunchul Bae","Heejin Ahn"],"published":"2026-05-26T07:26:34Z","updated":"2026-05-26T07:26:34Z","abstract_url":"https://arxiv.org/abs/2605.26642v1","html_url":"https://arxiv.org/html/2605.26642v1","pdf_url":"https://arxiv.org/pdf/2605.26642v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26641v1","title":"OmniRetriever: Any-to-Any Audio-Video-Text Retrieval via Fusion-as-Teacher Distillation","abstract":"Unified multimodal embedding spaces have become the standard interface for cross-modal retrieval and multimodal RAG, and recent audio-video-text (AVT) encoders extend this setting to three modalities. Such encoders can produce a joint (T,V,A) embedding whenever all three modalities are available, but standard pairwise InfoNCE objectives leave this signal unused during training. We close this gap with fusion-as-teacher distillation, which treats a stop-gradient copy of the fused embedding as a teacher signal for the single-modal embeddings, paired with a Tuple-InfoNCE term that supervises the fused embedding directly. We instantiate this objective as OmniRetriever-7B. Across six zero-shot retrieval benchmarks, OmniRetriever-7B surpasses the closed-source Gemini Embedding 2 by 13.3-18.0 R@1 on Clotho and SoundDescs, and reaches the contemporary zero-shot specialist band of open video-text encoders on MSR-VTT and MSVD. To stress-test joint representations, we further release OmniRetriever-Bench, a 12-direction AVT retrieval benchmark totaling 3782 triples; on it OmniRetriever-7B attains AVG-all 34.84, improving over Gemini Embedding 2 by 1.72 and over the best prior open-source AVT method by 8.03.","authors":["Yunze Liu","Chi-Hao Wu","Enmin Zhou","Junxiao Shen"],"published":"2026-05-26T07:26:23Z","updated":"2026-05-26T07:26:23Z","abstract_url":"https://arxiv.org/abs/2605.26641v1","html_url":"https://arxiv.org/html/2605.26641v1","pdf_url":"https://arxiv.org/pdf/2605.26641v1.pdf","matched_keywords":["video","retrieval","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26630v1","title":"Attenuation-Resilient Alternating Optimization for Laparoscopic Liver Landmark Detection","abstract":"Liver surface landmark detection is a fundamental prerequisite for anatomical guidance in laparoscopic liver surgery. However, it remains unreliable in practice due to two pervasive challenges: illumination attenuation in underexposed regions and the structural mismatch between pixel-wise localization and continuous curvilinear geometry. To address these limitations, we propose A2ONet, an attenuation-resilient alternating optimization network for robust liver landmark detection. To mitigate illumination attenuation, A2ONet embraces an illumination field compensation (IFC) block that adaptively enhances dark regions while preserving structural consistency. Meanwhile, we introduce a lightweight frequency-orientation selective filter (FOSF) to suppress repetitive texture interference and preserve salient curvilinear cues. Building upon these resilient representations, we design an alternating seg-curve optimization (ASCO) decoder that iteratively couples dense segmentation with explicit curve modeling, enabling mutual guidance to optimize both structural continuity and endpoint localization. Extensive evaluations on L3D-2K, L3D, and P2ILF demonstrate consistent improvements over competitive methods, establishing a more reliable foundation for intraoperative anatomy guidance. Our code will be available at https://github.com/hyperiondk115/A2ONet.","authors":["Lanqing Liu","Ruize Cui","Jialun Pei","Diandian Guo","Tiffany Y. So","Pheng-Ann Heng","Jing Qin"],"published":"2026-05-26T07:06:10Z","updated":"2026-05-26T07:06:10Z","abstract_url":"https://arxiv.org/abs/2605.26630v1","html_url":"https://arxiv.org/html/2605.26630v1","pdf_url":"https://arxiv.org/pdf/2605.26630v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26629v1","title":"DelowlightSplat: Feed-Forward Gaussian Splatting for Lowlight 3D Scene Reconstruction","abstract":"Novel-view synthesis and 3D reconstruction from sparse posed images are central to robotics and AR/VR. Yet, feed-forward 3D Gaussian reconstruction fails under lowlight due to noise, color shifts, and unreliable correspondence. We propose DelowlightSplat, a lowlight-aware feed-forward Gaussian splatting framework for clean novel-view rendering. We build a controllable multi-view lowlight benchmark by degrading only context views while keeping target views clean. We introduce a lightweight Lowlight Adapter for residual enhancement to improve matchability, and couple it with cost-volume-based multi-view inference to directly predict clean 3D Gaussians. Experiments show that DelowlightSplat significantly outperforms previous feed-forward method and two-stage pipeline under lowlight conditions.","authors":["Fuzhen Jiang","Zengtian Xie","Zhuoran Li"],"published":"2026-05-26T07:05:10Z","updated":"2026-05-26T07:05:10Z","abstract_url":"https://arxiv.org/abs/2605.26629v1","html_url":"https://arxiv.org/html/2605.26629v1","pdf_url":"https://arxiv.org/pdf/2605.26629v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26624v1","title":"MSCGC-KAN: Multi-scale Causal Graph Convolution and Kolmogorov-Arnold Feature Mapping for EEG Emotion Recognition","abstract":"Electroencephalogram (EEG)-based emotion recognition is an important affective computing task, and recent EEG foundation models provide useful generic representations for downstream adaptation. However, under the fine-tuning setting, three limitations remain prominent: insufficient modeling of multi-scale emotional dynamics, inadequate exploitation of inter-channel functional connectivity, and the limited expressive power of simple linear classification heads. To address these issues, this paper proposes a new EEG emotion recognition method, termed MSCGC-KAN, which introduces a structured task head composed of multi-scale causal graph convolution and Kolmogorov--Arnold feature mapping. Built on a pre-trained CBraMod backbone, MSCGC-KAN enhances downstream adaptation by jointly strengthening multi-scale temporal modeling, learnable inter-channel connectivity modeling, and nonlinear discriminative mapping within a compact task-specific head. This design preserves the representation advantage of the foundation model while making the classifier more sensitive to emotion-related spatiotemporal patterns. Extensive experiments are conducted on the public FACED and SEED-VII datasets. The proposed method achieves a balanced accuracy of 60.66\\%, a Cohen's Kappa of 0.5525, and a weighted F1-score of 60.40\\% on FACED, and obtains 33.27\\%, 0.2223, and 33.64\\%, respectively, on SEED-VII. Compared with the CBraMod+Linear baseline, the balanced accuracy is improved by 5.91 and 2.03 percentage points on the two datasets, respectively. These results indicate that structured task-head design is an effective way to improve EEG emotion recognition when fine-tuning pre-trained EEG models.","authors":["Haoliang Gong","Qingshan She","Jiale Xua","Yunyan Gao","Xugang Xi"],"published":"2026-05-26T07:02:13Z","updated":"2026-05-26T07:02:13Z","abstract_url":"https://arxiv.org/abs/2605.26624v1","html_url":"https://arxiv.org/html/2605.26624v1","pdf_url":"https://arxiv.org/pdf/2605.26624v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26621v1","title":"MedVol-R1: Reward-Driven Evidence Grounding for Volumetric Reasoning Segmentation","abstract":"Volumetric Reasoning Segmentation (VRS) aims to segment a target region in a 3D medical scan from a free-form clinical query, where the referent is often implicit and requires both medical knowledge and volume-grounded reasoning. Existing methods typically rely on specialized segmentation tokens to connect language with mask decoding, but this coupling collapses the decision process into opaque latent representations, limiting interpretability and generalization to diverse narrative expressions. In this paper, we present MedVol-R1, a reinforcement learning-based framework for VRS that explicitly decouples evidence grounding from volumetric delineation: the LVLM grounds clinical reasoning to a verifiable 2D evidence anchor (key axial slice and 2D bounding boxes), which is then propagated into a coherent 3D mask by a frozen MedSAM2 module. We train MedVol-R1 with cold-start supervised fine-tuning followed by GRPO, guided by a multi-component reward that encourages informative evidence selection, accurate 2D spatial grounding, and cross-slice volumetric coherence, without requiring costly chain-of-thought annotations. Experiments on CT-ORG, AbdomenCT-1K, and KiTS23 from the M3D-Seg benchmark demonstrate that MedVol-R1 consistently outperforms strong baselines and achieves state-of-the-art performance, with reinforcement learning providing clear gains over pure supervised fine-tuning.","authors":["Zichun Wang","Hairong Shi","Bingzheng Wei","Yan Xu","Zihua Wang"],"published":"2026-05-26T06:59:19Z","updated":"2026-05-26T06:59:19Z","abstract_url":"https://arxiv.org/abs/2605.26621v1","html_url":"https://arxiv.org/html/2605.26621v1","pdf_url":"https://arxiv.org/pdf/2605.26621v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26616v1","title":"Gaussian-Voxel Duet: A Dual-Scaffolding Hybrid Representation for Fast and Accurate Monocular Surface Reconstruction","abstract":"While 3D Gaussian Splatting has achieved remarkable success in photorealistic novel view synthesis, its pursuit of fast and high-fidelity 3D reconstruction has long been constrained by a trade-off between geometric accuracy and optimization efficiency. Methods specialized in image rendering converge quickly at the cost of imperfect geometry caused by superfluous primitives overfitting training views, while methods integrating neural signed-distance field (SDF) for better geometry incur prohibitive training costs. In this paper, we attempt to strike a better trade-off by tethering scaffold-anchored Gaussians to a jointly optimized sparse voxel scaffold. This hybrid Gaussian-Voxel representation explicitly confines anchored Gaussians to a narrow band around surfaces defined by voxelized SDFs, which effectively improves representation efficiency and condenses floating Gaussians without sacrificing geometry quality. An implicit surface tethering loss further pulls individual Gaussian primitives closer to SDF-induced surfaces in a mutually regularized manner for improved reconstruction accuracy. Extensive experiments on diverse real-world indoor scenes from ScanNet++, ScanNetv2, and DeepBlending datasets demonstrate that our method achieves state-of-the-art surface reconstruction quality as well as superior novel view synthesis against leading baselines, while maintaining fast training convergence and real-time rendering. Code will be available at https://github.com/duzh11/VoxelGS.","authors":["Zhenhua Du","Zhen Tan","Haoyu Zhang","Dewen Hu","Shuaifeng Zhi","Peidong Liu"],"published":"2026-05-26T06:53:47Z","updated":"2026-05-26T06:53:47Z","abstract_url":"https://arxiv.org/abs/2605.26616v1","html_url":"https://arxiv.org/html/2605.26616v1","pdf_url":"https://arxiv.org/pdf/2605.26616v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26601v1","title":"FTibSuite: A Comprehensive Resource Suite for Tibetan Vision-Language Modeling","abstract":"Vision-language models have progressed rapidly, but Tibetan remains a severely underserved low-resource language due to the lack of reproducible training and evaluation infrastructure. To fill this gap, we introduce FTibSuite, a comprehensive resource suite for Tibetan vision-language research, consisting of FTibData (human-verified multimodal training corpora spanning continual pretraining, image-text alignment, and instruction tuning data), FTibBench (Tibetan adaptations of five mainstream multimodal benchmarks with a hierarchical quality-control workflow to reduce translation noise), and FTibVLM, a reproducible baseline built on Qwen3-VL-8B-Instruct via a three-stage adaptation pipeline. Experiments on FTibBench show FTibVLM delivers consistent performance gains across all tasks, such as improving MMBench accuracy from 42.97 to 67.78 and POPE-random accuracy from 47.53 to 80.56, while retaining the backbone's original Chinese capabilities with minimal degradation, providing the first standardized foundation for Tibetan multimodal research.","authors":["Guixian Xu","Yide Liang","Zeli Su","Xuexian Song","Ziyin Zhang","Yushuang Dong","Ting Zhang","Xu Han"],"published":"2026-05-26T06:36:27Z","updated":"2026-05-26T06:36:27Z","abstract_url":"https://arxiv.org/abs/2605.26601v1","html_url":"https://arxiv.org/html/2605.26601v1","pdf_url":"https://arxiv.org/pdf/2605.26601v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26584v1","title":"O-MARC: Omni Memory-Augmented Compression Distillation for Efficient Video Understanding","abstract":"Omnimodal large language models enable unified audio video understanding, but long joint token sequences make inference costly, and existing benchmarks do not fully isolate audio visual association in noisy user generated videos. We introduce UGC-AVQA, a public UGC benchmark with 1,000 videos and 4,816 QA pairs, where an audio removal test ensures that benchmark questions require both acoustic and visual evidence. To reduce inference cost, we propose OMAC, a training free plug in compression method that preserves salient visual memory and temporally grounded audio anchors. To further make compact models robust to compressed inputs, we introduce O-MARC, a compression distillation framework for learning with memory compressed multimodal contexts. On Qwen2.5-Omni-3B, O-MARC improves the average score across four benchmarks to 45.8, outperforming full token inference at 44.1 and OmniZip at 41.0. OMAC also keeps inference efficient, reducing latency by 34.6\\% (1.53$\\times$ speedup) and memory by 34.7\\% compared with full token inference.","authors":["Peiran Wu","Yunze Liu","Chi-Hao Wu","Chen Chen","Junxiao Shen"],"published":"2026-05-26T06:07:11Z","updated":"2026-05-26T06:07:11Z","abstract_url":"https://arxiv.org/abs/2605.26584v1","html_url":"https://arxiv.org/html/2605.26584v1","pdf_url":"https://arxiv.org/pdf/2605.26584v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26576v1","title":"TrackRef3D: Multi-View Consistent Track-then-Label for Open-World Referring Segmentation in 3D Gaussian Splatting","abstract":"Referring 3D Gaussian Splatting (R3DGS), which utilizes natural language for 3D object segmentation, has emerged as a crucial capability for embodied AI. However, existing methods typically rely on expensive per-scene manual annotation and per-view pseudo mask generation, which suffer from multi-view inconsistency and poor generalization to varying query specificities. To address this, we present TrackRef3D, a fully automatic pipeline that achieves open-world referring segmentation in 3D Gaussian Splatting (3DGS) without manual annotation by introducing a multi-view consistent track-then-label paradigm that fundamentally decouples object discovery from semantic grounding. Specifically, we propose a Trajectory-Aware Semantic Consensus Module (TSCM) which aggregates cross-view predictions via synonymous clustering and trajectory-aware voting to establish a canonical semantic identity, thereby ensuring multi-view consistency. Furthermore, we employ a visibility-aware description generation strategy to mitigate ambiguity and propose a Hybrid Training Strategy (HTS) that jointly optimizes coarse category semantics and fine-grained referential cues to ensure robustness under varying query specificities using a multi-positive contrastive objective. Extensive experiments on benchmarks demonstrate that TrackRef3D achieves state-of-the-art performance.","authors":["Yuyang Tan","Renhe Zhang","Hang Zhang","Ao Li","Xin Tan"],"published":"2026-05-26T05:49:12Z","updated":"2026-05-26T05:49:12Z","abstract_url":"https://arxiv.org/abs/2605.26576v1","html_url":"https://arxiv.org/html/2605.26576v1","pdf_url":"https://arxiv.org/pdf/2605.26576v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26538v1","title":"Scheduled Style Injection: Expanding the Style-Content Pareto Frontier in Training-Free Diffusion-based Style Transfer","abstract":"Style transfer with pre-trained diffusion models has advanced rapidly, but a core question remains underexplored: where in the model should style injection be strongest? StyleID, the leading training-free method, uses a single global parameter (gamma) uniformly across all layers and timesteps, which forces a fixed tradeoff between style quality and content preservation. We show this tradeoff is unnecessarily rigid. We systematically explore four dimensions of control: varying style injection strength across decoder layers, across denoising timesteps, and scheduling ControlNet geometric conditioning along both axes. The pattern is consistent everywhere: decreasing schedules, with stronger structural signal injection in shallower layers and earlier timesteps, reliably outperform the reverse. Beyond direction, schedule shape matters: cosine and square-root timestep schedules outperform linear. Most importantly, we find that gamma scheduling and ControlNet conditioning are nearly independent. The resulting combined configurations expand the Pareto frontier, offering superior tradeoffs between style fidelity and content preservation compared to any single baseline setting. Our best balanced configuration achieves ArtFID of 27.036 versus StyleID's 28.801 - a 6.1% relative improvement, with consistent gains across the full style-content tradeoff frontier. Results are validated across 35 configurations totaling over 28,000 stylized images using four complementary metrics. These findings generalize across SD backbones with identical rank ordering. All modifications are training-free, parameter-free, and require only a few lines of scheduling code; code is available at https://github.com/ameyskulkarni/scheduled_style_injection.","authors":["Amey Sunil Kulkarni"],"published":"2026-05-26T04:39:40Z","updated":"2026-05-26T04:39:40Z","abstract_url":"https://arxiv.org/abs/2605.26538v1","html_url":"https://arxiv.org/html/2605.26538v1","pdf_url":"https://arxiv.org/pdf/2605.26538v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26535v1","title":"Recursive Flow Matching","abstract":"Generative models have emerged as a powerful paradigm for solving physics systems and modeling complex spatiotemporal dynamics. However, achieving high physical accuracy without incurring high computational cost remains a fundamental challenge, as existing approaches face a critical speed-fidelity trade-off. In this work, we introduce Recursive Flow Matching (RecFM), a generative framework for forecasting complex spatiotemporal dynamics. RecFM enforces self-consistency to align trajectories across discretization scales, reducing discretization errors and improving performance across metrics for physics-based tasks. To our knowledge, this is the first method to achieve high-fidelity one- and few-step (2-4 step) dynamic generation for scientific systems with performance comparable to state-of-the-art multi-step solvers. Across challenging scientific benchmarks, RecFM achieves up to a 20$\\times$ speedup over leading diffusion-based emulators while improving predictive accuracy. Furthermore, RecFM reduces mean squared error by over 15% compared to vanilla flow matching, offering a scalable and efficient solution for real-time scientific emulation.","authors":["Jiahe Huang","Sihan Xu","Sharvaree Vadgama","Rose Yu"],"published":"2026-05-26T04:32:01Z","updated":"2026-05-26T04:32:01Z","abstract_url":"https://arxiv.org/abs/2605.26535v1","html_url":"https://arxiv.org/html/2605.26535v1","pdf_url":"https://arxiv.org/pdf/2605.26535v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26533v1","title":"A Hybrid Vision-Language Architecture for Automated Defect Reasoning and Report Generation in Industrial Inspection","abstract":"Automated industrial inspection requires both precise defect localization and structured maintenance report generation; in current practice these tasks are handled separately, with linguistic interpretation left to human experts. This paper describes a decoupled, edge-deployable pipeline for wind turbine blade inspection built from three components that each handle a distinct sub-task. The Eyes a YOLO26-x-obb oriented bounding-box detector localizes defects at dataset-native resolution. The Bridge a deterministic, parameter-free encoding module maps each detected bounding box to grid-referenced spatial tokens embedded in a structured prompt. The Brain a 4-bit quantized Qwen-2.5-1.5B model adapted with Quantized Low-Rank Adaptation (QLoRA) on 947 synthetically generated maintenance reports generates a structured JSON report from that prompt. Retrieval-Augmented Fine-Tuning (RAFT) further grounds each recommendation in indexed maintenance procedures. Five ablation experiments, scored by BLEU-4, ROUGE-L, Hallucination Rate (HR), and an LLM-as-a-Judge rubric, compare the pipeline against a monolithic vision-language model (VLM) baseline and against partial configurations in which one component is removed. The complete system achieves BLEU-4 0.41, HR=4%, and Expert Score = 8.6/10 compared with 0.07, 65%, and 3.3/10 for the zero-shot VLM baseline. The QLoRA-adapted 1.5B model generates higher-quality reports than a 671B-parameter generalist API model given identical detection evidence, at 47 tokens per second on a single T4-class GPU. The results show that purpose-built decoupled architecture with a small domain-specific training corpus outperforms a generalist end-to-end model on this structured generation task.","authors":["Malikussaid","Imad Gohar"],"published":"2026-05-26T04:27:38Z","updated":"2026-05-26T04:27:38Z","abstract_url":"https://arxiv.org/abs/2605.26533v1","html_url":"https://arxiv.org/html/2605.26533v1","pdf_url":"https://arxiv.org/pdf/2605.26533v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26525v1","title":"ReCA: Multi-Shot Long Video Extrapolation via Recursive Context Allocation","abstract":"Minute-scale cinematic video generation is a central challenge for generative video models. Existing paradigms address only fragments of this challenge: single-shot extrapolation preserves an anchor but lacks cinematic structure, while multi-shot storytelling imposes structure yet remains free to invent its visual states rather than continue an observed one. We define Multi-Shot Video Extrapolation (MSVE), a task that extends an observed frame or clip into a sequence of cinematically structured shots while preserving anchor state and advancing narrative intent. This setting operates under the finite per-call generation budget of short-video models. We identify three coupled bottlenecks: (1) global planners over-specify unsupported details from full screenplays; (2) shot-level prompts dilute task-relevant state when carrying the complete story; and (3) temporal chaining turns generated frames into a lossy memory in which identity, scene, object, and action state decay. MSVE reveals that long-video failure is not merely a limitation of context length, but a failure of context allocation. We propose Recursive Context Allocation (ReCA), an inference-time framework that allocates context hierarchically across planning and generation. ReCA recursively decomposes MSVE into context-bounded subproblems, invokes frozen generators at leaf nodes, and propagates structured state updates across time. To evaluate this setting, we further propose MSVE-Bench and NB-Q, a source-grounded protocol with prompts purpose-built for 3 to 5 minute long-video generation, a regime not addressed by existing short-clip benchmarks. Compared to previous methods, ReCA improves average normalized score by 8 to 16 percent over the strongest competing controller and improves multi-shot consistency metrics by 28 to 43 percent. View the project page at https://reca.vmv.re.","authors":["Akide Liu","Jinbo Xing","Chaojie Mao","Ye Li","Zeyu Zhang","Yefei He","Weijie Wang","Zihan Wang","Yu Liu","Gholamreza Haffari","Bohan Zhuang"],"published":"2026-05-26T04:16:56Z","updated":"2026-05-26T04:16:56Z","abstract_url":"https://arxiv.org/abs/2605.26525v1","html_url":"https://arxiv.org/html/2605.26525v1","pdf_url":"https://arxiv.org/pdf/2605.26525v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26524v1","title":"CmIVTP: Cross-modal Interaction-based Vessel Trajectory Prediction for Maritime Intelligence","abstract":"Maritime intelligent transportation systems (MITS) are essential for ensuring navigation safety and efficiency in busy waterways. However, accurate vessel trajectory prediction remains challenging due to the limitations of single-source data. Automatic identification system (AIS) data is often sparse or unavailable for small vessels, while closed-circuit television (CCTV) data alone cannot fully capture dynamic vessel behavior. To mitigate these challenges, we propose a cross-modal interaction-based vessel trajectory prediction (named CmIVTP) framework to model the intricate interactions between vessel dynamics and environmental constraints. Specifically, we introduce a target-aware scene encoder to extract scene semantic features, effectively capturing vessel-environment interactions and enhancing trajectory prediction accuracy. In addition, we propose a cross-modal interaction transformer, which integrates AIS-derived motion features, CCTV-based environmental features, and scene representations. It leverages cross-modal attention mechanisms to simultaneously capture intra-modal semantics and inter-modal interactions, ensuring dynamically consistent and environmentally feasible predictions. Furthermore, we construct a vessel group trajectory bank by clustering historical AIS trajectories into representative motion patterns, providing an efficient and scalable approach for candidate trajectory generation. Additionally, we introduce the maritime multimodal dataset plus (named Maritime-MmD$^+$), a large-scale dataset that synchronizes AIS data and CCTV video data, providing robust support for multimodal trajectory prediction research. Extensive experiments demonstrate that CmIVTP achieves better performance on multimodal-driven vessel trajectory prediction benchmarks. The code resources for this work can be available at https://github.com/LouisYxLu/CmIVTP.","authors":["Yuxu Lu","Dong Yang","Xiaoyu Li","Mengwei Bao","Congcong Zhao"],"published":"2026-05-26T04:14:35Z","updated":"2026-05-26T04:14:35Z","abstract_url":"https://arxiv.org/abs/2605.26524v1","html_url":"https://arxiv.org/html/2605.26524v1","pdf_url":"https://arxiv.org/pdf/2605.26524v1.pdf","matched_keywords":["video","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26519v1","title":"$R^3$: 3D Reconstruction via Relative Regression","abstract":"Recent feed-forward geometry foundation models have demonstrated impressive generalization by recovering depth and poses in a single forward pass. However, these models are typically constrained by a global coordinate frame assumption. This dependency becomes a significant bottleneck for long-context and streaming reconstruction, as it forces the network to maintain an arbitrary temporal origin and handle translation magnitudes that grow unbounded over time. Our solution, which we call $R^3$, employs relative regression. We employ a lightweight MLP to predict confidence-weighted relative constraints. These confidences serve as a unified anchor: weighting losses during training and guiding pose aggregation during inference. $R^3$ supports both full-context offline reconstruction and causal, bounded-memory streaming. Our evaluation in both offline and streaming settings validates the effectiveness of our relative mechanism. Project page: https://kevinxu02.github.io/r3-site","authors":["Congrong Xu","Huachen Gao","Xingyu Chen","Yuliang Xiu","Jun Gao","Anpei Chen"],"published":"2026-05-26T04:03:38Z","updated":"2026-05-26T04:03:38Z","abstract_url":"https://arxiv.org/abs/2605.26519v1","html_url":"https://arxiv.org/html/2605.26519v1","pdf_url":"https://arxiv.org/pdf/2605.26519v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26514v1","title":"CSV-ViT: A Vision Transformer with the Variable-sized Cortical Supervertices for Detection of Alzheimer's Disease Pathologies","abstract":"Confirming Alzheimer's disease (AD) typically relies on positron emission tomography (PET), which remains costly and invasive, motivating the use of structural MRI-based prescreening. Deep learning on non-Euclidean manifolds, particularly brain cortical surfaces, faces significant challenges due to the data's spherical topology. Recent surface models have enabled learning from cortical surface data; however, imposing face-based uniform patches often causes duplicate vertices at patch boundaries. In general, many surface-based models are limited in their awareness of the region of interest (ROI), which can result in non-cortical regions, such as the medial wall, being included. We propose a cortical surface tokenization that performs ROI-preserving, vertex-based, variable-sized patch partitioning. We refer to these cortical surface patches as cortical supervertices (CSVs). Building on this representation, we design the CSV Vision Transformer (CSV-ViT), a variable-size patch-tolerant Vision Transformer that uses padding and a mask-aware patch embedding. We used T1-weighted MRI and evaluated our framework by classifying AD-related status into three categories: AD diagnosis, amyloid positivity, and tau positivity. Across the experiments, CSV-ViT achieved higher classification performance than recent surface-based models. The results suggest that the proposed CSV-ViT may support MRI-based prediction of AD-related status prior to PET or CSF confirmation.","authors":["Geonwoo Baek","Ikbeom Jang"],"published":"2026-05-26T03:57:33Z","updated":"2026-05-26T03:57:33Z","abstract_url":"https://arxiv.org/abs/2605.26514v1","html_url":"https://arxiv.org/html/2605.26514v1","pdf_url":"https://arxiv.org/pdf/2605.26514v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26513v1","title":"Re-M3Dr: Rebalanced MultiModal Mean Deviation Regression","abstract":"Mean Deviation (MD) is a critical metric for assessing visual field loss in ophthalmology. While previous work has focused solely on predicting MD from Optical Coherence Tomography (OCT), it is intuitive to assume that combining OCT with another imaging of fundus photography (FP) could improve performance, as two ophthalmic medical imaging provide complementary information. This is particularly expected when sophisticated multi-objective optimization is applied, as documented in common multimodal classification. Surprisingly, our investigations reveal that multimodal fusion in this medical imaging scenario performs worse than unimodal model. Through detailed analysis, we identify the root cause as a coupled imbalance between data distribution and modality learning conflict. This imbalance distorts the optimization landscape, leading to unstable training. To address this challenge, we propose the method of Rebalanced MultiModal Mean Deviation Regression (Re-M3Dr), a novel multimodal regression framework. We enhance unimodal representation through adaptive margin based supervised contrastive learning. Then, our framework stabilizes the joint optimization with the sharpness-aware gradient modulation. Experimental results on both public and private clinical datasets show average 29\\% reduction in MSE compared to SOTA multimodal learning methods, demonstrating the superiority of Re-M3Dr. The code is available in the supplementary materials.","authors":["Haojie Yin","Chengcheng Feng","Tianyi Liu","Tianqi Zhang","Kaizhu Huang"],"published":"2026-05-26T03:57:28Z","updated":"2026-05-26T03:57:28Z","abstract_url":"https://arxiv.org/abs/2605.26513v1","html_url":"https://arxiv.org/html/2605.26513v1","pdf_url":"https://arxiv.org/pdf/2605.26513v1.pdf","matched_keywords":["3d","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26503v1","title":"Uncertainty-Aware Gaussian Map for Vision-Language Navigation","abstract":"Vision-Language Navigation (VLN) requires an agent to navigate 3D environments following natural language instructions. During navigation, existing agents commonly encounter perceptual uncertainty, such as insufficient evidence for reliable grounding or ambiguity in interpreting spatial cues, yet they typically ignore such information when predicting actions. In this work, we explicitly model three forms of perceptual uncertainty (i.e., geometric, semantic, and appearance uncertainty) and integrate them into the agent's observation space to enable informed decision-making. Concretely, our agent first constructs a Semantic Gaussian Map (SGM), composed of differentiable 3D Gaussian primitives initialized from panoramic observations, that encodes both the geometric structure and semantic content of the environment. On top of SGM, geometric uncertainty is estimated through variational perturbations of Gaussian position and scale to assess structural reliability; semantic uncertainty is captured by perturbing Gaussian semantic attributes to reveal ambiguous interpretations; and appearance uncertainty is characterized by Fisher Information, which measures the sensitivity of rendered observations to Gaussian-level variations. These uncertainties are incorporated into SGM, extending it into a unified 3D Value Map, which grounds them as affordances and constraints that support reliable navigation. Comprehensive evaluations across multiple VLN benchmarks show the effectiveness of our agent.","authors":["Jianzhe Gao","Rui Liu","Yuxuan Xu","Tongtong Cao","Yingxue Zhang","Zhanguang Zhang","Sida Peng","Yi Yang","Wenguan Wang"],"published":"2026-05-26T03:33:47Z","updated":"2026-05-26T03:33:47Z","abstract_url":"https://arxiv.org/abs/2605.26503v1","html_url":"https://arxiv.org/html/2605.26503v1","pdf_url":"https://arxiv.org/pdf/2605.26503v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26500v1","title":"3D Gaussian Map with Open-Set Semantic Grouping for Vision-Language Navigation","abstract":"Vision-language navigation (VLN) requires an agent to traverse complex 3D environments based on natural language instructions, necessitating a thorough scene understanding. While existing works equip agents with various scene representations to enhance spatial awareness, they often neglect the complex 3D geometry and rich semantics in VLN scenarios, limiting the ability to generalize across diverse and unseen environments. To address these challenges, this work proposes a 3D Gaussian Map that represents the environment as a set of differentiable 3D Gaussians and accordingly develops a navigation strategy for VLN. Specifically, Egocentric Scene Map is constructed online by initializing 3D Gaussians from sparse pseudo-lidar point clouds, providing informative geometric priors for scene understanding. Each Gaussian primitive is further enriched through Open-Set Semantic Grouping operation, which groups 3D Gaussians based on their membership in object instances or stuff categories within the open world, resulting in a unified 3D Gaussian Map. Building on this map, Multi-Level Action Prediction strategy, which combines spatial-semantic cues at multiple granularities, is designed to assist agents in decision-making. Extensive experiments conducted on three public benchmarks (i.e., R2R, R4R, and REVERIE) validate the effectiveness of our method.","authors":["Jianzhe Gao","Rui Liu","Wenguan Wang"],"published":"2026-05-26T03:25:49Z","updated":"2026-05-26T03:25:49Z","abstract_url":"https://arxiv.org/abs/2605.26500v1","html_url":"https://arxiv.org/html/2605.26500v1","pdf_url":"https://arxiv.org/pdf/2605.26500v1.pdf","matched_keywords":["3d","agent","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26491v1","title":"Beyond Pairwise Preferences: Listwise Reward-Aware Alignment for Diffusion Models","abstract":"Preference optimization has emerged as an efficient alternative to online reinforcement learning from human feedback (RLHF) for aligning text-to-image diffusion models. However, existing methods largely reduce supervision to binary pairwise comparisons. This pairwise reduction is limiting when training data naturally contains multiple candidate images for the same prompt, and when continuous reward scores can provide richer information than a single winner-loser label. To address these limitations, we propose Diffusion LAIR, a reward-aware listwise preference optimization method for diffusion models. For each prompt, LAIR converts reward scores across a group of candidate images into centered advantage weights, then optimizes an advantage-weighted regression objective on the implicit reward, defined as the denoising-loss improvement of the current model over a fixed reference model, with a quadratic penalty that regularizes the magnitude of the implicit reward. The resulting objective uses all candidates simultaneously rather than selecting pairs, and remains conservative by explicitly controlling the magnitude of the implicit reward. The LAIR objective admits a bounded closed-form optimum in implicit-reward space, clarifying how the regularization strength controls the magnitude of the preference update. Experiments show that Diffusion LAIR outperforms strong preference optimization baselines on SD1.5 and SDXL across text-to-image generation, compositional generation, and image editing benchmarks.","authors":["Austin Wang","Jiaqi Han","Stefano Ermon","Yisong Yue"],"published":"2026-05-26T03:09:24Z","updated":"2026-05-26T03:09:24Z","abstract_url":"https://arxiv.org/abs/2605.26491v1","html_url":"https://arxiv.org/html/2605.26491v1","pdf_url":"https://arxiv.org/pdf/2605.26491v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26486v1","title":"LongCat-Video-Avatar 1.5 Technical Report","abstract":"Despite advances in audio-driven video generation, achieving commercial-grade stability remains challenging. We present LongCat-Video-Avatar 1.5, an upgraded open-source framework prioritizing systematic engineering and production-readiness over architectural novelty. By upgrading the audio encoder to Whisper Large and meticulously scaling our training recipes, v1.5 achieves accurate lip-synchronization, full-body temporal stability, and robust long-video generation with strict identity consistency. Through rigorous data curation and RLHF Training, the model readily generalizes to stylized domains such as anime and animals, and natively handles complex real-world conditions, such as multi-person interactions and object handling. Furthermore, addressing the practical demands of industrial deployment, we employ advanced step distillation to accelerate inference to an optimal 8 NFE, achieving a favorable trade-off between serving efficiency and visual fidelity. The superiority of our approach is validated through extensive quantitative metrics and a rigorous human evaluation conducted on a comprehensive benchmark of over 500 diverse test cases. Results show that v1.5 achieves competitive or superior performance compared to leading closed-source systems (e.g., HeyGen, OmniHuman 1.5, Kling Avatar 2.0) across human-likeness ratings and expert-level quality assessments on our benchmark. With its open-source release, LongCat-Video-Avatar 1.5 narrows the gap between academic research prototypes and commercial-grade deployment.","authors":["Meituan LongCat Team","Xunliang Cai","Meng Cheng","Feng Gao","Zhe Kong","Jiamu Li","Le Li","Weiheng Li","Hongyu Liu","Shuai Tan","Xiaoming Wei","Tianyu Yang","Yong Zhang"],"published":"2026-05-26T02:54:12Z","updated":"2026-05-26T02:54:12Z","abstract_url":"https://arxiv.org/abs/2605.26486v1","html_url":"https://arxiv.org/html/2605.26486v1","pdf_url":"https://arxiv.org/pdf/2605.26486v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26485v1","title":"OmniInteract: Benchmarking Real-World Streaming Interaction for Real-Time Omnimodal Assistants","abstract":"We introduce OmniInteract, a streaming benchmark for real-time omnimodal large language models evaluated through native online inference over audio-visual streams. Unlike offline video understanding or text-prompted streaming QA, OmniInteract preserves the original audio-visual stream and requires models to process it online, without access to future content. User queries and ambient sounds are embedded in the audio track, requiring models to detect multimodal triggers, decide when to respond, and answer while the stream unfolds. OmniInteract contains 250 videos with 1,430 temporally grounded response slots: 1,062 1Q1A slots across real-time, proactive, and nested scenarios, and 368 1QnA slots for continuous task monitoring and step guidance. Each slot includes a trigger, response window, and target answer. We evaluate response correctness, timing, invalid outputs, interruption handling, and context continuity using Interaction-Aware Quality-Timeliness F1, Interruption Diagnostic Suite, and Nested Chain Completion Score. Experiments show that current models remain weak in streaming interaction, with the best overall IA-QTF1 reaching only 0.368 and the best 1QnA IA-QTF1 only 0.052. Further study on mathematical reasoning in full-duplex settings shows that offline capability does not necessarily transfer to online interaction. Code and datasets will be made publicly accessible at https://github.com/Lucky-Lance/OmniInteract.","authors":["Xudong Lu","Xueying Li","Annan Wang","Yang Bo","Jinpeng Chen","Zengliang Li","Nianzu Yang","Rui Liu","Xue Yang","Jingwen Hou","Hongsheng Li"],"published":"2026-05-26T02:49:47Z","updated":"2026-05-26T02:49:47Z","abstract_url":"https://arxiv.org/abs/2605.26485v1","html_url":"https://arxiv.org/html/2605.26485v1","pdf_url":"https://arxiv.org/pdf/2605.26485v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"},{"id":"2605.26483v1","title":"Clinically-Grounded Counterfactual Reasoning for Medical Video Diagnosis","abstract":"Medical video diagnosis involves inferring clinical decisions from dynamic tissue responses throughout examination processes. Existing methods rely on an end-to-end learning paradigm that i) focuses on appearance rather than pathology, ii) lacks clinical priors, and iii) reasons solely from observations without counterfactual comparison. This work introduces MedVCR, a counterfactual reasoning framework that mimics clinical diagnostic thinking. MedVCR comprises three components: a Counterfactual Generator that synthesizes tissue evolution under specified pathological states via a diffusion-based manner; a Counterfactual Representation Learning module that encodes diagnostic knowledge through clinical rules (i.e., temporal consistency, pathological separability, and counterfactual alignment); and a Dual Diagnostic Prediction strategy that integrates video-level assessment with frame-level counterfactual analysis. MedVCR is evaluated under both fully supervised (e.g., colposcopy) and weakly supervised (e.g., colonoscopy) video diagnosis settings, yielding 2.6%-10.2% performance gains compared with leading baselines. Comprehensive ablation studies further validate the effectiveness of each component. The code will be released.","authors":["Jianzhe Gao","Churan Wang","Weiyi Zhang","Jianghua Li","Li-An Li","Wenguan Wang","Yixin Zhu","Yizhou Wang"],"published":"2026-05-26T02:46:15Z","updated":"2026-05-26T02:46:15Z","abstract_url":"https://arxiv.org/abs/2605.26483v1","html_url":"https://arxiv.org/html/2605.26483v1","pdf_url":"https://arxiv.org/pdf/2605.26483v1.pdf","matched_keywords":["video","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-05-27T05:12:04+00:00","last_seen_at":"2026-05-27T05:12:04+00:00"}],"tracked_paper_count":80,"storage_mode":"latest_overwrite"}};
